"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[1477],{10:function(n){n.exports=JSON.parse('{"blogPosts":[{"id":"mysql-table-clear","metadata":{"permalink":"/blog/mysql-table-clear","source":"@site/blog\\\\2022-06-20-MySQL\u5927\u8868\u5386\u53f2\u6570\u636e\u6e05\u7406.md","title":"MySQL\u5927\u8868\u5386\u53f2\u6570\u636e\u6e05\u7406","description":"\u6700\u8fd1\u5de5\u4f5c\u4e2d\u5728\u5904\u7406\u7ebf\u4e0a\u51e0\u4e2a\u6570\u636e\u8868\u7684\u6e05\u7406\u5de5\u4f5c\uff0c\u5de5\u4f5c\u867d\u7136\u7b80\u5355\uff0c\u4f46\u64cd\u4f5c\u8d77\u6765\u6ce8\u610f\u7684\u5730\u65b9\u8fd8\u662f\u633a\u591a\u7684\u3002\u73b0\u5c06\u6574\u4e2a\u8fc7\u7a0b\u8fdb\u884c\u7b80\u5355\u7684\u603b\u7ed3\uff0c\u4ee5\u4fbf\u4f5c\u4e3a\u65e5\u540e\u7684\u53c2\u8003\u3002","date":"2022-06-20T00:00:00.000Z","formattedDate":"2022\u5e746\u670820\u65e5","tags":[{"label":"MySQL","permalink":"/blog/tags/my-sql"}],"truncated":true,"authors":[],"frontMatter":{"slug":"mysql-table-clear","title":"MySQL\u5927\u8868\u5386\u53f2\u6570\u636e\u6e05\u7406","tags":["MySQL"]},"nextItem":{"title":"MySQL\u5b9a\u65f6\u4efb\u52a1(Event Scheduler)","permalink":"/blog/mysql-event-scheduler"}},"content":"\u6700\u8fd1\u5de5\u4f5c\u4e2d\u5728\u5904\u7406\u7ebf\u4e0a\u51e0\u4e2a\u6570\u636e\u8868\u7684\u6e05\u7406\u5de5\u4f5c\uff0c\u5de5\u4f5c\u867d\u7136\u7b80\u5355\uff0c\u4f46\u64cd\u4f5c\u8d77\u6765\u6ce8\u610f\u7684\u5730\u65b9\u8fd8\u662f\u633a\u591a\u7684\u3002\u73b0\u5c06\u6574\u4e2a\u8fc7\u7a0b\u8fdb\u884c\u7b80\u5355\u7684\u603b\u7ed3\uff0c\u4ee5\u4fbf\u4f5c\u4e3a\u65e5\u540e\u7684\u53c2\u8003\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n\u9996\u5148\u786e\u5b9a\u4e0b\u6211\u4eec\u6e05\u7406\u6570\u636e\u7684\u671f\u671b\uff1a\\n- \u671f\u671b\u6e05\u7406\u8fc7\u7a0b\u4e0d\u80fd\u5bf9\u7ebf\u4e0a\u4e1a\u52a1\u4ea7\u751f\u5f71\u54cd\uff0c\u6700\u591a\u53ea\u80fd\u5bf9\u7ebf\u4e0a\u4ea7\u751f\u5fae\u5c0f\u3001\u77ed\u6682\u7684\u5f71\u54cd\\n- \u671f\u671b\u6e05\u7406\u8fc7\u7a0b\u6700\u597d\u53ef\u590d\u7528\uff0c\u6574\u4e2a\u8fc7\u7a0b\u5728\u4e0b\u6b21\u9700\u8981\u6e05\u7406\u6570\u636e\u65f6\u53ef\u4ee5\u91cd\u590d\u4f7f\u7528\\n- \u671f\u671b\u80fd\u591f\u5728\u76d1\u63a7\u4e0b\u8fdb\u884c\uff0c\u5982\u679c\u5f71\u54cd\u5728\u53ef\u63a7\u8303\u56f4\u5185\uff0c\u5e0c\u671b\u80fd\u5728\u4efb\u610f\u65f6\u523b\u8fdb\u884c\\n\\n\\n\u5bf9\u4e8e\u5f85\u6e05\u7406\u7684\u5386\u53f2\u6570\u636e\u53ef\u5206\u4e3a\u4e24\u7c7b\uff0c\u4e00\u7c7b\u662f\u786e\u8ba4\u6ca1\u6709\u5b9e\u9645\u4ef7\u503c\u7684\u6570\u636e\uff0c\u8fd9\u90e8\u5206\u6570\u636e\u53ef\u4ee5\u76f4\u63a5\u5220\u9664\uff0c\u91c7\u7528\u5b9a\u65f6\u5668\u7684\u65b9\u5f0f\u5b9a\u65f6\u6e05\u7406\u5c31\u53ef\u4ee5\u4e86\uff1b\u53e6\u4e00\u7c7b\u7684\u662f\u672a\u6765\u53ef\u80fd\u6709\u4ef7\u503c\u7684\u6570\u636e\uff0c\u8fd9\u90e8\u5206\u6570\u636e\u4e00\u822c\u4e0d\u4f1a\u76f4\u63a5\u5220\u9664\uff0c\u800c\u662f\u5b9a\u65f6\u5c06\u5386\u53f2\u4e1a\u52a1\u6570\u636e\u7684\u5f52\u6863\u3002\\n\\n\u9488\u5bf9\u7b2c\u4e00\u7c7b\u6570\u636e\uff0c\u5b9a\u65f6\u6e05\u7406\u6bd4\u8f83\u7b80\u5355\uff0c\u53ea\u9700\u8981\u5728\u4f4e\u5cf0\u671f\u5b9a\u65f6\u6309\u6761\u4ef6\u5220\u9664\u5373\u53ef\\n\\n```SQL\\ndelimiter $$\\n\\nCREATE EVENT IF NOT EXISTS event_records_interval_clear\\n    ON SCHEDULE\\n      EVERY 1 DAY STARTS \'2022-06-10 01:05:00\'\\n    DO\\n      BEGIN\\n        DECLARE v_time BIGINT(20) DEFAULT 0;\\n        \\n        SET v_time = (SELECT UNIX_TIMESTAMP(DATE_SUB(CURDATE(), INTERVAL 15 DAY)) * 1000);\\n\\n        DELETE FROM t_record WHERE create_time < v_time;\\n\\n       END $$\\n\\ndelimiter ;\\n```\\n\\n\u5728\u5b9e\u9645\u5de5\u7a0b\u5b9e\u8df5\u4e2d\uff0c\u53ef\u80fd\u5927\u90e8\u5206\u8fd8\u662f\u7b2c\u4e8c\u7c7b\u6570\u636e\uff0c\u5b9a\u65f6\u5f52\u6863\u6570\u636e\uff0c\u8fd9\u91cc\u4e3b\u8981\u9700\u8981\u8003\u8651\u6570\u636e\u8fc1\u79fb\u7684\u65f6\u95f4\uff0c\u662f\u5426\u80fd\u591f\u7528\u4e0a\u7d22\u5f15\u7b49\u95ee\u9898\u3002\u8fd9\u90e8\u5206\u6682\u4e14\u4e0d\u8868\uff0c\u7b49\u540e\u9762\u5b9e\u9645\u64cd\u4f5c\u4e86\u518d\u7ed3\u5408\u4e00\u4e2a\u6848\u4f8b\u8fdb\u884c\u8bf4\u660e\u3002\\n\\n\u5f53\u7136\u5982\u679c\u524d\u671f\u5df2\u7ecf\u8003\u8651\u4e86\u6570\u636e\u6e05\u7406\u7684\u65b9\u6848\uff0c\u4e00\u5207\u90fd\u4f1a\u6bd4\u8f83\u7b80\u5355\uff0c\u8868\u4e0d\u4f1a\u53d8\u5f97\u5f88\u5927\uff0c\u4e5f\u6ca1\u6709\u6ca1\u6709\u5728\u5927\u8868\u4e2d\u5220\u9664\u6570\u636e\u7684\u9700\u6c42\u3002\u4f46\u662f\u5982\u679c\u548c\u6211\u4eec\u4e00\u6837\uff0c\u662f\u7b49\u5230\u6570\u636e\u91cf\u5806\u79ef\u5f88\u5927\u4e86\u624d\u7740\u624b\u8003\u8651\u6e05\u7406\uff0c\u5c31\u4f1a\u9047\u5230\u5728\u4e00\u5f20\u5728\u7ebf\u4e1a\u52a1\u5927\u8868\u4e2d\uff0c\u5220\u9664\u5927\u91cf\u5386\u53f2\u6570\u636e\u7684\u60c5\u51b5\u3002\u63a5\u4e0b\u6765\u5c31\u5bf9\u9047\u5230\u7684\u8fd9\u79cd\u60c5\u51b5\u8fdb\u884c\u603b\u7ed3\uff0c\u7f51\u4e0a\u67e5\u627e\u7684\u8d44\u6599\uff0c\u65b9\u5f0f\u4e3b\u8981\u6709\u4e24\u79cd\u3002\\n\\n## \u4e00\u3001\u5206\u6279\u6e05\u7406\\n\\n\u6309\u4e00\u5b9a\u7684\u67e5\u8be2\u6761\u4ef6\uff0c\u5206\u6279\u6b21\u7684\u5220\u9664\u6570\u636e\uff0c\u8be5\u65b9\u6cd5\u64cd\u4f5c\u6bd4\u8f83\u7b80\u5355\uff0c\u4f46\u9700\u8981\u6ce8\u610f\u7684\u5730\u65b9\u4e5f\u6bd4\u8f83\u591a\\n\\n\u6ce8\u610f\u70b9\uff1a\\n- \u5206\u6279\u6b21\u7684\u67e5\u8be2\u548c\u5220\u9664\u8981\u63a7\u5236\u597d\u6570\u636e\u91cf\u3001\u6267\u884c\u8017\u65f6\uff0c\u4fdd\u8bc1\u6bcf\u6279\u6b21\u8017\u65f6\u4e0d\u8981\u592a\u957f\\n- \u8fdb\u884c\u5220\u9664\u524d\uff0c\u9884\u7559\u597d\u8db3\u591f\u7684\u5b58\u50a8\u7a7a\u95f4\uff0c\u5fc5\u8981\u65f6\u9700\u8981\u5148\u6269\u5bb9\u518d\u6e05\u7406\u3002\u5728\u5220\u9664\u540e\u5b58\u50a8\u7a7a\u95f4\u53ef\u80fd\u4e0d\u4f1a\u964d\u4f4e\uff0c\u8fd8\u53ef\u80fd\u4f1a\u589e\u957f\uff0c\u56e0\u4e3a\u5b9e\u9645\u64cd\u4f5c\u4e2d\u4ea7\u751f\u4e86\u5927\u91cfbinlog\u65e5\u5fd7\u3002\u81f3\u5c11\u9884\u7559\u4e0e\u5220\u9664\u6570\u636e\u91cf\u540c\u7b49\u5927\u5c0f\u7684\u7a7a\u95f4\\n- \u5220\u9664\u6570\u636e\u540e\uff0c\u9700\u8981\u989d\u5916\u5bf9\u788e\u7247\u7a7a\u95f4\u8fdb\u884c\u6e05\u7406\uff0c\u8be5\u64cd\u4f5c\u4e5f\u6bd4\u8f83\u8017\u65f6\uff0c\u9700\u8981\u4f4e\u5cf0\u6267\u884c\\n\\n\u5b9e\u6d4b\u4e2d\uff0c\u5220\u9664 1400w \u6570\u636e\uff0c\u65e5\u5fd7\u7a7a\u95f4\u589e\u957f\u8fd110G\uff0c\u4e0e\u5220\u9664\u6570\u636e\u5360\u7528\u5b58\u50a8\u7a7a\u95f4\u63a5\u8fd1\\n\\n```SQL\\ndelimiter $$\\n\\nCREATE EVENT IF NOT EXISTS event_task_clear\\n    ON SCHEDULE\\n      EVERY 10 MINUTE STARTS \'2022-06-20 22:30:00\' ENDS \'2022-06-21 03:10:00\'\\n    DO\\n      BEGIN\\n        DECLARE v_endId BIGINT(20) DEFAULT 0;\\n        DECLARE v_endCreateTime BIGINT(20) DEFAULT 0;\\n        DECLARE v_maxEndTime BIGINT(20) DEFAULT 0;\\n        \\n\\n        SET v_maxEndTime = (SELECT UNIX_TIMESTAMP(\'2022-05-01 00:00:00\') * 1000); \\n\\n        -- cost 2.5s\\n        SELECT ID, create_time INTO v_endId, v_endCreateTime FROM ttask ORDER BY ID ASC LIMIT 500000,1;\\n\\n        IF v_endCreateTime <= v_maxEndTime THEN\\n            -- cost 7s\\n            DELETE FROM t_preview_convert_task WHERE id < v_endId;\\n        END IF;\\n        \\n       END $$\\n\\ndelimiter ;\\n```\\n\\n## \u4e8c\u3001\u65b0\u5efa\u4e34\u65f6\u8868\uff0c\u5206\u6279\u6b21\u5bfc\u5165\uff0c\u7136\u540e\u66ff\u6362\\n\\n1. \u62f7\u8d1d\u8868\u7ed3\u6784\uff0c\u65b0\u5efa\u4e34\u65f6\u8868\\n2. \u5bfc\u5165\u9700\u8981\u4fdd\u7559\u7684\u6570\u636e\uff0c\u5982\u679c\u6570\u636e\u91cf\u5927\uff0c\u9700\u8981\u5206\u6279\u6b21 `INSERT`\\n3. \u5c06\u6e90\u8868\u91cd\u547d\u540d\u4e3a\u5907\u4efd\u8868\uff0c\u4e34\u65f6\u8868\u547d\u540d\u4e3a\u539f\u8868\u540d\\n\\n```SQL\\n-- \u6b65\u9aa41\\nCREATE TABLE IF NOT EXISTS t_task_tmp like t_task;\\n-- \u6b65\u9aa42,\u9700\u8981\u8003\u8651\u67e5\u8be2\u548c\u63d2\u5165\u7684\u65f6\u95f4\\nINSERT INTO t_task_tmp SELECT * FROM t_task WHERE id > 6868326044778799105; \\n-- \u6b65\u9aa43,\u91cd\u547d\u540d\uff0c\u66ff\u6362\u539f\u8868\\nRENAME TABLE t_task TO t_task_bak, t_task_tmp TO t_task;\\n```\\n\\n\u5b9e\u9645\u64cd\u4f5c\u4e2d\u6ce8\u610f\u4ee5\u4e0b\u51e0\u70b9\uff1a\\n- \u6b65\u9aa42\u5982\u679c\u6570\u636e\u8fc7\u591a\uff0c\u9700\u8981\u5206\u6279\u8fdb\u884c\\n- \u6b65\u9aa42\u548c\u6b65\u9aa43\u53ef\u80fd\u4f1a\u5bfc\u81f4\u4e00\u5c0f\u90e8\u5206\u6570\u636e\u4e22\u5931\uff0c\u5982\u679c\u6700\u8fd1\u6570\u636e\u662f\u70ed\u70b9\u6570\u636e\uff0c\u8be5\u65b9\u6cd5\u4e0d\u9002\u7528\uff0c\u6216\u9009\u62e9\u5728\u4f4e\u5cf0\u671f\u8fdb\u884c\\n- \u5982\u679c\u6570\u636e\u8868\u4e3b\u952e\u662f\u81ea\u589eID\uff0c\u9700\u8981\u66f4\u65b0\u66ff\u6362\u540e\u7684\u8868\u7684\u81ea\u589eID\\n\\n\\n## \u4e09\u3001\u6848\u4f8b\\n\\n\u6211\u4eec\u7ebf\u4e0a\u6709\u4e2a\u4efb\u52a1\u8868 `t_task`\uff0c\u76ee\u524d\u6570\u636e\u91cf\u5728 `2000w` \uff0c\u5b58\u50a8\u7a7a\u95f4\u5728 `18G` \u3002\u8ba1\u5212\u5148\u5c06 2 \u4e2a\u6708\u4ee5\u524d\u7684\u6570\u636e\u8fdb\u884c\u6e05\u7406\uff0c\u5728\u6e05\u7406\u5386\u53f2\u6570\u636e\u540e\u518d\u8003\u8651\u5206\u6708\u5f52\u6863\u3002\\n\\n\u8868\u7684 `create_time` \u5b57\u6bb5\u6ca1\u6709\u7d22\u5f15\uff0c\u4e3b\u952e `ID` \u91c7\u7528\u96ea\u82b1\u7b97\u6cd5\u751f\u6210\u3002\u56e0\u4e3a\u8868\u4e2d\u6570\u636e\u6700\u8fd1\u6570\u636e\u4e3a\u70ed\u70b9\u6570\u636e\uff0c\u6240\u6709\u6ca1\u6709\u91c7\u7528\u65b9\u6848(\u4e8c)\uff0c\u4f7f\u7528\u7684\u662f\u5206\u6279\u5220\u9664\u7684\u65b9\u5f0f\u3002\\n\\n\u5728\u5b9e\u6d4b\u4e2d\u53d1\u73b0\uff0c\u5206\u6279\u5220\u9664\u5982\u679c\u6839\u636e\u521b\u5efa\u65f6\u95f4\u505a\u67e5\u8be2\u5220\u9664\uff0c\u8017\u65f6\u4e0d\u592a\u7406\u60f3\uff0c\u9700\u8981\u9009\u62e9\u5728\u4f4e\u5cf0\u6bb5\u8fdb\u884c\u3002\u8003\u8651\u5230\u6211\u4eec\u7684\u6570\u636e\u8868\u4e3b\u952e\u662f\u8d8b\u52bf\u9012\u589e\u7684\uff0c\u6211\u4eec\u53ef\u4ee5\u6279\u91cf\u5220\u9664\u524d 50w \u6761\u6570\u636e\uff0c\u76f4\u5230\u7b2c50w\u6761\u8bb0\u5f55\u8d85\u51fa\u4e86\u9700\u8981\u6e05\u7406\u7684\u65e5\u671f\uff0c\u7136\u540e\u518d\u624b\u52a8\u5c06\u5269\u4f59\u7684\u4e00\u5c0f\u90e8\u5206\u6570\u636e\u5220\u9664(\u5982\u679c\u4e0d\u8981\u6c42\u7279\u522b\u7cbe\u786e\uff0c\u5176\u5b9e\u4e5f\u53ef\u4ee5\u4e0d\u5220)\u3002\u5b9e\u9645\u6d4b\u8bd5\u4e2d\uff0c\u91c7\u7528\u8fd9\u79cd\u65b9\u5f0f\u6bcf\u6267\u884c\u4e00\u6b21\u5927\u7ea6 10s \u5de6\u53f3\u3002\u8fd9\u6837\u505a\u7684\u597d\u5904\u662f\u8017\u65f6\u77ed\uff0c\u53ef\u4ee5\u5728\u4efb\u610f\u65f6\u95f4\u6bb5\u8fdb\u884c\uff0c\u4e0d\u597d\u7684\u5730\u65b9\u662f\uff0c\u6700\u540e\u8fd8\u662f\u9700\u8981\u624b\u52a8\u505a\u4e00\u6b21\u6e05\u7406\u3002\\n\\n```SQL\\ndelimiter $$\\n\\nCREATE EVENT IF NOT EXISTS event_task_clear\\n    ON SCHEDULE\\n      EVERY 10 MINUTE STARTS \'2022-03-01 00:00:00\' ENDS \'2022-03-01 06:00:00\'\\n    DO\\n      BEGIN\\n        DECLARE v_endId BIGINT(20) DEFAULT 0;\\n        DECLARE v_endCreateTime BIGINT(20) DEFAULT 0;\\n        DECLARE v_maxEndTime BIGINT(20) DEFAULT 0;\\n        \\n\\n        SET v_maxEndTime = (SELECT UNIX_TIMESTAMP(\'2022-01-01 00:00:00\') * 1000); \\n\\n        SELECT ID, create_time INTO v_endId, v_endCreateTime FROM t_task ORDER BY ID ASC LIMIT 500000,1;\\n\\n        IF v_endCreateTime <= v_maxEndTime THEN\\n            DELETE FROM t_task WHERE id < v_endId;\\n        END IF;\\n        \\n       END $$\\n\\ndelimiter ;\\n```\\n\\n\\n## \u56db\u3001\u4e3a\u4ec0\u4e48\u6ca1\u6709\u91c7\u7528MySQL\u5206\u533a\u8868\\n\\n- \u5206\u533a\u8868\u6280\u672f\u4e0d\u662f\u7528\u4e8e\u63d0\u5347MySQL\u6570\u636e\u5e93\u7684\u6027\u80fd\uff0c\u800c\u662f\u65b9\u4fbf\u6570\u636e\u7684\u7ba1\u7406\u3002\u5206\u533a\u8868\u8bbe\u8ba1\u4e0d\u89e3\u51b3\u6027\u80fd\u95ee\u9898\uff0c\u66f4\u591a\u7684\u662f\u89e3\u51b3\u6570\u636e\u8fc1\u79fb\u548c\u5907\u4efd\u7684\u95ee\u9898\\n- \u5206\u533a\u8868\uff0c\u5206\u533a\u952e\u8bbe\u8ba1\u4e0d\u592a\u7075\u6d3b\uff1a**All columns**\xa0used in the table\'s partitioning expression must be part of\xa0**every unique key**\xa0that the table may have, including any primary key\\n- \u5206\u533a\u8868\u8fbe\u5f0f\u4e2d\uff0c\u4ec5\u53ef\u4ee5\u4f7f\u7528\u90e8\u5206\u51fd\u6570([https://dev.mysql.com/doc/refman/5.7/en/partitioning-limitations-functions.html](https://dev.mysql.com/doc/refman/5.7/en/partitioning-limitations-functions.html))\\n- \u6709\u989d\u5916\u7684\u5b66\u4e60\u6210\u672c\u548c\u6f5c\u5728\u7684\u98ce\u9669\\n\\n```SQL\\nCREATE TABLE `t_device_online_record_partition`  (\\n    `id` bigint UNSIGNED NOT NULL COMMENT \'\u4e3b\u952eID\',\\n    `device_id` varchar(64) NOT NULL COMMENT \'\u8bbe\u5907ID\',\\n    `online` bit NOT NULL COMMENT \'\u662f\u5426\u5728\u7ebf,1/\u5728\u7ebf,0/\u79bb\u7ebf\',\\n    `occur_time` datetime NOT NULL COMMENT \'\u53d1\u751f\u65f6\u95f4\',\\n    `create_time` bigint UNSIGNED NOT NULL COMMENT \'\u521b\u5efa\u65f6\u95f4\',\\n    `create_by` varchar(64) NULL COMMENT \'\u521b\u5efa\u4eba\',\\n    `update_time` bigint UNSIGNED NULL COMMENT \'\u66f4\u65b0\u65f6\u95f4\',\\n    `update_by` varchar(64) NULL COMMENT \'\u66f4\u65b0\u4eba\',\\n    `update_version` int UNSIGNED NOT NULL DEFAULT 0 COMMENT \'\u4e50\u89c2\u9501\',\\n    PRIMARY KEY (`id`, `occur_time`),\\n    INDEX `idx_device_id_create_time`(`device_id`, `create_time`) USING BTREE\\n) ENGINE = InnoDB CHARACTER SET = utf8mb4 COMMENT = \'\u8bbe\u5907\u4e0a\u4e0b\u7ebf\u8bb0\u5f55\u5206\u533a\u8868\'\\nPARTITION BY LIST(\\nMONTH(occur_time)\\n)(\\nPARTITION p01 VALUES IN(1),\\nPARTITION p02 VALUES IN(2),\\nPARTITION p03 VALUES IN(3),\\nPARTITION p04 VALUES IN(4),\\nPARTITION p05 VALUES IN(5),\\nPARTITION p06 VALUES IN(6),\\nPARTITION p07 VALUES IN(7),\\nPARTITION p08 VALUES IN(8),\\nPARTITION p09 VALUES IN(9),\\nPARTITION p10 VALUES IN(10),\\nPARTITION p11 VALUES IN(11),\\nPARTITION p12 VALUES IN(12)\\n);\\n```\\n\\n\u4e0a\u9762\u7684\u793a\u4f8b\u4e2d\uff0c\u56e0\u4e3a\u60f3\u6309\u6708\u5206\u533a\uff0c\u4e8e\u662f\u5206\u533a\u51fd\u6570\u4e2d\u7684 `occur_time` \u5fc5\u987b\u662f\u8868\u4e2d\u4e3b\u952e\u7684\u4e00\u90e8\u5206\uff0c\u9700\u8981 `id` \u548c `occur_time` \u5171\u540c\u7ec4\u6210\u590d\u5408\u4e3b\u952e\u3002\u53e6\u5916\uff0c\u521a\u5f00\u59cb\u662f\u60f3\u7528bigint\u7c7b\u578b\u7684 `create_time` \u5b57\u6bb5\u5206\u533a\uff0c\u4f46\u662f\u6ca1\u6709\u53ef\u5229\u7528\u7684\u51fd\u6570\u4ece\u65f6\u95f4\u6233\u6beb\u79d2\u503c\u83b7\u53d6\u6708\u4efd(\u5206\u533a\u51fd\u6570\u4e2d\uff0cUNIX_TIMESTAMP()\u53ea\u7528\u4f5c\u7528\u5728TIMESTAMP\u5b57\u6bb5\u4e0a)\uff0c\u53ea\u80fd\u5355\u72ec\u7ef4\u62a4\u4e00\u4e2adatetime\u7c7b\u578b\u7684\u5b57\u6bb5\uff0c\u6216\u8005\u5728\u5165\u5e93\u65f6\u5c31\u8ba1\u7b97\u597d\u6708\u4efd\u3002\u5f53\u7136\u4e5f\u53ef\u7528\u4f7f\u7528 `RANGE` \u5206\u533a\u914d\u5408 `LESS THAN`, \u8ba1\u7b97\u597d\u56fa\u4ef6\u6708\u4efd\u7684\u65f6\u95f4\u6233\uff0c\u4f46\u8fd9\u6837\u7684\u5206\u533a\u8868\u540e\u9762\u9700\u8981\u5230\u70b9\u6269\u5145\u5206\u533a\uff0c\u4e0d\u662f\u6211\u60f3\u8981\u7684\u3002\\n\\n\\n## \u53c2\u8003\u6587\u7ae0\\n1. Navicat\u7edf\u8ba1\u7684\u884c\u6570\u7adf\u7136\u548c\u8868\u5b9e\u9645\u884c\u6570\u4e0d\u4e00\u81f4\uff1a[https://cloud.tencent.com/developer/article/1909935](https://cloud.tencent.com/developer/article/1909935)\\n2. MySQL\u6570\u636e\u6e05\u7406\u6709\u6280\u5de7\uff1a[https://cloud.tencent.com/developer/article/1546545](https://cloud.tencent.com/developer/article/1546545)\\n3. Mysql\u5927\u8868\u6570\u636e\u6e05\u7406\u65b9\u6848\uff1a[https://blog.csdn.net/zhaobangyu/article/details/122606850](https://blog.csdn.net/zhaobangyu/article/details/122606850)\\n4. MySQL CREATE EVENT\u6587\u6863\uff1a[https://dev.mysql.com/doc/refman/5.7/en/create-event.html](https://dev.mysql.com/doc/refman/5.7/en/create-event.html)\\n5. \u91ca\u653eMySQL\u5b9e\u4f8b\u7684\u8868\u7a7a\u95f4\uff1a[https://help.aliyun.com/document_detail/41720.html](https://help.aliyun.com/document_detail/41720.html)\\n6. MySQL\xa0\u5206\u533a\u8868\u7684\u9650\u5236\u53ca\u5c40\u9650\u6027\uff1a[https://dev.mysql.com/doc/refman/5.7/en/partitioning-limitations.html](https://dev.mysql.com/doc/refman/5.7/en/partitioning-limitations.html)"},{"id":"mysql-event-scheduler","metadata":{"permalink":"/blog/mysql-event-scheduler","source":"@site/blog\\\\2022-06-09-MySQL\u5b9a\u65f6\u4efb\u52a1(Event Scheduler).md","title":"MySQL\u5b9a\u65f6\u4efb\u52a1(Event Scheduler)","description":"\u4e3b\u8981\u4ecb\u7ecd\u4e86MySQL Event Scheduler\u7684\u8bed\u6cd5\uff0c\u53ca\u4e00\u90e8\u5206\u793a\u4f8b","date":"2022-06-09T00:00:00.000Z","formattedDate":"2022\u5e746\u67089\u65e5","tags":[{"label":"MySQL","permalink":"/blog/tags/my-sql"}],"truncated":true,"authors":[],"frontMatter":{"slug":"mysql-event-scheduler","title":"MySQL\u5b9a\u65f6\u4efb\u52a1(Event Scheduler)","tags":["MySQL"]},"prevItem":{"title":"MySQL\u5927\u8868\u5386\u53f2\u6570\u636e\u6e05\u7406","permalink":"/blog/mysql-table-clear"},"nextItem":{"title":"SpringBoot\u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u4f18\u5148\u7ea7","permalink":"/blog/springboot-config-priority"}},"content":"\u4e3b\u8981\u4ecb\u7ecd\u4e86MySQL Event Scheduler\u7684\u8bed\u6cd5\uff0c\u53ca\u4e00\u90e8\u5206\u793a\u4f8b\\r\\n\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n\u57fa\u4e8e MySQL 5.7\uff0c\u5b98\u65b9\u6587\u6863\u5730\u5740\uff1a\\r\\n\\r\\nCREATE\uff1a[https://dev.mysql.com/doc/refman/5.7/en/create-event.html](https://dev.mysql.com/doc/refman/5.7/en/create-event.html)\\r\\n\\r\\nALTER EVENT: [https://dev.mysql.com/doc/refman/5.7/en/alter-event.html](https://dev.mysql.com/doc/refman/5.7/en/alter-event.html)\\r\\n\\r\\n## \u524d\u7f6e\u6761\u4ef6\\r\\n\\r\\n\u5728\u521b\u5efaEVENT\u4e4b\u524d\uff0c\u9700\u8981\u5148\u786e\u8ba4 `Event Scheduler` \u529f\u80fd\u662f\u5426\u5f00\u542f\u3002[https://dev.mysql.com/doc/refman/5.7/en/events-configuration.html](https://dev.mysql.com/doc/refman/5.7/en/events-configuration.html)\\r\\n\\r\\n```SQL\\r\\n-- \u67e5\u770b\u5f00\u542f\u72b6\u6001 \\r\\nSHOW GLOBAL VARIABLES like \'%event_scheduler%\'; \\r\\n-- \u5f00\u542f \\r\\nSET GLOBAL event_scheduler = ON; \\r\\n-- \u5173\u95ed \\r\\nSET GLOBAL event_scheduler = OFF;\\r\\n```\\r\\n\\r\\n\\r\\n## CREATE Event\\r\\n\\r\\n\u8bed\u6cd5\\r\\n\\r\\n```SQL\\r\\n\\r\\nCREATE\\r\\n    [DEFINER = user]\\r\\n    EVENT\\r\\n    [IF NOT EXISTS]\\r\\n    event_name\\r\\n    ON SCHEDULE schedule\\r\\n    [ON COMPLETION [NOT] PRESERVE]\\r\\n    [ENABLE | DISABLE | DISABLE ON SLAVE]\\r\\n    [COMMENT \'string\']\\r\\n    DO event_body;\\r\\n\\r\\nschedule: {\\r\\n    AT timestamp [+ INTERVAL interval] ...\\r\\n  | EVERY interval\\r\\n    [STARTS timestamp [+ INTERVAL interval] ...]\\r\\n    [ENDS timestamp [+ INTERVAL interval] ...]\\r\\n}\\r\\n\\r\\ninterval:\\r\\n    quantity {YEAR | QUARTER | MONTH | DAY | HOUR | MINUTE |\\r\\n              WEEK | SECOND | YEAR_MONTH | DAY_HOUR | DAY_MINUTE |\\r\\n              DAY_SECOND | HOUR_MINUTE | HOUR_SECOND | MINUTE_SECOND}\\r\\n              \\r\\n```\\r\\n\\r\\n-   DEFINER\uff0c\u5b9a\u4e49\u7528\u6237\\r\\n-   schedule\uff0c\u6267\u884c\u8ba1\u5212\uff0c\u6709\u4e24\u79cd\u65b9\u5f0f\uff1a`ON SCHEDULE AT CURRENT_TIMESTAMP + INTERVAL 1 HOUR` \u6216 `EVERY 1 DAY STARTS CURRENT_TIMESTAMP`\\r\\n-   `ON COMPLETION [NOT] PRESERVE`, \u9ed8\u8ba4EVENT\u8fc7\u671f\u540e\u5c31\u4e22\u5f03(NOT PRESERVE)\uff0c\u53ef\u901a\u8fc7 `ON COMPLETION PRESERVE` \u7533\u660e\u8fc7\u671f\u540e\u4ecd\u7136\u4fdd\u7559\uff0c\u4e00\u822c\u7528\u4e8e\u5230\u4e86\u65f6\u95f4\u70b9\uff0c\u4e0a\u4e00\u4e2a\u4efb\u52a1\u8fd8\u6ca1\u6709\u6267\u884c\u5b8c\u6210\uff0c\u5f53\u524d\u7684\u8fd9\u4e2a\u4efb\u52a1\u662f\u76f4\u63a5\u4e22\u5f03\uff0c\u8fd8\u662f\u7b49\u4e0a\u4e2a\u4efb\u52a1\u6267\u884c\u5b8c\u6210\u540e\u518d\u6267\u884c\\r\\n-   `[ENABLE | DISABLE | DISABLE ON SLAVE]`, \u7533\u660e\u4ece\u5e93\uff0c\u4e00\u822c\u4e0d\u7533\u660e\\r\\n\\r\\n\u5bf9\u4e8eDO\u64cd\u4f5c\u4e2d\u6bd4\u8f83\u590d\u6742\u7684\u6267\u884c\u8ba1\u5212\uff0c\u53ef\u4ee5\u901a\u8fc7\u4ee5\u4e0b2\u79cd\u65b9\u5f0f\\r\\n\\r\\n-   `DO` \u4e2d\u7533\u660e `BEGIN` \u548c `END`\\r\\n-   \u6539\u6210\u8c03\u7528\u50a8\u5b58\u8fc7\u7a0b\u7684\u65b9\u5f0f\\r\\n\\r\\n## \u793a\u4f8b\\r\\n\\r\\n**1. \u5b98\u65b9\u793a\u4f8b**\\r\\n\\r\\n```SQL\\r\\n-- \u793a\u4f8b\uff1a\u6bcf\u5c0f\u65f6\u66f4\u65b0\u4e00\u6b21\\r\\nCREATE EVENT myevent\\r\\n    ON SCHEDULE AT CURRENT_TIMESTAMP + INTERVAL 1 HOUR\\r\\n    DO\\r\\n      UPDATE myschema.mytable SET mycol = mycol + 1;\\r\\n```\\r\\n\\r\\n```SQL\\r\\ndelimiter $$\\r\\n\\r\\nCREATE EVENT e\\r\\n    ON SCHEDULE\\r\\n      EVERY 5 SECOND\\r\\n    DO\\r\\n      BEGIN\\r\\n        DECLARE v INTEGER;\\r\\n        -- \u8fd9\u91cc\u7684 BEGIN END\uff0c\u4e0d\u6e05\u695a\u662f\u5426\u662f\u7b14\u8bef\\r\\n        DECLARE CONTINUE HANDLER FOR SQLEXCEPTION BEGIN END;\\r\\n\\r\\n        SET v = 0;\\r\\n\\r\\n        WHILE v < 5 DO\\r\\n          INSERT INTO t1 VALUES (0);\\r\\n          UPDATE t2 SET s1 = s1 + 1;\\r\\n          SET v = v + 1;\\r\\n        END WHILE;\\r\\n    END $$\\r\\n\\r\\ndelimiter ;\\r\\n```\\r\\n\\r\\n```SQL\\r\\nCREATE EVENT e_call_myproc\\r\\n    ON SCHEDULE\\r\\n      AT CURRENT_TIMESTAMP + INTERVAL 1 DAY\\r\\n    DO CALL myproc(5, 27);\\r\\n```\\r\\n\\r\\n\\r\\n**2. \u5de5\u7a0b\u5b9e\u8df5**\\r\\n\\r\\n\u6eda\u52a8\u5220\u9664\u5386\u53f2\u6570\u636e\uff0c\u5220\u9664\u5f53\u524d\u65f6\u95f4\u5f80\u524d15\u7684\u5386\u53f2\u6570\u636e\u3002\u6ca1\u6709\u8bbe\u7f6e `ON COMPLETION PRESERVE` \u7684\u539f\u56e0\u662f\uff0c\u5982\u679c\u6f0f\u6389\u4e00\u6b21\u5bf9\u4e8b\u4ef6\u672c\u8eab\u5f71\u54cd\u4e0d\u5927\u3002\\r\\n\\r\\n```SQL\\r\\n-- CREATE\\r\\ndelimiter $$\\r\\n\\r\\nCREATE EVENT IF NOT EXISTS records_interval_clear\\r\\n    ON SCHEDULE\\r\\n      EVERY 1 DAY STARTS \'2021-08-06 01:00:00\'        \\r\\n    DO\\r\\n      BEGIN\\r\\n        DECLARE v_time BIGINT(20) DEFAULT 0;\\r\\n        -- \u5f53\u524d\u65e5\u671f\u5f80\u524d15\u5929\\r\\n        SET v_time = (SELECT UNIX_TIMESTAMP(DATE_SUB(CURDATE(), INTERVAL 15 DAY)) * 1000);\\r\\n        DELETE FROM t_history WHERE create_time < v_time;\\r\\n       END $$\\r\\n\\r\\ndelimiter ;\\r\\n```\\r\\n\\r\\n## \u5176\u4ed6\u547d\u4ee4\\r\\n\\r\\n\u67e5\u770b\u6267\u884c\u8ba1\u5212\uff1a\\r\\n\\r\\n```SQL\\r\\nSELECT * FROM INFORMATION_SCHEMA.events;\\r\\n```\\r\\n\\r\\n\\r\\n\u7981\u7528 `EVENT`\\r\\n\\r\\n```SQL\\r\\nALTER EVENT myevent DISABLE;\\r\\n```\\r\\n\\r\\nDROP\\r\\n\\r\\n```SQL\\r\\nDROP EVENT [IF EXISTS] event_name\\r\\n```\\r\\n\\r\\n## \u6ce8\u610f\\r\\n\\r\\n1. \u5728\u5b9a\u65f6\u4efb\u52a1\u5f00\u542f\u524d\uff0c\u9700\u8981\u9884\u4f30\u4e0b\u7b2c\u4e00\u6b21\u6267\u884c\u65f6\u5220\u9664\u7684\u5386\u53f2\u6570\u636e\u91cf\uff0c\u4ee5\u514d\u56e0\u5220\u9664\u6570\u636e\u91cf\u8fc7\u591a\u5bfc\u81f4\u6570\u636e\u5e93\u5361\u6b7b\u7684\u60c5\u51b5\uff0c\u5efa\u8bae\u7b2c\u4e00\u6b21\u5148\u624b\u52a8\u5220\u9664\u5386\u53f2\u6570\u636e\\r\\n2. \u5220\u9664\u5927\u8868\u540e\uff0c\u6570\u636e\u5e93\u7684\u5b58\u50a8\u7a7a\u95f4\u5927\u5c0f\u4e0d\u4f1a\u6539\u53d8\uff0c\u9700\u8981\u901a\u8fc7 `optimize table` \u8bed\u53e5\u91ca\u653e\u8868\u7a7a\u95f4\uff0c\u540e\u7eed\u4f18\u5316\u53ef\u53c2\u8003\uff1a[https://help.aliyun.com/document_detail/41720.html](https://help.aliyun.com/document_detail/41720.html) \u6216 \u78c1\u76d8\u788e\u7247\u65e0\u9501\u8868\u7a7a\u95f4\u6e05\u7406\u963f\u91cc\u4e91\u6587\u6863\uff1a[https://help.aliyun.com/document_detail/128340.html](https://help.aliyun.com/document_detail/128340.html)"},{"id":"springboot-config-priority","metadata":{"permalink":"/blog/springboot-config-priority","source":"@site/blog\\\\2022-05-08-SpringBoot\u4e2d\u914d\u7f6e\u6587\u4ef6\u4f18\u5148\u7ea7.md","title":"SpringBoot\u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u4f18\u5148\u7ea7","description":"\u5728\u5f00\u53d1\u8fc7\u7a0b\u4e2d\uff0c\u4e0d\u77e5\u9053\u6709\u6ca1\u6709\u8fd9\u6837\u7684\u7ecf\u5386\uff0c\u9879\u76ee\u5b9e\u9645\u8bfb\u53d6\u7684\u914d\u7f6e\u4fe1\u606f\u6709\u65f6\u5019\u603b\u662f\u4e0e\u9884\u671f\u4e0d\u7b26\uff0c\u4eca\u5929\u5c31\u6765\u7814\u7a76\u4e0b SpringBoot \u8bfb\u53d6\u914d\u7f6e\u6587\u4ef6\u987a\u5e8f\u3002\u672c\u6587\u8bd5\u56fe\u5bf9\u914d\u7f6e\u7684\u4f18\u5148\u7ea7\u8fdb\u884c\u603b\u7ed3\u3002","date":"2022-05-08T00:00:00.000Z","formattedDate":"2022\u5e745\u67088\u65e5","tags":[{"label":"SpringBoot","permalink":"/blog/tags/spring-boot"},{"label":"config","permalink":"/blog/tags/config"}],"truncated":true,"authors":[],"frontMatter":{"slug":"springboot-config-priority","title":"SpringBoot\u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u4f18\u5148\u7ea7","tags":["SpringBoot","config"]},"prevItem":{"title":"MySQL\u5b9a\u65f6\u4efb\u52a1(Event Scheduler)","permalink":"/blog/mysql-event-scheduler"},"nextItem":{"title":"\u8bb0\u4e00\u6b21dump\u6587\u4ef6\u5206\u6790\u5386\u7a0b","permalink":"/blog/jvm-dump-file-analysis-experience"}},"content":"\u5728\u5f00\u53d1\u8fc7\u7a0b\u4e2d\uff0c\u4e0d\u77e5\u9053\u6709\u6ca1\u6709\u8fd9\u6837\u7684\u7ecf\u5386\uff0c\u9879\u76ee\u5b9e\u9645\u8bfb\u53d6\u7684\u914d\u7f6e\u4fe1\u606f\u6709\u65f6\u5019\u603b\u662f\u4e0e\u9884\u671f\u4e0d\u7b26\uff0c\u4eca\u5929\u5c31\u6765\u7814\u7a76\u4e0b `SpringBoot` \u8bfb\u53d6\u914d\u7f6e\u6587\u4ef6\u987a\u5e8f\u3002\u672c\u6587\u8bd5\u56fe\u5bf9\u914d\u7f6e\u7684\u4f18\u5148\u7ea7\u8fdb\u884c\u603b\u7ed3\u3002\\r\\n\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n## \u4e00\u3001SpringBoot \u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u4f18\u5148\u7ea7\\r\\n\\r\\n[SpringBoot\u5b98\u65b9\u6587\u6863](https://docs.spring.io/spring-boot/docs/2.2.9.RELEASE/reference/htmlsingle/#boot-features-external-config)\u8bf4\u660e\u4e86\u52a0\u8f7d\u7684\u987a\u5e8f\u5982\u4e0b\uff0c\u8d8a\u9760\u524d\u4f18\u5148\u7ea7\u8d8a\u9ad8\u3002\\r\\n\\r\\n>Spring Boot uses a very particular\xa0`PropertySource`\xa0order that is designed to allow sensible overriding of values. Properties are considered in the following order\\r\\n\\r\\n```text  \\r\\n\\r\\n1. \u5f00\u53d1\u8005\u5de5\u5177 Devtools \u5168\u5c40\u914d\u7f6e\u53c2\u6570\uff1b  \\r\\n\\r\\n2. \u5355\u5143\u6d4b\u8bd5\u4e0a\u7684 [@TestPropertySource](mailto:@TestPropertySource)` \u6ce8\u89e3\u6307\u5b9a\u7684\u53c2\u6570;  \\r\\n\\r\\n3. \u5355\u5143\u6d4b\u8bd5\u4e0a\u7684 [@SpringBootTest](mailto:@SpringBootTest)` \u6ce8\u89e3\u6307\u5b9a\u7684\u53c2\u6570\uff1b  \\r\\n\\r\\n4. \u547d\u4ee4\u884c\u6307\u5b9a\u7684\u53c2\u6570\uff0c\u5982 java -jar springboot.jar --name=\\"xxx\\"\uff1b  \\r\\n\\r\\n5. \u547d\u4ee4\u884c\u4e2d\u7684 SPRING_APPLICATION_JSON \u6307\u5b9a\u53c2\u6570, \u5982 java -Dspring.application.json=\'{\\"name\\":\\"xxx\\"}\' -jar springboot.jar  \\r\\n\\r\\n6. ServletConfig\u521d\u59cb\u5316\u53c2\u6570\uff1b  \\r\\n\\r\\n7. ServletContext\u521d\u59cb\u5316\u53c2\u6570\uff1b  \\r\\n\\r\\n8. JNDI\u53c2\u6570\uff08\u5982 java:comp/env/spring.application.json\uff09\uff1b  \\r\\n\\r\\n9. Java\u7cfb\u7edf\u53c2\u6570\uff08\u6765\u6e90\uff1aSystem.getProperties()\uff09\uff1b  \\r\\n\\r\\n10. \u64cd\u4f5c\u7cfb\u7edf\u73af\u5883\u53d8\u91cf\u53c2\u6570\uff1b  \\r\\n\\r\\n11. RandomValuePropertySource \u968f\u673a\u6570\uff0c\u4ec5\u5339\u914d\uff1aramdom.*\uff1b  \\r\\n\\r\\n12. JAR\u5305\u5916\u9762\u7684\u914d\u7f6e\u6587\u4ef6\u53c2\u6570\uff08application-{profile}.properties\uff08YAML\uff09\uff09  \\r\\n\\r\\n13. JAR\u5305\u91cc\u9762\u7684\u914d\u7f6e\u6587\u4ef6\u53c2\u6570\uff08application-{profile}.properties\uff08YAML\uff09\uff09  \\r\\n\\r\\n14. JAR\u5305\u5916\u9762\u7684\u914d\u7f6e\u6587\u4ef6\u53c2\u6570\uff08application.properties\uff08YAML\uff09\uff09  \\r\\n\\r\\n15. JAR\u5305\u91cc\u9762\u7684\u914d\u7f6e\u6587\u4ef6\u53c2\u6570\uff08application.properties\uff08YAML\uff09\uff09  \\r\\n\\r\\n16. @Configuration (mailto:@Configuration)\u914d\u7f6e\u6587\u4ef6\u4e0a @PropertySource(mailto:@PropertySource) \u6ce8\u89e3\u52a0\u8f7d\u7684\u53c2\u6570\uff1b  \\r\\n\\r\\n17. \u9ed8\u8ba4\u53c2\u6570\uff08\u901a\u8fc7 SpringApplication.setDefaultProperties \u6307\u5b9a\uff09\uff1b  \\r\\n\\r\\n\\r\\n```\\r\\n\\r\\n\u8fd9\u91cc\u6211\u4eec\u53ea\u5bf9\u6bd4\u5e38\u7528\u7684\u51e0\u4e2a\u5730\u65b9\u7684\u914d\u7f6e\u4f18\u5148\u7ea7\uff1a\\r\\n\\r\\n\u547d\u4ee4\u884c\u53c2\u6570 > JAR\u5305\u5916\u9762\u7684 `application-{profile}.properties` > JAR\u5305\u5185\u7684 `application-{profile}.properties` > JAR\u5305\u5916\u7684 `application.properties` > JAR\u5305\u5185\u7684 `application.properties`\\r\\n\\r\\n\\r\\n\u8fd9\u6837\u53ef\u80fd\u4e0d\u592a\u76f4\u89c2\uff0c\u800c\u4e14\u6709\u7684\u9879\u76ee\u4f1a\u5c06 application.properties \u6587\u4ef6\u653e\u5728config\u6587\u4ef6\u5939\u5185\uff0c\u4e8e\u662f\u8fdb\u4e00\u6b65\u5bf9\u6bd4\u4e86\u8fd9\u4e24\u4e2a\u4f4d\u7f6e\u7684\u4f18\u5148\u7ea7\uff0c\u7ed3\u679c\u5982\u4e0b\\r\\n\\r\\n`SpringBoot` \u5e94\u7528\u7a0b\u5e8f\u5728\u542f\u52a8\u65f6\u4f1a\u9075\u5faa\u4ee5\u4e0b\u987a\u5e8f\u8fdb\u884c\u52a0\u8f7d\u914d\u7f6e\u6587\u4ef6  \\r\\n1. \u7c7b\u8def\u5f84\u4e0b\u7684\u914d\u7f6e\u6587\u4ef6  \\r\\n2. \u7c7b\u8def\u5f84\u5185`config`\u5b50\u76ee\u5f55\u7684\u914d\u7f6e\u6587\u4ef6  \\r\\n3. \u9879\u76ee\u6839\u76ee\u5f55\u4e0b\u7684\u914d\u7f6e\u6587\u4ef6  \\r\\n4. \u9879\u76ee\u6839\u76ee\u5f55\u4e0b`config`\u5b50\u76ee\u5f55\u7684\u914d\u7f6e\u6587\u4ef6  \\r\\n  \\r\\n```text  \\r\\n. project-sample  \\r\\n\u251c\u2500\u2500 config  \\r\\n\u2502   \u251c\u2500\u2500 application.yml \uff084\uff09  \\r\\n\u2502   \u2514\u2500\u2500 src/main/resources  \\r\\n|   \u2502   \u251c\u2500\u2500 application.yml \uff081\uff09  \\r\\n|   \u2502   \u2514\u2500\u2500 config  \\r\\n|   |   \u2502   \u251c\u2500\u2500 application.yml \uff082\uff09  \\r\\n\u251c\u2500\u2500 application.yml \uff083\uff09  \\r\\n  \\r\\n\u6ce8\uff1asrc/main/resources\u4e0b\u7684\u914d\u7f6e\u6587\u4ef6\u5728\u9879\u76ee\u7f16\u8bd1\u65f6\uff0c\u4f1a\u653e\u5728target/classes\u4e0b  \\r\\n```  \\r\\n\\r\\n**\u542f\u52a8\u65f6\u52a0\u8f7d\u914d\u7f6e\u6587\u4ef6\u987a\u5e8f\uff1a`1 -> 2 -> 3 -> 4`\uff0c\u4f18\u5148\u7ea7 `4 > 3 > 2 > 1`**\\r\\n\\r\\n\u6ce8\u610f\uff1a  \\r\\n- \u5982\u679c\u5728`IDEA`\u4e2d\u662f\u591a `module` \u9879\u76ee\uff0c3 \u548c 4 \u7684\u4f4d\u7f6e\u662f\u6307\u7684\u662f\u9879\u76ee\u6839\u76ee\u5f55\u4e0b\u7684\u4f4d\u7f6e  \\r\\n- \u5f53 .properties \u548c .yml \u6587\u4ef6\u540c\u65f6\u5b58\u5728\u65f6\uff0c.properties\u4f1a\u5931\u6548\uff0c.yml\u4f1a\u8d77\u4f5c\u7528\u3002  \\r\\n  \\r\\n![](http://file.huhan.tech/images/202205291130509.png)\\r\\n\\r\\n\\r\\n## \u4e8c\u3001bootstrap.yml\u914d\u7f6e\u6587\u4ef6\\r\\n\\r\\n\u5728 `SpringCloud` \u7684\u9879\u76ee\u4e2d\uff0c\u6211\u4eec\u5e38\u5e38\u4f1a\u78b0\u5230\u53e6\u5916\u4e00\u4e2a\u914d\u7f6e\u6587\u4ef6 `bootstrap.yml`\u3002\u8fd9\u4e2a\u914d\u7f6e\u6587\u4ef6\u4e3b\u8981\u662f\u7528\u4e8e\u5e94\u7528\u7a0b\u5e8f\u4e0a\u4e0b\u6587\u7684\u5f15\u5bfc\u9636\u6bb5\uff0c\u8be5\u914d\u7f6e\u6587\u4ef6\u7684\u52a0\u8f7d\u662f\u5728 `application.yml` \u4e4b\u524d\u3002\\r\\n\\r\\nbootstrap.yml \u548c application.yml \u6587\u4ef6\u7684\u533a\u522b\u53ef\u53c2\u8003\uff1a[What is the difference between putting a property on application.yml or bootstrap.yml in spring boot](https://stackoverflow.com/questions/32997352/what-is-the-difference-between-putting-a-property-on-application-yml-or-bootstra)\\r\\n\\r\\n\u5728 SpringCloud \u4e2d\u6709\u4e24\u79cd\u4e0a\u4e0b\u6587\uff0c\u4e00\u79cd\u662f bootstrap, \u53e6\u5916\u4e00\u79cd\u662f application, bootstrap \u662f\u5e94\u7528\u7a0b\u5e8f\u7684\u7236\u4e0a\u4e0b\u6587\u3002\u5b98\u65b9\u7684\u539f\u8bdd\u662f [A Spring Cloud application operates by creating a\xa0\u201cbootstrap\u201d\xa0context, which is a parent context for the main application](https://cloud.spring.io/spring-cloud-commons/multi/multi__spring_cloud_context_application_context_services.html#_the_bootstrap_application_context)\u3002\\r\\n\\r\\n`bootstrap.yml`\u914d\u7f6e\u6587\u4ef6\u7684\u4f7f\u7528\u573a\u666f\uff1a\\r\\n- \u4f7f\u7528\u914d\u7f6e\u4e2d\u5fc3\u65f6\uff0c\u8fd9\u65f6\u9700\u8981\u5728bootstrap\u914d\u7f6e\u6587\u4ef6\u4e2d\u6dfb\u52a0\u8fde\u63a5\u5230\u914d\u7f6e\u4e2d\u5fc3\u7684\u4fe1\u606f\uff0c\u6765\u52a0\u8f7d\u5916\u90e8\u914d\u7f6e\u4e2d\u5fc3\u7684\u914d\u7f6e\u4fe1\u606f\\r\\n- \u4e00\u4e9b\u56fa\u5b9a\u7684\u4e0d\u80fd\u88ab\u8986\u76d6\u7684\u5c5e\u6027\\r\\n- \u4e00\u4e9b\u52a0\u5bc6/\u89e3\u5bc6\u7684\u4fe1\u606f\\r\\n\\r\\n\u9879\u76ee\u4e2d `bootstrap.yml` \u793a\u4f8b\\r\\n\\r\\n```yml\\r\\n\\r\\nspring:\\r\\n  application:\\r\\n    name: \\r\\n  profiles:\\r\\n    active: local\\r\\n  cloud:\\r\\n    nacos:\\r\\n      # \u8fdc\u7a0b\u914d\u7f6e\\r\\n      config:\\r\\n        server-addr: \\r\\n        namespace: \\r\\n        group: ${spring.profiles.active}\\r\\n        file-extension: yml\\r\\n      # \u670d\u52a1\u53d1\u73b0\\r\\n      discovery:\\r\\n        server-addr: \\r\\n        namespace: \\r\\n        group: ${spring.profiles.active}\\r\\n\\r\\n```\\r\\n\\r\\n\\r\\n## \u4e09\u3001\u914d\u7f6e\u4e2d\u5fc3\u7684\u914d\u7f6e\\r\\n\\r\\n\u5728 `SpringCloud` \u9879\u76ee\u4e2d\uff0c\u6211\u4eec\u7684\u914d\u7f6e\u5e38\u7531\u914d\u7f6e\u4e2d\u5fc3\u8fdb\u884c\u7edf\u4e00\u7ba1\u7406\uff0c\u8fd9\u5c31\u6d89\u53ca\u5230\u672c\u5730\u4e0e\u8fdc\u7a0b\u914d\u7f6e\u6587\u4ef6\u7684\u4f18\u5148\u7ea7\u95ee\u9898\u3002\u8fd9\u91cc\u53ea\u8bf4\u660e\u9047\u5230\u8fc7\u7684\u4e24\u79cd: SpringCloud Config \u548c Nacos\u3002\\r\\n\\r\\n1. SpringCloud Config\\r\\n\\r\\nSpringCloud Config \u4e2d\u7684\u8fdc\u7a0b\u914d\u7f6e\uff0c\u9ed8\u8ba4\u662f\u65e0\u6cd5\u88ab\u672c\u5730\u8986\u76d6\uff0c\u5982\u679c\u9700\u8981\u672c\u5730\u914d\u7f6e\u8986\u76d6\u8fdc\u7a0b\u914d\u7f6e\uff0c\u9700\u8981\u5728\u8fdc\u7a0b\u505a\u5982\u4e0b\u914d\u7f6e\uff1a\\r\\n\\r\\n```yml\\r\\nspring:  \\r\\n  cloud:  \\r\\n    config:  \\r\\n      allowOverride: true  \\r\\n      overrideNone: true  \\r\\n      overrideSystemProperties: false\\r\\n```\\r\\n\\r\\n\u4e0a\u9762\u7684\u8bf4\u6cd5\u53ef\u4ee5\u5728\u5982\u4e0b\u94fe\u63a5\u4e2d\u5f97\u5230\u9a8c\u8bc1\uff1a\\r\\nhttps://cloud.spring.io/spring-cloud-commons/multi/multi__spring_cloud_context_application_context_services.html#overriding-bootstrap-properties\\r\\n\\r\\n2. Nacos\\r\\n\\r\\nNacos\u4e2d\u7684\u8fdc\u7a0b\u914d\u7f6e\uff0c\u4f3c\u4e4e\u4e0d\u652f\u6301\u672c\u5730\u8986\u76d6\uff0c\u5728Nacos\u9879\u76ee\u4e2dIssue\u4e2d\u5f97\u5230\u8bc1\u5b9e\uff0c\u4f3c\u4e4e\u5b98\u65b9\u4e5f\u6ca1\u6709\u8fd9\u79cd\u6253\u7b97\u3002\u503c\u5f97\u4e00\u63d0\u7684\u662f\uff0c\u5373\u4f7f\u901a\u8fc7\u547d\u4ee4\u884c\u6307\u5b9a\u7684\u53c2\u6570\uff0c\u4e5f\u4e0d\u80fd\u8986\u76d6\u8fdc\u7a0b\u914d\u7f6e\u3002\\r\\n\\r\\n\u5173\u4e8e\u8be5\u95ee\u9898\u7684Issue:\\r\\n\\r\\n- [Unable to override datasource](https://github.com/alibaba/nacos/issues/4190)\\r\\n- [\u5728\u4f7f\u7528\u547d\u4ee4\u884c\u53c2\u6570(-Dserver.port = 9000)\u542f\u52a8\u88abnacos\u7ba1\u7406\u7684\u670d\u52a1\u5ba2\u6237\u7aef\u65f6,\u53d1\u73b0\u547d\u4ee4\u884c\u53c2\u6570\u6ca1\u6709\u751f\u6548](https://github.com/alibaba/nacos/issues/3510)\\r\\n- [nacos\u662f\u5426\u5b58\u5728\u7c7b\u4f3cspringcloudconfig\u7684allow-override\u7b49\u672c\u5730\u63a7\u5236\u6743\u9650\u53c2\u6570\uff1f\u6216\u8005\u662f\u5426\u652f\u6301\u8fd9\u4e2a\u53c2\u6570](https://github.com/alibaba/nacos/issues/3981)\\r\\n\\r\\n\\r\\n## \u56db\u3001\u8e29\u8fc7\u7684\u5751\\r\\n\\r\\n\u5728\u4e00\u6b21\u5f00\u53d1\u8fc7\u7a0b\u4e2d\uff0c\u6211\u4eec\u5e0c\u671b\u670d\u52a1(serviceA)\u7684\u67d0\u4e9b\u8282\u70b9\u7684\u914d\u7f6e\u4e0e\u5176\u4ed6\u8282\u70b9\u914d\u7f6e\u4e0d\u540c\uff0c\u521a\u5f00\u59cb\u7684\u60f3\u6cd5\u662f\u5728\u542f\u52a8\u547d\u4ee4\u884c\u52a0\u5165\u53c2\u6570 `spring.application.name=serviceB`\uff0c\u7136\u540e\u5728\u914d\u7f6e\u4e2d\u5fc3 `nacos`  \u4e2d\u590d\u5236\u4e00\u4efdserviceA\u7684\u914d\u7f6e\u547d\u540d\u4e3a service B\u3002\u4f46\u662f\u5b9e\u9645\u6d4b\u8bd5\u4e2d\uff0c\u4e0d\u80fd\u4fee\u6539 application.name \u7684\u503c\uff0c\u56e0\u4e3a\u53c2\u4e0e\u5230\u4e00\u4e9b\u4e1a\u52a1\u914d\u7f6e\u3002\\r\\n\\r\\n\u63a5\u7740\u6211\u4eec\u60f3\u76f4\u63a5\u5728\u547d\u4ee4\u884c\u4e2d\u52a0\u5165\u533a\u522b\u4e8e\u5176\u4ed6\u8282\u70b9\u7684\u53c2\u6570\uff0c\u5e0c\u671b\u80fd\u591f\u8986\u76d6\u8fdc\u7a0b\u7684\u914d\u7f6e\uff0c\u4f46\u524d\u9762\u4e5f\u8bf4\u8fc7\uff0c\u547d\u4ee4\u884c\u7684\u914d\u7f6e\u65e0\u6cd5\u8986\u76d6\u8fdc\u7a0bNacos\u914d\u7f6e\uff0c\u4e14Nacos\u6ca1\u6709\u63d0\u4f9b\u652f\u6301\u8986\u76d6\u7684\u5f00\u5173\uff0c\u6240\u4ee5\u4e5f\u6ca1\u80fd\u8fbe\u5230\u6211\u4eec\u9884\u671f\u7684\u7ed3\u679c\u3002\\r\\n\\r\\n\u5b9e\u9645\u6d4b\u8bd5\u7684\u7ed3\u679c\uff0c\u914d\u7f6e\u4f18\u5148\u7ea7\uff1a**nacos\u4e0a\u7684\u914d\u7f6e > \u547d\u4ee4\u884c\u914d\u7f6e > system env > classpath:application.yml > classpath:bootstrap.yml**\\r\\n\\r\\n\u6700\u540e\u6211\u4eec\u53d1\u73b0nacos\u652f\u6301\u6307\u5b9a\u670d\u52a1\u914d\u7f6e\uff0c\u4ee5\u53ca\u670d\u52a1\u53d1\u73b0\u7684\u540d\u79f0\uff0c\u8fd9\u4e9b\u914d\u7f6e\u662f\u5728 `bootstap.yml` \u6587\u4ef6\u4e2d\u6307\u5b9a\uff0c\u9ed8\u8ba4\u503c\u662f `spring.application.name`\u3002\u5b9e\u9645\u6d4b\u8bd5\u7ed3\u679c\uff0c\u901a\u8fc7\u547d\u4ee4\u884c\u53ef\u4ee5\u8986\u76d6\u8be5\u6587\u4ef6\u4e2d\u7684\u914d\u7f6e\uff0c\u8fd9\u6837\u6b63\u597d\u80fd\u591f\u6ee1\u8db3\u6211\u4eec\u7684\u9700\u6c42\uff1a\u4e0d\u4fee\u6539application.name\uff0c\u53c8\u53ef\u4ee5\u4f7f\u90e8\u5206\u8282\u70b9\u7684\u914d\u7f6e\u533a\u522b\u4e8e\u5176\u4ed6\u8282\u70b9\u3002\\r\\n\\r\\n```shell\\r\\njava -jar ./app.jar --spring.profiles.active=local --spring.cloud.nacos.config.name=serviceB --spring.cloud.nacos.discovery.service=serviceB\\r\\n```\\r\\n\\r\\n\\r\\n## \u4e94\u3001\u53c2\u8003\u8d44\u6599\\r\\n\\r\\n- [SpringBoot Externalized Configuration](https://docs.spring.io/spring-boot/docs/2.2.9.RELEASE/reference/htmlsingle/#boot-features-external-config)\\r\\n- [Nacos \u914d\u7f6e\u4e2d\u5fc3\uff0c\u53ef\u914d\u7f6e\u9879](https://github.com/alibaba/spring-cloud-alibaba/wiki/Nacos-config-en#more-information-about-nacos-config-starter-configurations)\\r\\n- [Nacos\u6ce8\u518c\u4e2d\u5fc3\uff0c\u53ef\u914d\u7f6e\u9879](https://github.com/alibaba/spring-cloud-alibaba/wiki/Nacos-discovery-en#more-information-about-nacos-discovery-starter-configurations)"},{"id":"jvm-dump-file-analysis-experience","metadata":{"permalink":"/blog/jvm-dump-file-analysis-experience","source":"@site/blog\\\\2022-03-12-\u8bb0\u4e00\u6b21dump\u6587\u4ef6\u5206\u6790\u5386\u7a0b.md","title":"\u8bb0\u4e00\u6b21dump\u6587\u4ef6\u5206\u6790\u5386\u7a0b","description":"\u672c\u6587\u8bb0\u5f55\u4e86\u4e00\u6b21\u6392\u67e5JVM\u5185\u5b58\u6cc4\u9732\u7684\u7ecf\u5386\u3002","date":"2022-03-12T00:00:00.000Z","formattedDate":"2022\u5e743\u670812\u65e5","tags":[{"label":"JVM","permalink":"/blog/tags/jvm"}],"truncated":true,"authors":[{"name":"hans"}],"frontMatter":{"slug":"jvm-dump-file-analysis-experience","title":"\u8bb0\u4e00\u6b21dump\u6587\u4ef6\u5206\u6790\u5386\u7a0b","authors":{"name":"hans"},"tags":["JVM"]},"prevItem":{"title":"SpringBoot\u914d\u7f6e\u6587\u4ef6\u52a0\u8f7d\u4f18\u5148\u7ea7","permalink":"/blog/springboot-config-priority"},"nextItem":{"title":"Windows\u4e0bGit\u591a\u8d26\u6237\u7ba1\u7406","permalink":"/blog/multi-git-manage"}},"content":"\u672c\u6587\u8bb0\u5f55\u4e86\u4e00\u6b21\u6392\u67e5JVM\u5185\u5b58\u6cc4\u9732\u7684\u7ecf\u5386\u3002\\n\\n\x3c!--truncate--\x3e\\n\\n## \u4e00\u3001\u80cc\u666f\\n\\n\u4eca\u5929\u4e0b\u5348\uff0c\u6b63\u9163\u7545\u6dcb\u6f13\u7684\u642c\u7816\uff0c\u7a81\u7136\u8fd0\u7ef4\u540c\u4e8b\u5728\u7fa4\u91cc\u901a\u77e5\uff0c\u6838\u5fc3\u670d\u52a1\u67d0\u4e2a\u8282\u70b9\u5185\u5b58\u5f02\u5e38\uff0c\u670d\u52a1\u5047\u6b7b\u3002\u795e\u7ecf\u4e00\u4e0b\u5b50\u7d27\u5f20\u8d77\u6765\uff0c\u8d76\u7d27\u8dd1\u5230\u8fd0\u7ef4\u90a3\u8fb9\u89c2\u5bdf\u73b0\u8c61\u3002\\n\\n\u89c2\u5bdf\u7684\u7ed3\u679c\u662f\u670d\u52a1\u5185\u5b58\u6ea2\u51fa\uff0c\u8be5\u670d\u52a1\u662f\u6838\u5fc3\u670d\u52a1\uff0c\u5206\u914d\u4e865G\u5185\u5b58\u3002\u8fd0\u7ef4\u5728\u8f6c\u5b58\u5feb\u7167\u540e\uff0c\u7acb\u523b\u91cd\u542f\u670d\u52a1\u540e\u6b63\u5e38\u3002\u5728\u63a5\u4e0b\u6765\u7684\u4e00\u6bb5\u65f6\u95f4\u91cc\uff0c\u53e6\u4e00\u53f0\u670d\u52a1\u8282\u70b9\u4e5f\u53d1\u751f\u4e86\u540c\u6837\u7684\u60c5\u51b5\u3002\\n\\n## \u4e8c\u3001\u5206\u6790\u8fc7\u7a0b\\n\\n\u8fd9\u4e2a\u670d\u52a1\u662f\u53e6\u5916\u4e00\u4e2a\u540c\u4e8b\u8d1f\u8d23\u5f00\u53d1\u7684\uff0c\u672c\u7740\u5b66\u4e60\u7684\u6001\u5ea6\uff0c\u5728\u62ff\u5230\u8fd0\u7ef4\u8f6c\u5b58\u7684dump\u6587\u4ef6\u540e\uff0c\u5c31\u51c6\u5907\u5c1d\u8bd5\u7740\u5206\u6790\u4e0b\u95ee\u9898\uff0c\u7531\u4e8e\u4e4b\u524d\u6ca1\u6709\u7c7b\u4f3c\u7684\u7ecf\u5386\uff0c\u4e8e\u662f\u5148\u5728\u7f51\u4e0a\u67e5\u4e86\u4e0b\u4e00\u822c\u600e\u4e48\u5206\u6790\u7c7b\u4f3c\u7684\u95ee\u9898\u3002\\n\\n\u9996\u5148\u5c1d\u8bd5\u4f7f\u7528MAT(Memory Analyzer)\u5de5\u5177\u8fdb\u884c\u5206\u6790\uff0c\u4e0b\u8f7d\u540e\u5c31\u51c6\u5907\u8f7d\u5165dump\u6587\u4ef6\uff0c\u5f88\u4e0d\u5e78\u7531\u4e8edump\u6587\u4ef6\u8fc7\u5927\uff0c\u8f7d\u5165\u5931\u8d25\u4e86\uff0c\u4e8e\u662f\u8c03\u5927\u4e86\u5185\u5b58\u5927\u5c0f\uff0c\u5c1d\u8bd5\u518d\u6b21\u8f7d\u5165\uff0c\u4f46\u6b64\u65f6\u8fd9\u4e2a\u6587\u4ef6\u4e0d\u518d\u5c1d\u8bd5\u91cd\u65b0\u8f7d\u5165\uff0c\u76f4\u63a5\u63d0\u793a\u8f7d\u5165\u5931\u8d25\u3002\\n\\n\u5148\u4e0d\u7ea0\u7ed3\u5de5\u5177\u7684\u95ee\u9898\uff0c\u7136\u540e\u7f51\u4e0a\u8bf4JDK\u81ea\u5e26\u7684`jvisualvm`\u4e5f\u53ef\u4ee5\u7528\u6765\u5206\u6790dump\u6587\u4ef6, \u4f46\u4e5f\u9047\u5230\u4e86\u540c\u6837\u5185\u5b58\u4e0d\u8db3\u7684\u95ee\u9898\uff0c\u518d\u5c1d\u8bd5\u4fee\u6539`jvisualvm`\u7684\u5185\u5b58\u9650\u5236\u540e, \u6210\u529f\u8f7d\u5165\u4e86\u3002\\n\\n\u770b\u5230\u7684\u754c\u9762\u662f\u8fd9\u6837\u7684\uff0c\u5f88\u660e\u663e\u770b\u5230char[]\u5360\u7528\u4e86\u8fd170%\u7684\u5185\u5b58\uff0c\u63a5\u8fd14G\uff0c\u8fd9\u592a\u4e0d\u6b63\u5e38\u4e86\uff0c\u70b9\u8fdb\u53bb\u770b\u5bf9\u5e94\u7684\u5b9e\u4f8b(\u52a0\u8f7d\u7684\u975e\u5e38\u6162\uff0c\u9700\u8981\u8010\u5fc3)\u3002\\n\\n![](http://file.huhan.tech/images/202205291114190.png)\\n\\n\u5728\u5b9e\u4f8b\u6570\u754c\u9762\u4e2d\u770b\u5230\u5b9e\u4f8b\u6570\u8fbe\u5230\u4e86\u5343\u4e07\u7ea7\uff0c\u5927\u90e8\u5206\u90fd\u662f\u4e00\u4e9b\u6587\u4ef6\u7684\u8def\u5f84\u5b57\u7b26\u4e32\u4fe1\u606f\u3002\u5728\u4e1a\u52a1\u4e2d\uff0c\u6211\u4eec\u4f1a\u751f\u6210\u5f88\u591a\u4e34\u65f6\u6587\u4ef6\uff0c\u7136\u540e\u8fd9\u4e9b\u4e34\u65f6\u6587\u4ef6\u4f1a\u5220\u9664\uff0c\u8fd9\u91cc\u9762\u5927\u90e8\u5206\u4fdd\u5b58\u7684\u662f\u8fd9\u4e9b\u4e34\u65f6\u6587\u4ef6\u8def\u5f84\u3002\\n\\n![](http://file.huhan.tech/images/202205291115665.png)\\n\\n\u5230\u8fd9\u91cc\u5bfc\u81f4\u5185\u5b58\u6cc4\u9732\u7684\u539f\u56e0\u4f3c\u4e4e\u627e\u5230\u4e86\uff0c\u4f46\u597d\u50cf\u53c8\u8fd8\u4e0d\u591f\uff0c\u662f\u4ec0\u4e48\u539f\u56e0\u5bfc\u81f4\u8fd9\u4e9b\u4e34\u65f6\u53d8\u91cf\u6ca1\u6709\u88ab\u56de\u6536\u5462\u3002\\n\\n\u56de\u5230\u5bb6\u540e\uff0c\u8fd8\u662f\u60f3\u7740\u8fd9\u4e2a\u4e8b\u60c5\uff0c\u4e8e\u662f\u53c8\u5f00\u59cb\u7814\u7a76\u8d77\u6765\uff0c\u8fd9\u4e2a\u65f6\u5019\u60f3\u8d77\u6765\u53ef\u4ee5\u518d\u7528MAT\u8bd5\u7740\u5206\u6790\u4e0b\uff0c\u6bd5\u7adf\u636e\u8bf4\u5de5\u5177\u5f88\u5f3a\u5927\u3002\u91cd\u542f\u4e86\u7535\u8111\u4e4b\u540e\uff0c\u7ecf\u8fc7\u6f2b\u957f\u7684\u7b49\u5f85\uff0c\u8f7d\u5165\u6210\u529f\u4e86(\u679c\u7136\u91cd\u542f\u80fd\u89e3\u51b3\u4e00\u5207\u95ee\u9898)\u3002\\n\\nMAT\u7684\u754c\u9762\u662f\u8fd9\u6837\u7684\uff0c\u91cc\u9762\u5305\u542b\u7684\u4fe1\u606f\u6bd4\u8f83\u591a\uff0c\u5bf9\u4e8e\u6211\u8fd9\u4e2a\u83dc\u9e1f\u6765\u8bf4\uff0c\u786e\u5b9e\u4e00\u4e0b\u5b50\u4e0d\u77e5\u9053\u770b\u54ea\u91cc\u3002\\n\u90a3\u5c31\u4e00\u4e2a\u4e2a\u6162\u6162\u770b\u5427\uff0cHistogram\u91cc\u9762\u7684\u4e0e\u4f7f\u7528`jvisualvm`\u4e2d\u770b\u5230\u7684\u4fe1\u606f\u662f\u76f8\u540c\u7684\u3002\\n\\n![](http://file.huhan.tech/images/202205291115133.png)\\n\\n\u63a5\u4e0b\u6765\u8fdb\u5165\u5230`Dominator Tree`\u89c6\u56fe, \u5217\u51fa\u5f53\u524d\u5b58\u6d3b\u7684\u5bf9\u8c61\u7684\u5185\u5b58\u5927\u5c0f\uff0c\u8fd9\u770b\u8d77\u6765\u50cf\u662f\u6211\u9700\u8981\u5173\u6ce8\u7684\u91cd\u70b9\u3002\u7136\u540e\u67e5\u4e86\u4e0b\u8fd9\u4e2a\u7c7b `java.io.DeleteOnExitHook`  \u4e0e \u5185\u5b58\u6cc4\u9732\u7684\u76f8\u5173\u95ee\u9898\u3002\\n\\n![](http://file.huhan.tech/images/202205291116984.png)\\n\\n\u8fd9\u4e2a\u95ee\u9898\u5728\u4e0b\u9762\u4e24\u4e2a\u94fe\u63a5\u4e2d\u7ed9\u51fa\u4e86\u8bf4\u660e\uff0c\u5927\u6982\u610f\u601d\u662f\u5728\u5220\u9664\u6587\u4ef6\u4f7f\u7528 `File.deleteOnExit()` \u65b9\u6cd5\u65f6\uff0c\u5e76\u4e0d\u662f\u7acb\u523b\u5220\u9664\u6587\u4ef6\uff0c\u800c\u662f\u5c06\u8be5\u6587\u4ef6\u8def\u5f84\u7ef4\u62a4\u5728\u7c7bDeleteOnExit\u7684\u4e00\u4e2aLinkedHashSet\u4e2d\uff0c\u6700\u540e\u5728JVM\u5173\u95ed\u7684\u65f6\u5019\uff0c\u624d\u4f1a\u53bb\u5220\u9664\u8fd9\u91cc\u9762\u7684\u6587\u4ef6\uff0c\u8fd9\u4e2a\u65b9\u6cd5\u4e0d\u80fd\u7528\u4e8e\u957f\u65f6\u95f4\u8fd0\u884c\u7684\u670d\u52a1\u3002\\nhttps://stackoverflow.com/questions/40119188/memory-leak-on-deleteonexithook\\nhttps://bugs.openjdk.java.net/browse/JDK-6664633\\n\\n\u4e0a\u9762\u7684\u63cf\u8ff0\uff0c\u901a\u8fc7\u6e90\u7801\u548cJDK\u6587\u6863\u4e5f\u90fd\u5f97\u5230\u4e86\u8bc1\u660e\u3002\\n\\n```java\\n// java.io.File\\n// Requests that the file or directory denoted by this abstract pathname be deleted when the virtual machine terminates.\\npublic void deleteOnExit() {\\n\\tSecurityManager security = System.getSecurityManager();\\n\\tif (security != null) {\\n\\t\\tsecurity.checkDelete(path);\\n\\t}\\n\\tif (isInvalid()) {\\n\\t\\treturn;\\n\\t}\\n\\tDeleteOnExitHook.add(path);\\n}\\n\\n// java.io.DeleteOnExitHook\\nprivate static LinkedHashSet<String> files = new LinkedHashSet<>();\\n\\nstatic synchronized void add(String file) {\\n\\tif(files == null) {\\n\\t\\t// DeleteOnExitHook is running. Too late to add a file\\n\\t\\tthrow new IllegalStateException(\\"Shutdown in progress\\");\\n\\t}\\n\\n\\tfiles.add(file);\\n}\\n```\\n\\n\\n## \u4e09\u3001\u7ed3\u8bba\\n\\n\u95ee\u9898\u5b9a\u4f4d\u4e8e`File.deleteOnExit()`\u65b9\u6cd5\u7684\u8c03\u7528\uff0c\u5bfc\u81f4\u5185\u5b58\u6cc4\u6f0f\u3002\u8c03\u7528\u8be5\u65b9\u6cd5\u53ea\u4f1a\u5c06\u9700\u8981\u5220\u9664\u6587\u4ef6\u7684\u8def\u5f84\uff0c\u7ef4\u62a4\u5728\u7c7b`DeleteOnExit`\u7684\u4e00\u4e2aLinkedHashSet\u4e2d\uff0c\u5728JVM\u5173\u95ed\u65f6\uff0c\u624d\u4f1a\u53bb\u771f\u6b63\u6267\u884c\u5220\u9664\u6587\u4ef6\u64cd\u4f5c\u3002\u8fd9\u6837\u5bfc\u81f4`DeleteOnExitHook`\u8fd9\u4e2a\u5bf9\u8c61\u8d8a\u6765\u8d8a\u5927\uff0c\u6700\u7ec8\u5185\u5b58\u6ea2\u51fa\u3002\\n\\n`File.delete()`\u4e0e `File.deleteOnExit()` \u7684\u533a\u522b\uff1a\\n\u5f53\u8c03\u7528delete()\u65b9\u6cd5\u65f6\uff0c\u76f4\u63a5\u5220\u9664\u6587\u4ef6\uff0c\u4e0d\u7ba1\u8be5\u6587\u4ef6\u662f\u5426\u5b58\u5728\uff0c\u4e00\u7ecf\u8c03\u7528\u7acb\u5373\u6267\u884c\\n\u5f53\u8c03\u7528deleteOnExit()\u65b9\u6cd5\u65f6\uff0c\u53ea\u662f\u76f8\u5f53\u4e8e\u5bf9deleteOnExit()\u4f5c\u4e00\u4e2a\u58f0\u660e\uff0c\u5f53\u7a0b\u5e8f\u8fd0\u884c\u7ed3\u675f\uff0cJVM\u7ec8\u6b62\u65f6\u624d\u771f\u6b63\u8c03\u7528deleteOnExit()\u65b9\u6cd5\u5b9e\u73b0\u5220\u9664\u64cd\u4f5c\u3002\\n\\n\u6211\u5199\u4e86\u4e0b\u9762\u8fd9\u4e2a\u6d4b\u8bd5\u65b9\u6cd5\uff0c\u5bf9\u6bd4 `delete()`\u548c`deleteOnExit()`\u7684\u533a\u522b\uff0c\u73b0\u8c61\u4f1a\u6bd4\u8f83\u660e\u663e\u3002\u4f7f\u7528`deleteOnExit`\u65f6\u662f\u5728\u6587\u4ef6\u5168\u90e8\u521b\u5efa\uff0cJVM\u5173\u95ed\u7684\u65f6\u5019\uff0c\u624d\u4e00\u4e2a\u4e2a\u5220\u9664\u6587\u4ef6\uff0c`delete`\u4f1a\u7acb\u523b\u5220\u9664\u6587\u4ef6\u3002(\u6240\u4ee5\u8fd9\u4e2a\u65b9\u6cd5\u7684\u4f7f\u7528\u573a\u666f\u662f\u600e\u6837\u7684\uff0c\u6211\u5c31\u4e0d\u592a\u6e05\u695a\u4e86)\\n```java\\npublic static void loopTest() throws IOException {\\n\\tString root = \\"D:\\\\\\\\C_Temp\\\\\\\\files\\\\\\\\\\";\\n\\n\\tFile path = new File(root);\\n\\tif (!path.exists()) {\\n\\t\\tpath.mkdirs();\\n\\t}\\n\\tint i = 0;\\n\\twhile (i < 40000) {\\n\\t\\tFile file = new File(path, \\"Hello-\\" + i + \\".txt\\");\\n\\t\\tfile.createNewFile();\\n\\t\\tfile.delete();\\n//            file.deleteOnExit();\\n\\t\\ti++;\\n\\t}\\n}\\n```\\n\\n## \u56db\u3001\u6536\u83b7\\n\\n\u672c\u6b21\u6392\u67e5\u7ecf\u5386\u6700\u5927\u7684\u6536\u83b7\u5c31\u662f\u5c1d\u8bd5\u5229\u7528\u5de5\u5177\u5206\u6790dump\u6587\u4ef6\uff0c\u4ee5\u524d\u5bf9\u8fd9\u79cd\u90fd\u662f\u671b\u800c\u5374\u6b65\uff0c\u611f\u89c9\u5f88\u96be\u3002\u4f46\u8fd9\u6b21\u5e26\u7740\u95ee\u9898\u53bb\u5206\u6790\u3001\u601d\u8003\uff0c\u8fd9\u6837\u4e0b\u6765\u4e5f\u4e0d\u7b97\u8fc7\u4e8e\u590d\u6742\u3002\u6709\u4e9b\u95ee\u9898\u4e0d\u662f\u95ee\u9898\u672c\u8eab\u96be\uff0c\u662f\u81ea\u5df1\u628a\u5b83\u60f3\u5f97\u5f88\u96be\u3002\\n\\n\u4e0b\u9762\u662f\u672c\u6b21\u7684\u4e00\u4e9b\u601d\u8003\u548c\u8e29\u8fc7\u7684\u5751\uff0c\u4ee5\u4f5c\u5907\u5fd8\u3002\\n\\n**1. \u83b7\u53d6dump\u6587\u4ef6\u6709\u4e24\u79cd\u65b9\u6cd5**\\n\\n1)\u901a\u8fc7 `jmap` \u5de5\u5177\u751f\u6210\u53ef\u4ee5\u751f\u6210\u4efb\u610fJava\u8fdb\u7a0b\u7684dump\u6587\u4ef6\\n```shell\\n# \u5148\u627e\u5230PID\\nps -ef | grep java\\n\\n# jmap \u8f6c\u5b58\u5feb\u7167\\njmap -dump:format=b,file=/opt/dump/test.dump {PID}\\n```\\n\\n2)\u901a\u8fc7\u914d\u7f6eJVM\u542f\u52a8\u53c2\u6570\\n```shell\\n#  \u5f53\u7a0b\u5e8f\u51fa\u73b0OutofMemory\u65f6\uff0c\u5c06\u4f1a\u5728\u76f8\u5e94\u7684\u76ee\u5f55\u4e0b\u751f\u6210\u4e00\u4efddump\u6587\u4ef6\uff0c\u5982\u679c\u4e0d\u6307\u5b9a\u9009\u9879HeapDumpPath\u5219\u5728\u5f53\u524d\u76ee\u5f55\u4e0b\u751f\u6210dump\u6587\u4ef6\\n-XX:+HeapDumpOnOutOfMemoryError -XX:HeapDumpPath=/opt/dumps\\n```\\n\\n![](http://file.huhan.tech/images/202205291116514.png)\\n\\n**2. MAT\u9700\u8981JDK11\u624d\u80fd\u8fd0\u884c**\\n\\n\u89e3\u51b3\u529e\u6cd5\u662f\uff0c\u6253\u5f00MAT\u7684\u5b89\u88c5\u76ee\u5f55\uff0c\u6709\u4e00\u4e2a\u914d\u7f6e\u6587\u4ef6MemoryAnalyzer.ini\u3002\u6253\u5f00\u8fd9\u4e2a\u6587\u4ef6\uff0c\u5728\u6587\u4ef6\u4e2d\u6307\u5b9aJDK\u7248\u672c\u5373\u53ef\u3002\u65b0\u589e\u4e24\u884c\u914d\u7f6e\uff1a\\n```shell\\n-vm D:/jdkPath/bin/javaw.exe\\n```\\n\\n**3. \u5728\u4f7f\u7528jvisualvm\u5206\u6790\u5927\u7684dump\u6587\u4ef6\u65f6\uff0c\u5806\u67e5\u5668\u4f7f\u7528\u7684\u5185\u5b58\u4e0d\u8db3**\\n\\n\u4fee\u6539JAVA_HOME/lib/visualvm/etc/visualvm.conf\u6587\u4ef6\u4e2d visualvm_default_options=\\"-J-client -J-Xms24 -J-Xmx256m\\"\uff0c\u7136\u540e\u91cd\u542fjvisualVM\u5373\u53ef\\n\\n**4. MAT\u4fee\u6539\u5185\u5b58\u7a7a\u95f4**\\n\\n\u5206\u6790\u5806\u8f6c\u50a8\u6587\u4ef6\u9700\u8981\u6d88\u8017\u5f88\u591a\u7684\u5806\u7a7a\u95f4\uff0c\u4e3a\u4e86\u4fdd\u8bc1\u5206\u6790\u7684\u6548\u7387\u548c\u6027\u80fd\uff0c\u5728\u6709\u6761\u4ef6\u7684\u60c5\u51b5\u4e0b\uff0c\u5efa\u8bae\u5206\u914d\u7ed9 MAT \u5c3d\u53ef\u80fd\u591a\u7684\u5185\u5b58\u8d44\u6e90\u3002\u4e24\u79cd\u65b9\u5f0f\u5206\u914d\u5185\u5b58\u8d44\u6e90\u7ed9 MAT\uff1a\\n1\uff09\u4fee\u6539\u542f\u52a8\u53c2\u6570 MemoryAnalyzer.exe -vmargs -Xmx4g\\n2\uff09\u7f16\u8f91\u6587\u4ef6 MemoryAnalyzer.ini \u6dfb\u52a0 -vmargs \u2013 Xmx4g\\n\\n\u8fd9\u91cc\u4e5f\u5217\u4e00\u4e2a\u4ee3\u529e\u9879\\n- \u5b66\u4e60`MAT`\u5de5\u5177\u7684\u4f7f\u7528\\n\\n\\n\u53c2\u8003\u7684\u4e00\u4e9b\u6587\u7ae0\uff1a\\n- jvisualvm\u5206\u6790\uff1ahttps://zhuanlan.zhihu.com/p/163774290\\n- MAT\u5b9a\u4f4d\u5927\u5bf9\u8c61\uff1ahttps://www.cnblogs.com/rb2010/p/14741674.html\\n- MAT\u8be6\u7ec6\uff1ahttps://blog.csdn.net/Jin_Kwok/article/details/80326088\\n- https://www.jianshu.com/p/82b25cf8cfde"},{"id":"multi-git-manage","metadata":{"permalink":"/blog/multi-git-manage","source":"@site/blog\\\\2019-12-05-Windows\u4e0bGit\u591a\u8d26\u6237\u7ba1\u7406.md","title":"Windows\u4e0bGit\u591a\u8d26\u6237\u7ba1\u7406","description":"\u672c\u6587\u4ee5\u914d\u7f6egithub\u8d26\u53f7\u548cgitlab\u8d26\u53f7\u6765\u9010\u6b65\u6f14\u793a\u5728Windows\u73af\u5883\u4e0b\u914d\u7f6eGit\u591a\u8d26\u53f7\u652f\u6301\u5373\u5728\u540c\u4e00\u4e2a\u7535\u8111\u4e0a\u7ba1\u7406\u591a\u4e2assh-key\uff0c\u5bf9git\u591a\u4e00\u5206\u4e86\u89e3","date":"2019-12-05T00:00:00.000Z","formattedDate":"2019\u5e7412\u67085\u65e5","tags":[{"label":"Git","permalink":"/blog/tags/git"}],"truncated":true,"authors":[],"frontMatter":{"slug":"multi-git-manage","title":"Windows\u4e0bGit\u591a\u8d26\u6237\u7ba1\u7406","tags":["Git"]},"prevItem":{"title":"\u8bb0\u4e00\u6b21dump\u6587\u4ef6\u5206\u6790\u5386\u7a0b","permalink":"/blog/jvm-dump-file-analysis-experience"},"nextItem":{"title":"\u521d\u8bc6ELK","permalink":"/blog/elk"}},"content":"\u672c\u6587\u4ee5\u914d\u7f6e**github**\u8d26\u53f7\u548c**gitlab**\u8d26\u53f7\u6765\u9010\u6b65\u6f14\u793a\u5728Windows\u73af\u5883\u4e0b\u914d\u7f6e**Git\u591a\u8d26\u53f7\u652f\u6301**\u5373\u5728\u540c\u4e00\u4e2a\u7535\u8111\u4e0a**\u7ba1\u7406\u591a\u4e2assh-key**\uff0c\u5bf9git\u591a\u4e00\u5206\u4e86\u89e3\\n\\n\x3c!-- truncate --\x3e\\n\\n## \u751f\u6210\u516c\u94a5\u3001\u79c1\u94a5\\n\\n\u4ee5\u7ba1\u7406\u5458\u65b9\u5f0f\u8fd0\u884cGit Bash\\n\\n1. \u751f\u6210github.com\u5bf9\u5e94\u7684\u79c1\u94a5\u516c\u94a5\\n\\n\u547d\u540d\u4e3aid_rsa_github,\u65b9\u4fbf\u533a\u5206\u3002\u6b64\u65f6\u5f53\u524d\u76ee\u5f55\u751f\u6210\u4e24\u4e2a\u6587\u4ef6`id_rsa_github.pub`\u548c`id_rsa_github`\\n\\n```shell\\nssh-keygen -t rsa -C email\\n```\\n\\n![](https://raw.githubusercontent.com/hans-yoyo/FigureBed/master/2019/12/20191204222919.png)\\n\\n2. \u7528\u540c\u6837\u7684\u65b9\u6cd5\u751f\u6210gitlab\u6240\u7528\u79c1\u94a5\u516c\u94a5\\n\\n\u547d\u540d\u4e3aid_rsa_gitlab.\u90ae\u7bb1\u5730\u5740\u53ef\u4ee5\u76f8\u540c\u53ef\u4ee5\u4e0d\u540c, \u6211\u8fd9\u91cc\u4f7f\u7528\u4e86\u4e0d\u540c\u7684\u90ae\u7bb1\u5730\u5740\\n\\n\u5c06\u4ee5\u4e0a\u751f\u6210\u76844\u4e2a\u6587\u4ef6\u5206\u522b\u653e\u5165\u5230github\u548cgitlab\u4e24\u4e2a\u6587\u4ef6\u5939\u4e2d(\u4e5f\u53ef\u4ee5\u4e0d\u653e\u5728\u6587\u4ef6\u5939)\uff0c\u6211\u8fd9\u91cc\u662f\u4e3a\u4e86\u65b9\u4fbf\u7ba1\u7406\u3002\u5c06\u4e24\u4e2a\u6587\u4ef6\u5939\u62f7\u8d1d\u5230.ssh\u76ee\u5f55(C:\\\\Users\\\\idobe\\\\\\\\.ssh)\u4e0b\\n\\n## \u6dfb\u52a0\u516c\u94a5\u5230Git\u670d\u52a1\u5668\\n\\n\u5c06\u516c\u94a5(`.pub`\u7ed3\u5c3e\u7684\u6587\u4ef6)\u7684\u5185\u5bb9\u6dfb\u52a0\u5230Git\u670d\u52a1\u5668\\n\\n\\n\\n## \u914d\u7f6e\u672c\u5730\u591a\u8d26\u53f7\u7ba1\u7406\\n\\n\u5728.ssh\u76ee\u5f55\u521b\u5efaconfig\u6587\u672c\u6587\u4ef6\u5e76\u5b8c\u6210\u76f8\u5173\u914d\u7f6e(\u6700\u6838\u5fc3\u7684\u5730\u65b9)\\n\\n\u6bcf\u4e2a\u8d26\u53f7\u5355\u72ec\u914d\u7f6e\u4e00\u4e2aHost\uff0c\u6bcf\u4e2aHost\u8981\u53d6\u4e00\u4e2a\u522b\u540d\uff0c\u6bcf\u4e2aHost\u4e3b\u8981\u914d\u7f6eHostName\u548cIdentityFile\u4e24\u4e2a\u5c5e\u6027\u5373\u53ef\\n\\nHost\u7684\u540d\u5b57\u53ef\u4ee5\u53d6\u4e3a\u81ea\u5df1\u559c\u6b22\u7684\u540d\u5b57\\n\\n`config`\u6587\u4ef6\u5185\u5bb9\\n\\n```xml\\nHostName \u3000\u3000\u3000\u3000\u3000\u3000\u3000   \u8fd9\u4e2a\u662f\u771f\u5b9e\u7684\u57df\u540d\u5730\u5740\\nIdentityFile \u3000\u3000\u3000\u3000\u3000\u3000\u3000  \u8fd9\u91cc\u662fid_rsa\u7684\u5730\u5740\\nPreferredAuthentications   \u914d\u7f6e\u767b\u5f55\u65f6\u7528\u4ec0\u4e48\u6743\u9650\u8ba4\u8bc1--\u53ef\u8bbe\u4e3apublickey,password publickey,keyboard-interactive\u7b49\\nUser \u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u914d\u7f6e\u4f7f\u7528\u7528\u6237\u540d\\n\\n# \u914d\u7f6egithub.com\\nHost git@github.com                 \\nHostName github.com\\nIdentityFile C:\\\\\\\\Users\\\\\\\\idobe\\\\\\\\.ssh\\\\\\\\github\\\\\\\\id_rsa_github\\nPreferredAuthentications publickey\\nUser username\\n\\n# \u914d\u7f6egit.oschina.net \\nHost git@gitlab.com\\nHostName gitlab.com\\nIdentityFile C:\\\\\\\\Users\\\\\\\\idobe\\\\\\\\.ssh\\\\\\\\gitlab\\\\\\\\id_rsa_gitlab\\nPreferredAuthentications publickey\\nUser username\\n```\\n\\n## \u6d4b\u8bd5\\n\\n```shell\\n\\nidobe@Hyman-PC MINGW64 ~/Desktop\\n$ ssh -T git@github.com\\nEnter passphrase for key \'C:\\\\\\\\Users\\\\\\\\idobe\\\\\\\\.ssh\\\\\\\\github\\\\\\\\id_rsa_github\':\\nHi hyman213! You\'ve successfully authenticated, but GitHub does not provide shell access\\n\\nidobe@Hyman-PC MINGW64 ~/Desktop\\n$ ssh -T git@gitlab.com\\nEnter passphrase for key \'C:\\\\\\\\Users\\\\\\\\idobe\\\\\\\\.ssh\\\\\\\\gitlab\\\\\\\\id_rsa_gitlab\':\\nWelcome to GitLab, hyman213!\\n```\\n\\n\\n\\n\\n\\n## \u53c2\u8003\u6587\u7ae0\\n\\n- [Windows\u4e0bGit\u591a\u8d26\u53f7\u914d\u7f6e\uff0c\u540c\u4e00\u7535\u8111\u591a\u4e2assh-key\u7684\u7ba1\u7406](<https://www.cnblogs.com/popfisher/p/5731232.html>)\\n- [\u540c\u4e00\u53f0\u7535\u8111\u914d\u7f6e\u591a\u4e2agit\u8d26\u53f7](<https://github.com/jawil/notes/issues/2>)"},{"id":"elk","metadata":{"permalink":"/blog/elk","source":"@site/blog\\\\2019-10-27-\u521d\u8bc6ELK\u65e5\u5fd7\u5206\u6790\u7cfb\u7edf.md","title":"\u521d\u8bc6ELK","description":"\u5728\u4e0a\u4e00\u5bb6\u516c\u53f8\uff0c\u670d\u52a1\u5668\u6bd4\u8f83\u591a\uff0c\u52a0\u4e0a\u65e5\u5fd7\u91cf\u53c8\u5927\uff0c\u5728\u5b9e\u9645\u8fc7\u7a0b\u4e2d\u6392\u67e5\u65e5\u5fd7\u548c\u5b9a\u4f4d\u95ee\u9898\u51e0\u4e4e\u82b1\u8d39\u4e86\u5927\u90e8\u5206\u65f6\u95f4\u3002\u65b0\u516c\u53f8\u4f7f\u7528\u5fae\u670d\u52a1\u67b6\u6784\uff0c\u5229\u7528ELK\u642d\u5efa\u65e5\u5fd7\u5206\u6790\u7cfb\u7edf\uff0c\u4e8e\u662f\u7f51\u4e0a\u641c\u96c6\u8d44\u6599\uff0c\u5f00\u59cb\u4e86\u586b\u5751\u4e4b\u65c5\u3002\u3002\u3002\u6700\u7ec8\u672c\u5730\u642d\u5efaFilebeat--\x3eLogStash--\x3eKafka--\x3eES--\x3eKibana\uff0c\u611f\u89c9ELK\u786e\u5b9e\u5f3a\u5927\uff0c\u8ddf\u4e4b\u524d\u4e00\u53f0\u53f0grep\u53caawk, \u5b9e\u5728\u8f7b\u677e\u592a\u591a","date":"2019-10-27T00:00:00.000Z","formattedDate":"2019\u5e7410\u670827\u65e5","tags":[{"label":"ELK","permalink":"/blog/tags/elk"},{"label":"\u65e5\u5fd7","permalink":"/blog/tags/\u65e5\u5fd7"}],"truncated":false,"authors":[],"frontMatter":{"slug":"elk","title":"\u521d\u8bc6ELK","tags":["ELK","\u65e5\u5fd7"]},"prevItem":{"title":"Windows\u4e0bGit\u591a\u8d26\u6237\u7ba1\u7406","permalink":"/blog/multi-git-manage"},"nextItem":{"title":"\u521d\u8bc6Zuul","permalink":"/blog/zuul-basic"}},"content":"\u5728\u4e0a\u4e00\u5bb6\u516c\u53f8\uff0c\u670d\u52a1\u5668\u6bd4\u8f83\u591a\uff0c\u52a0\u4e0a\u65e5\u5fd7\u91cf\u53c8\u5927\uff0c\u5728\u5b9e\u9645\u8fc7\u7a0b\u4e2d\u6392\u67e5\u65e5\u5fd7\u548c\u5b9a\u4f4d\u95ee\u9898\u51e0\u4e4e\u82b1\u8d39\u4e86\u5927\u90e8\u5206\u65f6\u95f4\u3002\u65b0\u516c\u53f8\u4f7f\u7528\u5fae\u670d\u52a1\u67b6\u6784\uff0c\u5229\u7528ELK\u642d\u5efa\u65e5\u5fd7\u5206\u6790\u7cfb\u7edf\uff0c\u4e8e\u662f\u7f51\u4e0a\u641c\u96c6\u8d44\u6599\uff0c\u5f00\u59cb\u4e86\u586b\u5751\u4e4b\u65c5\u3002\u3002\u3002\u6700\u7ec8\u672c\u5730\u642d\u5efaFilebeat--\x3eLogStash--\x3eKafka--\x3eES--\x3eKibana\uff0c\u611f\u89c9ELK\u786e\u5b9e\u5f3a\u5927\uff0c\u8ddf\u4e4b\u524d\u4e00\u53f0\u53f0grep\u53caawk, \u5b9e\u5728\u8f7b\u677e\u592a\u591a\\n\\n\u603b\u7684\u6765\u8bf4\u5c31\u662f\u670d\u52a1\u672c\u5730\u7684Filebeat\u76d1\u63a7\u672c\u5730\u7684\u65e5\u5fd7\u6587\u4ef6\uff0c\u7136\u540e\u5c06\u65e5\u5fd7\u5b9e\u65f6\u8f93\u51fa\u5230\u8f93\u51fa\u7aef(\u53ef\u80fd\u662fLogstash\uff0cES\uff0cKafka)\uff0c\u6700\u7ec8\u4fdd\u5b58\u5230ES\u4e2d\uff0cKibana\u8fde\u63a5ES\u8fdb\u884c\u65e5\u5fd7\u7684\u5206\u6790\u53ca\u67e5\u627e\\n\\n\\n[TOC]\\n\\n## ELK\u7b80\u4ecb\\n\\nELK = Elasticsearch, Logstash, Kibana \u662f\u4e00\u5957\u5b9e\u65f6\u6570\u636e\u6536\u96c6\uff0c\u5b58\u50a8\uff0c\u7d22\u5f15\uff0c\u68c0\u7d22\uff0c\u7edf\u8ba1\u5206\u6790\u53ca\u53ef\u89c6\u5316\u7684\u89e3\u51b3\u65b9\u6848\u3002\u65b0\u589e\u4e86\u4e00\u4e2aFileBeat\uff0c\u5b83\u662f\u4e00\u4e2a\u8f7b\u91cf\u7ea7\u7684\u65e5\u5fd7\u6536\u96c6\u5904\u7406\u5de5\u5177(Agent)\uff0cFilebeat\u5360\u7528\u8d44\u6e90\u5c11\uff0c\u9002\u5408\u4e8e\u5728\u5404\u4e2a\u670d\u52a1\u5668\u4e0a\u641c\u96c6\u65e5\u5fd7\u540e\u4f20\u8f93\u7ed9Logstash\uff0c\u5b98\u65b9\u4e5f\u63a8\u8350\u6b64\u5de5\u5177\u3002\\n\\n\\n\\n### \u4e3a\u4ec0\u4e48\u7528\u5230ELK\\n\\n\u4e00\u822c\u5927\u578b\u7cfb\u7edf\u662f\u4e00\u4e2a\u5206\u5e03\u5f0f\u90e8\u7f72\u7684\u67b6\u6784\uff0c\u4e0d\u540c\u7684\u670d\u52a1\u6a21\u5757\u90e8\u7f72\u5728\u4e0d\u540c\u7684\u670d\u52a1\u5668\u4e0a\uff0c\u95ee\u9898\u51fa\u73b0\u65f6\uff0c\u5927\u90e8\u5206\u60c5\u51b5\u9700\u8981\u6839\u636e\u95ee\u9898\u66b4\u9732\u7684\u5173\u952e\u4fe1\u606f\uff0c\u5b9a\u4f4d\u5230\u5177\u4f53\u7684\u670d\u52a1\u5668\u548c\u670d\u52a1\u6a21\u5757\uff0c\u6784\u5efa\u4e00\u5957\u96c6\u4e2d\u5f0f\u65e5\u5fd7\u7cfb\u7edf\uff0c\u53ef\u4ee5\u63d0\u9ad8\u5b9a\u4f4d\u95ee\u9898\u7684\u6548\u7387\u3002\\n\\n\u4e00\u4e2a\u5b8c\u6574\u7684\u96c6\u4e2d\u5f0f\u65e5\u5fd7\u7cfb\u7edf\uff0c\u9700\u8981\u5305\u542b\u4ee5\u4e0b\u51e0\u4e2a\u4e3b\u8981\u7279\u70b9\uff1a\\n\\n- \u6536\u96c6\uff0d\u80fd\u591f\u91c7\u96c6\u591a\u79cd\u6765\u6e90\u7684\u65e5\u5fd7\u6570\u636e\\n- \u4f20\u8f93\uff0d\u80fd\u591f\u7a33\u5b9a\u7684\u628a\u65e5\u5fd7\u6570\u636e\u4f20\u8f93\u5230\u4e2d\u592e\u7cfb\u7edf\\n- \u5b58\u50a8\uff0d\u5982\u4f55\u5b58\u50a8\u65e5\u5fd7\u6570\u636e\\n- \u5206\u6790\uff0d\u53ef\u4ee5\u652f\u6301 UI \u5206\u6790\\n- \u8b66\u544a\uff0d\u80fd\u591f\u63d0\u4f9b\u9519\u8bef\u62a5\u544a\uff0c\u76d1\u63a7\u673a\u5236\\n\\nELK\u63d0\u4f9b\u4e86\u4e00\u6574\u5957\u89e3\u51b3\u65b9\u6848\uff0c\u5e76\u4e14\u90fd\u662f\u5f00\u6e90\u8f6f\u4ef6\uff0c\u4e4b\u95f4\u4e92\u76f8\u914d\u5408\u4f7f\u7528\uff0c\u5b8c\u7f8e\u8854\u63a5\uff0c\u9ad8\u6548\u7684\u6ee1\u8db3\u4e86\u5f88\u591a\u573a\u5408\u7684\u5e94\u7528\u3002\u76ee\u524d\u4e3b\u6d41\u7684\u4e00\u79cd\u65e5\u5fd7\u7cfb\u7edf\u3002\\n\\n\\n\\n### ELK\\n\\n**Elasticsearch**\u662f\u4e2a\u5f00\u6e90\u5206\u5e03\u5f0f\u641c\u7d22\u5f15\u64ce\uff0c\u63d0\u4f9b\u641c\u96c6\u3001\u5206\u6790\u3001\u5b58\u50a8\u6570\u636e\u4e09\u5927\u529f\u80fd\u3002\u5b83\u7684\u7279\u70b9\u6709\uff1a\u5206\u5e03\u5f0f\uff0c\u96f6\u914d\u7f6e\uff0c\u81ea\u52a8\u53d1\u73b0\uff0c\u7d22\u5f15\u81ea\u52a8\u5206\u7247\uff0c\u7d22\u5f15\u526f\u672c\u673a\u5236\uff0crestful\u98ce\u683c\u63a5\u53e3\uff0c\u591a\u6570\u636e\u6e90\uff0c\u81ea\u52a8\u641c\u7d22\u8d1f\u8f7d\u7b49\u3002\\n\\n**Logstash** \u4e3b\u8981\u662f\u7528\u6765\u65e5\u5fd7\u7684\u641c\u96c6\u3001\u5206\u6790\u3001\u8fc7\u6ee4\u65e5\u5fd7\u7684\u5de5\u5177\uff0c\u652f\u6301\u5927\u91cf\u7684\u6570\u636e\u83b7\u53d6\u65b9\u5f0f\u3002\u4e00\u822c\u5de5\u4f5c\u65b9\u5f0f\u4e3ac/s\u67b6\u6784\uff0cclient\u7aef\u5b89\u88c5\u5728\u9700\u8981\u6536\u96c6\u65e5\u5fd7\u7684\u4e3b\u673a\u4e0a\uff0cserver\u7aef\u8d1f\u8d23\u5c06\u6536\u5230\u7684\u5404\u8282\u70b9\u65e5\u5fd7\u8fdb\u884c\u8fc7\u6ee4\u3001\u4fee\u6539\u7b49\u64cd\u4f5c\u5728\u4e00\u5e76\u53d1\u5f80elasticsearch\u4e0a\u53bb\u3002\\n\\n**Kibana** \u4e5f\u662f\u4e00\u4e2a\u5f00\u6e90\u548c\u514d\u8d39\u7684\u5de5\u5177\uff0cKibana\u53ef\u4ee5\u4e3a Logstash \u548c ElasticSearch \u63d0\u4f9b\u7684\u65e5\u5fd7\u5206\u6790\u53cb\u597d\u7684 Web \u754c\u9762\uff0c\u53ef\u4ee5\u5e2e\u52a9\u6c47\u603b\u3001\u5206\u6790\u548c\u641c\u7d22\u91cd\u8981\u6570\u636e\u65e5\u5fd7\u3002\\n\\nFilebeat\u96b6\u5c5e\u4e8eBeats\u3002\u76ee\u524dBeats\u5305\u542b\u56db\u79cd\u5de5\u5177\uff1a\\n\\n1. 1. Packetbeat\uff08\u641c\u96c6\u7f51\u7edc\u6d41\u91cf\u6570\u636e\uff09\\n   2. Topbeat\uff08\u641c\u96c6\u7cfb\u7edf\u3001\u8fdb\u7a0b\u548c\u6587\u4ef6\u7cfb\u7edf\u7ea7\u522b\u7684 CPU \u548c\u5185\u5b58\u4f7f\u7528\u60c5\u51b5\u7b49\u6570\u636e\uff09\\n   3. Filebeat\uff08\u641c\u96c6\u6587\u4ef6\u6570\u636e\uff09\\n   4. Winlogbeat\uff08\u641c\u96c6 Windows \u4e8b\u4ef6\u65e5\u5fd7\u6570\u636e\uff09\\n\\n### \u5b98\u65b9\u6587\u6863\\n\\nFilebeat\uff1a\\n\\n[https://www.elastic.co/cn/products/beats/filebeat](https://link.zhihu.com/?target=https%3A//www.elastic.co/cn/products/beats/filebeat)\\n[https://www.elastic.co/guide/en/beats/filebeat/5.6/index.html](https://link.zhihu.com/?target=https%3A//www.elastic.co/guide/en/beats/filebeat/5.6/index.html)\\n\\nLogstash\uff1a\\n[https://www.elastic.co/cn/products/logstash](https://link.zhihu.com/?target=https%3A//www.elastic.co/cn/products/logstash)\\n[https://www.elastic.co/guide/en/logstash/5.6/index.html](https://link.zhihu.com/?target=https%3A//www.elastic.co/guide/en/logstash/5.6/index.html)\\n\\nKibana:\\n\\n[https://www.elastic.co/cn/products/kibana](https://link.zhihu.com/?target=https%3A//www.elastic.co/cn/products/kibana)\\n\\n[https://www.elastic.co/guide/en/kibana/5.5/index.html](https://link.zhihu.com/?target=https%3A//www.elastic.co/guide/en/kibana/5.5/index.html)\\n\\nElasticsearch\uff1a\\n[https://www.elastic.co/cn/products/elasticsearch](https://link.zhihu.com/?target=https%3A//www.elastic.co/cn/products/elasticsearch)\\n[https://www.elastic.co/guide/en/elasticsearch/reference/5.6/index.html](https://link.zhihu.com/?target=https%3A//www.elastic.co/guide/en/elasticsearch/reference/5.6/index.html)\\n\\nelasticsearch\u4e2d\u6587\u793e\u533a\uff1a\\n[https://elasticsearch.cn/](https://link.zhihu.com/?target=https%3A//elasticsearch.cn/)\\n\\n\\n\\n## \u5b89\u88c5\u642d\u5efa(\u7b80\u6613\u7248)\\n\\n**\u4f7f\u7528\u540c\u4e00\u4e2a\u7248\u672c\u53f7!!!**\\n\\n### Elasticsearch\\n\\n[\u4e0b\u8f7d\u5730\u5740](<https://www.elastic.co/cn/downloads/elasticsearch>)\\n\\n- Download and unzip Elasticsearch\\n- Run bin/elasticsearch (or bin\\\\elasticsearch.bat on Windows)\\n- Run curl http://localhost:9200/ or Invoke-RestMethod http://localhost:9200 with PowerShell\\n\\nElasticsearch \u4e5f\u662f\u4f7f\u7528 Java \u7f16\u5199\u7684\uff0c\u5b83\u7684\u5185\u90e8\u4f7f\u7528 Lucene \u505a\u7d22\u5f15\u4e0e\u641c\u7d22\\n\\n**\u542f\u52a8\u811a\u672c**\\n\\n```shell\\n#!/bin/bash\\n\\nexport JAVA_HOME=/data/service/jdk1.8.0_192\\n/data/service/elasticsearch-7.4.0/bin/elasticsearch\\n```\\n\\n\\n\\n### Logstach\\n\\n[\u4e0b\u8f7d\u5730\u5740](<https://www.elastic.co/cn/downloads/logstash>)\\n\\n- Download and unzip Logstash\\n- Prepare a logstash.conf config file\\n- Run `bin/logstash -f logstash.conf`\\n\\n\\n\\n```shell\\n\u5728 /usr/local \u76ee\u5f55\u4e0b\u89e3\u538b\uff1a\\ntar -zxvf  logstash-7.4.0.tar.gz\\n\u8fdb\u5165\u89e3\u538b\u540e\u7684\u76ee\u5f55\uff1a\\ncd /usr/local/logstash-7.4.0/bin\\n\u65b0\u589e\u914d\u7f6e\u6587\u4ef6\uff1a\\nvim logstash.conf\\n\u589e\u52a0\uff1a\\ninput{\\n    file{\\n      path => [\\"/var/log/*.log\\"]\\n    }\\n}\\noutput{\\n   elasticsearch{\\n       hosts => [\\"127.0.0.1:9200\\"]\\n       index => \\"logstash__log\\"\\n  }\\n}\\n```\\n\\n\\n\\n### Filebeat\\n\\n\\n- Download and unzip Filebeat\\n- Edit the filebeat.yml configuration file\\n- Start the daemon by running `sudo ./filebeat -e -c filebeat.yml`\\n\\n**\u4fee\u6539filebeat.yml**\\n\\n- \u8f93\u51fa\u5230ES\\n\\n```yml\\nfilebeat.inputs:\\n- type: log\\n  enabled: true\\n  paths:\\n    - /data/log/path1/**/*.log\\n  fields:\\n    topic: log1-app\\n- type: log\\n  enabled: true\\n  paths:\\n    - /data/log/path-api-*/logstash.log\\n  fields:\\n    topic: microservice\\n    \\nfilebeat.config.modules:\\n  # Glob pattern for configuration loading\\n  path: ${path.config}/modules.d/*.yml\\n\\n  # Set to true to enable config reloading\\n  reload.enabled: true\\n\\n  # Period on which files under path should be checked for changes\\n  reload.period: 60s\\n  \\n  \\n#-------------------------- Elasticsearch output ------------------------------\\noutput.elasticsearch:\\n hosts: [\\"localhost:9200\\"]  \\n    \\n```\\n\\n\u6b64\u5904\u7b80\u5355\u7684\u5c06\u51fa\u53e3\u5b9a\u4e49\u4e3aES\uff0c\u5b9e\u9645\u4e0a\u53ef\u80fd\u662fLogstash\\n\\n- \u8f93\u51fa\u5230Logstash\\n\\n```yml\\n#----------------------------- Logstash output --------------------------------\\noutput.logstash:\\n  # The Logstash hosts\\n  hosts: [\\"localhost:5044\\"]\\n\\n  # Optional SSL. By default is off.\\n  # List of root certificates for HTTPS server verifications\\n  #ssl.certificate_authorities: [\\"/etc/pki/root/ca.pem\\"]\\n\\n  # Certificate for SSL client authentication\\n  #ssl.certificate: \\"/etc/pki/client/cert.pem\\"\\n\\n  # Client Certificate Key\\n  #ssl.key: \\"/etc/pki/client/cert.key\\"\\n```\\n\\n\\n\\n\u542f\u52a8\\n\\n```shell\\n./filebeat -e -c filebeat.yml -d \\"publish\\"\\n```\\n\\n\\n\\n### Kibana\\n\\n\u4ece6.0.0\u5f00\u59cb\uff0cKibana \u53ea\u652f\u630164\u4f4d\u64cd\u4f5c\u7cfb\u7edf\u3002\\n\\nLinux64\u4f4d\u5305\\n\\n```shell\\n# Linux\\nwget https://artifacts.elastic.co/downloads/kibana/kibana-6.0.0-linux-x86_64.tar.gz\\nsha1sum kibana-6.0.0-linux-x86_64.tar.gz \\ntar -xzf kibana-6.0.0-linux-x86_64.tar.gz\\ncd kibana/ \\n\\n# windows\\n\u4e0b\u8f7dzip\u5305\uff0c\u89e3\u538b\u7f29\\nhttps://artifacts.elastic.co/downloads/kibana/kibana-6.0.0-windows-x86_64.zip\\n\\n# docker\\ndocker pull docker.elastic.co/kibana/kibana:6.0.0\\n\\n# \u542f\u52a8Kibana\\n./bin/kibana\\n\\n# \u914d\u7f6e\u6587\u4ef6\u8def\u5f84\\n$KIBANA_HOME/config/kibana.yml\\n```\\n\\n**\u914d\u7f6eKibana**\\n\\nKibana \u9ed8\u8ba4\u914d\u7f6e `localhost:5601`, \u914d\u7f6e\u6587\u4ef6\u8def\u5f84: `$KIBANA_HOME/config/kibana.yml`\\n\\n```xml\\nserver.host: \\"x.x.x.x\\"\\nserver.port: 5601\\nelasticsearch.url: \\"http://x.x.x.x:9200\\"\\n```\\n\\n**\u8bbf\u95ee**\\n\\n`http://YOURDOMAIN.com:5601`\\n\\n`localhost:5601/status` \u6765\u8bbf\u95ee Kibana \u7684\u670d\u52a1\u5668\u72b6\u6001\u9875\uff0c\u72b6\u6001\u9875\u5c55\u793a\u4e86\u670d\u52a1\u5668\u8d44\u6e90\u4f7f\u7528\u60c5\u51b5\u548c\u5df2\u5b89\u88c5\u63d2\u4ef6\u5217\u8868\u3002\\n\\n**\u542f\u52a8\u811a\u672c**\\n\\n```shell\\n#!/bin/bash\\n/data/service/kibana-7.4.0/bin/kibana -c /data/service/kibana-7.4.0/config/kibana.yml\\n```\\n\\n\\n\\n**\u52a0\u8f7d\u793a\u4f8b\u6570\u636e**\\n\\n- \u4e0b\u8f7d\u3001\u89e3\u538b\u793a\u4f8b\u6587\u4ef6\\n- \u5efa\u7acb\u6570\u636e\u96c6\u6620\u5c04\\n\\nshakespeare(\u6700\u65b07.4\u7248\u672c\u9700\u8981\u53bb\u6389doc\u8282\u70b9)\\n\\n```shell\\nPUT /shakespeare\\n{\\n \\"mappings\\": {\\n  \\"doc\\": {\\n   \\"properties\\": {\\n    \\"speaker\\": {\\"type\\": \\"keyword\\"},\\n    \\"play_name\\": {\\"type\\": \\"keyword\\"},\\n    \\"line_id\\": {\\"type\\": \\"integer\\"},\\n    \\"speech_number\\": {\\"type\\": \\"integer\\"}\\n   }\\n  }\\n }\\n}\\n\\n\\nPUT /shakespeare\\n{\\n \\"mappings\\": {\\n   \\"properties\\": {\\n    \\"speaker\\": {\\"type\\": \\"keyword\\"},\\n    \\"play_name\\": {\\"type\\": \\"keyword\\"},\\n    \\"line_id\\": {\\"type\\": \\"integer\\"},\\n    \\"speech_number\\": {\\"type\\": \\"integer\\"}\\n   }\\n  }\\n}\\n```\\n\\nlog\\n\\n```shell\\nPUT /logstash-2015.05.18\\n{\\n  \\"mappings\\": {\\n    \\"log\\": {\\n      \\"properties\\": {\\n        \\"geo\\": {\\n          \\"properties\\": {\\n            \\"coordinates\\": {\\n              \\"type\\": \\"geo_point\\"\\n            }\\n          }\\n        }\\n      }\\n    }\\n  }\\n}\\n```\\n\\n- \u7528 Elasticsearch bulk API \u6765\u52a0\u8f7d\u6570\u636e\u96c6\\n\\n```shell\\ncurl -H \'Content-Type: application/x-ndjson\' -XPOST \'localhost:9200/bank/account/_bulk?pretty\' --data-binary @accounts.json\\ncurl -H \'Content-Type: application/x-ndjson\' -XPOST \'localhost:9200/shakespeare/doc/_bulk?pretty\' --data-binary @shakespeare_6.0.json\\ncurl -H \'Content-Type: application/x-ndjson\' -XPOST \'localhost:9200/_bulk?pretty\' --data-binary @logs.jsonl\\n```\\n\\n- \u9a8c\u8bc1\\n\\n```shell\\nGET /_cat/indices?v\\n```\\n\\n\\n\\n## \u539f\u7406\u89e3\u6790\\n\\n### FileBeat\\n\\n\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/10/20191024221832.png)\\n\\nFilebeat\u7531\u4e24\u4e2a\u4e3b\u8981\u7ec4\u4ef6\u7ec4\u6210\uff1aprospectors \u548c harvesters\u3002\u8fd9\u4e24\u4e2a\u7ec4\u4ef6\u534f\u540c\u5de5\u4f5c\u5c06\u6587\u4ef6\u53d8\u52a8\u53d1\u9001\u5230\u6307\u5b9a\u7684\u8f93\u51fa\u4e2d\u3002\\n\\n**Harvester\uff08\u6536\u5272\u673a\uff09\uff1a**\u8d1f\u8d23\u8bfb\u53d6\u5355\u4e2a\u6587\u4ef6\u5185\u5bb9\u3002\u6bcf\u4e2a\u6587\u4ef6\u4f1a\u542f\u52a8\u4e00\u4e2aHarvester\uff0c\u6bcf\u4e2aHarvester\u4f1a\u9010\u884c\u8bfb\u53d6\u5404\u4e2a\u6587\u4ef6\uff0c\u5e76\u5c06\u6587\u4ef6\u5185\u5bb9\u53d1\u9001\u5230\u5236\u5b9a\u8f93\u51fa\u4e2d\u3002Harvester\u8d1f\u8d23\u6253\u5f00\u548c\u5173\u95ed\u6587\u4ef6\uff0c\u610f\u5473\u5728Harvester\u8fd0\u884c\u7684\u65f6\u5019\uff0c\u6587\u4ef6\u63cf\u8ff0\u7b26\u5904\u4e8e\u6253\u5f00\u72b6\u6001\uff0c\u5982\u679c\u6587\u4ef6\u5728\u6536\u96c6\u4e2d\u88ab\u91cd\u547d\u540d\u6216\u8005\u88ab\u5220\u9664\uff0cFilebeat\u4f1a\u7ee7\u7eed\u8bfb\u53d6\u6b64\u6587\u4ef6\u3002\u6240\u4ee5\u5728Harvester\u5173\u95ed\u4e4b\u524d\uff0c\u78c1\u76d8\u4e0d\u4f1a\u88ab\u91ca\u653e\u3002\u9ed8\u8ba4\u60c5\u51b5filebeat\u4f1a\u4fdd\u6301\u6587\u4ef6\u6253\u5f00\u7684\u72b6\u6001\uff0c\u76f4\u5230\u8fbe\u5230`close_inactive`\uff08\u5982\u679c\u6b64\u9009\u9879\u5f00\u542f\uff0cfilebeat\u4f1a\u5728\u6307\u5b9a\u65f6\u95f4\u5185\u5c06\u4e0d\u518d\u66f4\u65b0\u7684\u6587\u4ef6\u53e5\u67c4\u5173\u95ed\uff0c\u65f6\u95f4\u4eceharvester\u8bfb\u53d6\u6700\u540e\u4e00\u884c\u7684\u65f6\u95f4\u5f00\u59cb\u8ba1\u65f6\u3002\u82e5\u6587\u4ef6\u53e5\u67c4\u88ab\u5173\u95ed\u540e\uff0c\u6587\u4ef6\u53d1\u751f\u53d8\u5316\uff0c\u5219\u4f1a\u542f\u52a8\u4e00\u4e2a\u65b0\u7684harvester\u3002\u5173\u95ed\u6587\u4ef6\u53e5\u67c4\u7684\u65f6\u95f4\u4e0d\u53d6\u51b3\u4e8e\u6587\u4ef6\u7684\u4fee\u6539\u65f6\u95f4\uff0c\u82e5\u6b64\u53c2\u6570\u914d\u7f6e\u4e0d\u5f53\uff0c\u5219\u53ef\u80fd\u53d1\u751f\u65e5\u5fd7\u4e0d\u5b9e\u65f6\u7684\u60c5\u51b5\uff0c\u7531scan_frequency\u53c2\u6570\u51b3\u5b9a\uff0c\u9ed8\u8ba410s\u3002Harvester\u4f7f\u7528\u5185\u90e8\u65f6\u95f4\u6233\u6765\u8bb0\u5f55\u6587\u4ef6\u6700\u540e\u88ab\u6536\u96c6\u7684\u65f6\u95f4\u3002\u4f8b\u5982\uff1a\u8bbe\u7f6e5m\uff0c\u5219\u5728Harvester\u8bfb\u53d6\u6587\u4ef6\u7684\u6700\u540e\u4e00\u884c\u4e4b\u540e\uff0c\u5f00\u59cb\u5012\u8ba1\u65f65\u5206\u949f\uff0c\u82e55\u5206\u949f\u5185\u6587\u4ef6\u65e0\u53d8\u5316\uff0c\u5219\u5173\u95ed\u6587\u4ef6\u53e5\u67c4\u3002\u9ed8\u8ba45m\uff09\\n\\n**Prospector\uff08\u52d8\u6d4b\u8005\uff09\uff1a**\u8d1f\u8d23\u7ba1\u7406Harvester\u5e76\u627e\u5230\u6240\u6709\u8bfb\u53d6\u6e90\\n\\n```yml\\nfilebeat.inputs:\\n- type: log\\n  enabled: true\\n  paths:\\n    - - /apps/logs/*/info.log\\n```\\n\\nProspector\u4f1a\u627e\u5230/apps/logs/*\u76ee\u5f55\u4e0b\u7684\u6240\u6709info.log\u6587\u4ef6\uff0c\u5e76\u4e3a\u6bcf\u4e2a\u6587\u4ef6\u542f\u52a8\u4e00\u4e2aHarvester\u3002Prospector\u4f1a\u68c0\u67e5\u6bcf\u4e2a\u6587\u4ef6\uff0c\u770bHarvester\u662f\u5426\u5df2\u7ecf\u542f\u52a8\uff0c\u662f\u5426\u9700\u8981\u542f\u52a8\uff0c\u6216\u8005\u6587\u4ef6\u662f\u5426\u53ef\u4ee5\u5ffd\u7565\u3002\u82e5Harvester\u5173\u95ed\uff0c\u53ea\u6709\u5728\u6587\u4ef6\u5927\u5c0f\u53d1\u751f\u53d8\u5316\u7684\u65f6\u5019Prospector\u624d\u4f1a\u6267\u884c\u68c0\u67e5\u3002\u53ea\u80fd\u68c0\u6d4b\u672c\u5730\u7684\u6587\u4ef6\u3002\\n\\n**Filebeat\u5982\u4f55\u8bb0\u5f55\u6587\u4ef6\u72b6\u6001\uff1a**\\n\\n\u5c06\u6587\u4ef6\u72b6\u6001\u8bb0\u5f55\u5728\u6587\u4ef6\u4e2d\uff08\u9ed8\u8ba4\u5728/var/lib/filebeat/registry\uff09\u3002\u6b64\u72b6\u6001\u53ef\u4ee5\u8bb0\u4f4fHarvester\u6536\u96c6\u6587\u4ef6\u7684\u504f\u79fb\u91cf\u3002\u82e5\u8fde\u63a5\u4e0d\u4e0a\u8f93\u51fa\u8bbe\u5907\uff0c\u5982ES\u7b49\uff0cfilebeat\u4f1a\u8bb0\u5f55\u53d1\u9001\u524d\u7684\u6700\u540e\u4e00\u884c\uff0c\u5e76\u518d\u53ef\u4ee5\u8fde\u63a5\u7684\u65f6\u5019\u7ee7\u7eed\u53d1\u9001\u3002Filebeat\u5728\u8fd0\u884c\u7684\u65f6\u5019\uff0cProspector\u72b6\u6001\u4f1a\u88ab\u8bb0\u5f55\u5728\u5185\u5b58\u4e2d\u3002Filebeat\u91cd\u542f\u7684\u65f6\u5019\uff0c\u5229\u7528registry\u8bb0\u5f55\u7684\u72b6\u6001\u6765\u8fdb\u884c\u91cd\u5efa\uff0c\u7528\u6765\u8fd8\u539f\u5230\u91cd\u542f\u4e4b\u524d\u7684\u72b6\u6001\u3002\u6bcf\u4e2aProspector\u4f1a\u4e3a\u6bcf\u4e2a\u627e\u5230\u7684\u6587\u4ef6\u8bb0\u5f55\u4e00\u4e2a\u72b6\u6001\uff0c\u5bf9\u4e8e\u6bcf\u4e2a\u6587\u4ef6\uff0cFilebeat\u5b58\u50a8\u552f\u4e00\u6807\u8bc6\u7b26\u4ee5\u68c0\u6d4b\u6587\u4ef6\u662f\u5426\u5148\u524d\u88ab\u6536\u96c6\u3002\\n\\n**Filebeat\u5982\u4f55\u4fdd\u8bc1\u4e8b\u4ef6\u81f3\u5c11\u88ab\u8f93\u51fa\u4e00\u6b21\uff1a**\\n\\nFilebeat\u4e4b\u6240\u4ee5\u80fd\u4fdd\u8bc1\u4e8b\u4ef6\u81f3\u5c11\u88ab\u4f20\u9012\u5230\u914d\u7f6e\u7684\u8f93\u51fa\u4e00\u6b21\uff0c\u6ca1\u6709\u6570\u636e\u4e22\u5931\uff0c\u662f\u56e0\u4e3afilebeat\u5c06\u6bcf\u4e2a\u4e8b\u4ef6\u7684\u4f20\u9012\u72b6\u6001\u4fdd\u5b58\u5728\u6587\u4ef6\u4e2d\u3002\u5728\u672a\u5f97\u5230\u8f93\u51fa\u65b9\u786e\u8ba4\u65f6\uff0cfilebeat\u4f1a\u5c1d\u8bd5\u4e00\u76f4\u53d1\u9001\uff0c\u76f4\u5230\u5f97\u5230\u56de\u5e94\u3002\u82e5filebeat\u5728\u4f20\u8f93\u8fc7\u7a0b\u4e2d\u88ab\u5173\u95ed\uff0c\u5219\u4e0d\u4f1a\u518d\u5173\u95ed\u4e4b\u524d\u786e\u8ba4\u6240\u6709\u65f6\u4e8b\u4ef6\u3002\u4efb\u4f55\u5728filebeat\u5173\u95ed\u4e4b\u524d\u4e3a\u786e\u8ba4\u7684\u65f6\u95f4\uff0c\u90fd\u4f1a\u5728filebeat\u91cd\u542f\u4e4b\u540e\u91cd\u65b0\u53d1\u9001\u3002\u8fd9\u53ef\u786e\u4fdd\u81f3\u5c11\u53d1\u9001\u4e00\u6b21\uff0c\u4f46\u6709\u53ef\u80fd\u4f1a\u91cd\u590d\u3002\u53ef\u901a\u8fc7\u8bbe\u7f6e`shutdown_timeout` \u53c2\u6570\u6765\u8bbe\u7f6e\u5173\u95ed\u4e4b\u524d\u7684\u7b49\u5f85\u4e8b\u4ef6\u56de\u5e94\u7684\u65f6\u95f4\uff08\u9ed8\u8ba4\u7981\u7528\uff09\u3002\\n\\n### Logstash\\n\\nLogstash\u4e8b\u4ef6\u5904\u7406\u6709\u4e09\u4e2a\u9636\u6bb5\uff1ainputs \u2192 filters \u2192 outputs\u3002\u662f\u4e00\u4e2a\u63a5\u6536\uff0c\u5904\u7406\uff0c\u8f6c\u53d1\u65e5\u5fd7\u7684\u5de5\u5177\u3002\u652f\u6301\u7cfb\u7edf\u65e5\u5fd7\uff0cwebserver\u65e5\u5fd7\uff0c\u9519\u8bef\u65e5\u5fd7\uff0c\u5e94\u7528\u65e5\u5fd7\uff0c\u603b\u4e4b\u5305\u62ec\u6240\u6709\u53ef\u4ee5\u629b\u51fa\u6765\u7684\u65e5\u5fd7\u7c7b\u578b\u3002\\n\\n\u4f5c\u8005\uff1a\u86d9\u8bfe\u7f51\\n\\n\u94fe\u63a5\uff1a\\n\\n\u6765\u6e90\uff1a\u77e5\u4e4e\\n\\n\u8457\u4f5c\u6743\u5f52\u4f5c\u8005\u6240\u6709\u3002\u5546\u4e1a\u8f6c\u8f7d\u8bf7\u8054\u7cfb\u4f5c\u8005\u83b7\u5f97\u6388\u6743\uff0c\u975e\u5546\u4e1a\u8f6c\u8f7d\u8bf7\u6ce8\u660e\u51fa\u5904\u3002\\n\\n**Input\uff1a\u8f93\u5165\u6570\u636e\u5230logstash\u3002**\\n\\n\u4e00\u4e9b\u5e38\u7528\u7684\u8f93\u5165\u4e3a\uff1a\\n\\nfile\uff1a\u4ece\u6587\u4ef6\u7cfb\u7edf\u7684\u6587\u4ef6\u4e2d\u8bfb\u53d6\uff0c\u7c7b\u4f3c\u4e8etail -f\u547d\u4ee4\\n\\nsyslog\uff1a\u5728514\u7aef\u53e3\u4e0a\u76d1\u542c\u7cfb\u7edf\u65e5\u5fd7\u6d88\u606f\uff0c\u5e76\u6839\u636eRFC3164\u6807\u51c6\u8fdb\u884c\u89e3\u6790\\n\\nredis\uff1a\u4eceredis service\u4e2d\u8bfb\u53d6\\n\\nbeats\uff1a\u4ecefilebeat\u4e2d\u8bfb\u53d6\\n\\n**Filters\uff1a\u6570\u636e\u4e2d\u95f4\u5904\u7406\uff0c\u5bf9\u6570\u636e\u8fdb\u884c\u64cd\u4f5c\u3002**\\n\\n\u4e00\u4e9b\u5e38\u7528\u7684\u8fc7\u6ee4\u5668\u4e3a\uff1a\\n\\ngrok\uff1a\u89e3\u6790\u4efb\u610f\u6587\u672c\u6570\u636e\uff0cGrok \u662f Logstash \u6700\u91cd\u8981\u7684\u63d2\u4ef6\u3002\u5b83\u7684\u4e3b\u8981\u4f5c\u7528\u5c31\u662f\u5c06\u6587\u672c\u683c\u5f0f\u7684\u5b57\u7b26\u4e32\uff0c\u8f6c\u6362\u6210\u4e3a\u5177\u4f53\u7684\u7ed3\u6784\u5316\u7684\u6570\u636e\uff0c\u914d\u5408\u6b63\u5219\u8868\u8fbe\u5f0f\u4f7f\u7528\u3002\u5185\u7f6e120\u591a\u4e2a\u89e3\u6790\u8bed\u6cd5\u3002\\n\\n\u5b98\u65b9\u63d0\u4f9b\u7684grok\u8868\u8fbe\u5f0f\uff1a[https://github.com/logstash-plugins/logstash-patterns-core/tree/master/patterns](https://link.zhihu.com/?target=https%3A//github.com/logstash-plugins/logstash-patterns-core/tree/master/patterns)\\ngrok\u5728\u7ebf\u8c03\u8bd5\uff1a[https://grokdebug.herokuapp.com/](https://link.zhihu.com/?target=https%3A//grokdebug.herokuapp.com/)\\n\\nmutate\uff1a\u5bf9\u5b57\u6bb5\u8fdb\u884c\u8f6c\u6362\u3002\u4f8b\u5982\u5bf9\u5b57\u6bb5\u8fdb\u884c\u5220\u9664\u3001\u66ff\u6362\u3001\u4fee\u6539\u3001\u91cd\u547d\u540d\u7b49\u3002\\n\\ndrop\uff1a\u4e22\u5f03\u4e00\u90e8\u5206events\u4e0d\u8fdb\u884c\u5904\u7406\u3002\\n\\nclone\uff1a\u62f7\u8d1d event\uff0c\u8fd9\u4e2a\u8fc7\u7a0b\u4e2d\u4e5f\u53ef\u4ee5\u6dfb\u52a0\u6216\u79fb\u9664\u5b57\u6bb5\u3002\\n\\ngeoip\uff1a\u6dfb\u52a0\u5730\u7406\u4fe1\u606f(\u4e3a\u524d\u53f0kibana\u56fe\u5f62\u5316\u5c55\u793a\u4f7f\u7528)\\n\\n**Outputs\uff1aoutputs\u662flogstash\u5904\u7406\u7ba1\u9053\u7684\u6700\u672b\u7aef\u7ec4\u4ef6\u3002**\u4e00\u4e2aevent\u53ef\u4ee5\u5728\u5904\u7406\u8fc7\u7a0b\u4e2d\u7ecf\u8fc7\u591a\u91cd\u8f93\u51fa\uff0c\u4f46\u662f\u4e00\u65e6\u6240\u6709\u7684outputs\u90fd\u6267\u884c\u7ed3\u675f\uff0c\u8fd9\u4e2aevent\u4e5f\u5c31\u5b8c\u6210\u751f\u547d\u5468\u671f\u3002\\n\\n\u4e00\u4e9b\u5e38\u89c1\u7684outputs\u4e3a\uff1a\\n\\nelasticsearch\uff1a\u53ef\u4ee5\u9ad8\u6548\u7684\u4fdd\u5b58\u6570\u636e\uff0c\u5e76\u4e14\u80fd\u591f\u65b9\u4fbf\u548c\u7b80\u5355\u7684\u8fdb\u884c\u67e5\u8be2\u3002\\n\\nfile\uff1a\u5c06event\u6570\u636e\u4fdd\u5b58\u5230\u6587\u4ef6\u4e2d\u3002\\n\\ngraphite\uff1a\u5c06event\u6570\u636e\u53d1\u9001\u5230\u56fe\u5f62\u5316\u7ec4\u4ef6\u4e2d\uff0c\u4e00\u4e2a\u5f88\u6d41\u884c\u7684\u5f00\u6e90\u5b58\u50a8\u56fe\u5f62\u5316\u5c55\u793a\u7684\u7ec4\u4ef6\u3002\\n\\n**Codecs\uff1acodecs \u662f\u57fa\u4e8e\u6570\u636e\u6d41\u7684\u8fc7\u6ee4\u5668\uff0c\u5b83\u53ef\u4ee5\u4f5c\u4e3ainput\uff0coutput\u7684\u4e00\u90e8\u5206\u914d\u7f6e**\u3002Codecs\u53ef\u4ee5\u5e2e\u52a9\u4f60\u8f7b\u677e\u7684\u5206\u5272\u53d1\u9001\u8fc7\u6765\u5df2\u7ecf\u88ab\u5e8f\u5217\u5316\u7684\u6570\u636e\u3002\\n\\n\\n\\n### Elasticsearch\\n\\n\\n\\n### Kibana\\n\\nKibana \u662f\u4e00\u6b3e\u5f00\u6e90\u7684\u6570\u636e\u5206\u6790\u548c\u53ef\u89c6\u5316\u5e73\u53f0\uff0c\u53ef\u4ee5\u4f7f\u7528 Kibana \u5bf9 Elasticsearch \u7d22\u5f15\u4e2d\u7684\u6570\u636e\u8fdb\u884c\u641c\u7d22\u3001\u67e5\u770b\u3001\u4ea4\u4e92\u64cd\u4f5c\u3002\\n\\n\\n\\n## ELK\u67b6\u6784\\n\\n**\u67b6\u6784\u4e00**\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/10/20191024221500.png)\\n\\n\\n\\n\u8fd9\u662f\u6700\u7b80\u5355\u7684\u4e00\u79cdELK\u67b6\u6784\u65b9\u5f0f\u3002\u4f18\u70b9\u662f\u642d\u5efa\u7b80\u5355\uff0c\u6613\u4e8e\u4e0a\u624b\u3002\u7f3a\u70b9\u662fLogstash\u8017\u8d44\u6e90\u8f83\u5927\uff0c\u8fd0\u884c\u5360\u7528CPU\u548c\u5185\u5b58\u9ad8\u3002\u53e6\u5916\u6ca1\u6709\u6d88\u606f\u961f\u5217\u7f13\u5b58\uff0c\u5b58\u5728\u6570\u636e\u4e22\u5931\u9690\u60a3\u3002\\n\\n\u6b64\u67b6\u6784\u7531Logstash\u5206\u5e03\u4e8e\u5404\u4e2a\u8282\u70b9\u4e0a\u641c\u96c6\u76f8\u5173\u65e5\u5fd7\u3001\u6570\u636e\uff0c\u5e76\u7ecf\u8fc7\u5206\u6790\u3001\u8fc7\u6ee4\u540e\u53d1\u9001\u7ed9\u8fdc\u7aef\u670d\u52a1\u5668\u4e0a\u7684Elasticsearch\u8fdb\u884c\u5b58\u50a8\u3002Elasticsearch\u5c06\u6570\u636e\u4ee5\u5206\u7247\u7684\u5f62\u5f0f\u538b\u7f29\u5b58\u50a8\u5e76\u63d0\u4f9b\u591a\u79cdAPI\u4f9b\u7528\u6237\u67e5\u8be2\uff0c\u64cd\u4f5c\u3002\u7528\u6237\u4ea6\u53ef\u4ee5\u66f4\u76f4\u89c2\u7684\u901a\u8fc7\u914d\u7f6eKibana Web\u65b9\u4fbf\u7684\u5bf9\u65e5\u5fd7\u67e5\u8be2\uff0c\u5e76\u6839\u636e\u6570\u636e\u751f\u6210\u62a5\u8868\u3002\\n\\n**\u67b6\u6784\u4e8c**\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/10/20191024221635.png)\\n\\n\u6b64\u79cd\u67b6\u6784\u5f15\u5165\u4e86\u6d88\u606f\u961f\u5217\u673a\u5236\uff0c\u4f4d\u4e8e\u5404\u4e2a\u8282\u70b9\u4e0a\u7684Logstash Agent\uff08FileBeat\uff09\uff08\u5148\u5c06\u6570\u636e/\u65e5\u5fd7\u4f20\u9012\u7ed9Kafka\uff08\u6216\u8005Redis\uff09\uff0c\u5e76\u5c06\u961f\u5217\u4e2d\u6d88\u606f\u6216\u6570\u636e\u95f4\u63a5\u4f20\u9012\u7ed9Logstash\uff0cLogstash\u8fc7\u6ee4\u3001\u5206\u6790\u540e\u5c06\u6570\u636e\u4f20\u9012\u7ed9Elasticsearch\u5b58\u50a8\u3002\u6700\u540e\u7531Kibana\u5c06\u65e5\u5fd7\u548c\u6570\u636e\u5448\u73b0\u7ed9\u7528\u6237\u3002\u56e0\u4e3a\u5f15\u5165\u4e86Kafka\uff08\u6216\u8005Redis\uff09,\u6240\u4ee5\u5373\u4f7f\u8fdc\u7aefLogstash server\u56e0\u6545\u969c\u505c\u6b62\u8fd0\u884c\uff0c\u6570\u636e\u5c06\u4f1a\u5148\u88ab\u5b58\u50a8\u4e0b\u6765\uff0c\u4ece\u800c\u907f\u514d\u6570\u636e\u4e22\u5931\u3002\\n\\n\\n\\n## SpringBoot\u9879\u76ee\u96c6\u6210\\n\\n\u5f15\u5165\u4f9d\u8d56\\n\\n```xml\\n<dependency>\\n    <groupId>org.springframework.cloud</groupId>\\n    <artifactId>spring-cloud-starter-netflix-eureka-client</artifactId>\\n</dependency>\\n\\n<dependency>\\n    <groupId>com.ctrip.framework.apollo</groupId>\\n    <artifactId>apollo-client</artifactId>\\n</dependency>\\n<dependency>\\n    <groupId>org.springframework.boot</groupId>\\n    <artifactId>spring-boot-starter-actuator</artifactId>\\n</dependency>\\n\\n<dependency>\\n    <groupId>org.springframework.boot</groupId>\\n    <artifactId>spring-boot-starter-web</artifactId>\\n</dependency>\\n\\n<dependency>\\n    <groupId>org.springframework.cloud</groupId>\\n    <artifactId>spring-cloud-starter-sleuth</artifactId>\\n</dependency>\\n\\n<dependency>\\n    <groupId>net.logstash.logback</groupId>\\n    <artifactId>logstash-logback-encoder</artifactId>\\n</dependency>\\n\\n<dependency>\\n    <groupId>ch.qos.logback</groupId>\\n    <artifactId>logback-core</artifactId>\\n    <version>${logback.version}</version>\\n</dependency>\\n\\n<dependency>\\n    <groupId>ch.qos.logback</groupId>\\n    <artifactId>logback-classic</artifactId>\\n    <version>${logback.version}</version>\\n</dependency>\\n\\n<dependency>\\n    <groupId>org.slf4j</groupId>\\n    <artifactId>slf4j-api</artifactId>\\n    <version>${slf4j.version}</version>\\n</dependency>\\n\\n```\\n\\n\u542f\u52a8\u7c7b\\n\\n```java\\n@SpringBootApplication\\n@EnableDiscoveryClient\\n@EnableApolloConfig\\npublic class Application {\\n\\n    public static void main(String[] args) {\\n        SpringApplication.run(Application.class, args);\\n    }\\n\\n}\\n```\\n\\nlogback\\n\\n```xml\\n\\n  <property scope=\\"context\\" name=\\"logPath4Context\\" value=\\"${loggerRoot}/${loggerAppName}\\"/>\\n  <property scope=\\"context\\" name=\\"logPattern4Context\\" value=\\"[%d{yyyy-MM-dd HH:mm:ss.SSS}] - %level - %logger{10} - ${loggerAppName} - %class[%line] - %X{X-B3-TraceId} - %X{X-B3-SpanId} - %thread - %msg%n\\"/>\\n  <property scope=\\"context\\" name=\\"loggerLevel4Context\\" value=\\"${logLevel}}\\"/>\\n\\n\\n  <appender name=\\"HELLO-APPENDER\\" class=\\"ch.qos.logback.core.rolling.RollingFileAppender\\">\\n    <file>${logPath4Context}/application.log</file>\\n    <rollingPolicy class=\\"ch.qos.logback.core.rolling.TimeBasedRollingPolicy\\">\\n      <fileNamePattern>${logPath4Context}/archive/hello.log.%d{yyyyMMdd}.gz</fileNamePattern>\\n      <maxHistory>7</maxHistory>\\n    </rollingPolicy>\\n    <encoder>\\n      <pattern>${logPattern4Context}</pattern>\\n      <charset>UTF-8</charset>\\n    </encoder>\\n  </appender>\\n\\n    \x3c!--  logstash  --\x3e\\n    <appender name=\\"LOGSTASH-APPENDER\\" class=\\"ch.qos.logback.core.rolling.RollingFileAppender\\">\\n        <file>${logPath4Context}/logstash.log</file>\\n        <rollingPolicy class=\\"ch.qos.logback.core.rolling.TimeBasedRollingPolicy\\">\\n            <fileNamePattern>${logPath4Context}/archive/logstash.log.%d{yyyyMMddHH}.gz</fileNamePattern>\\n            <maxHistory>72</maxHistory>\\n        </rollingPolicy>\\n        <encoder class=\\"net.logstash.logback.encoder.LogstashEncoder\\">\\n            <includeContext>false</includeContext>\\n            <customFields>{\\"app_name\\":\\"${loggerAppName}\\"}</customFields>\\n        </encoder>\\n    </appender>\\n\\n\\n  <logger name=\\"HELLO-LOGGER\\" additivity=\\"false\\">\\n    <level value=\\"${loggerLevel4Context}\\"/>\\n    <appender-ref ref=\\"HELLO-APPENDER\\" />\\n    <appender-ref ref=\\"ERROR-APPENDER\\" />\\n    <appender-ref ref=\\"LOGSTASH-APPENDER\\"/>\\n  </logger>\\n\\n\\n```\\n\\n\\n\\n\\n\\n## \u53c2\u8003\u6587\u7ae0\\n\\n- [Kibana \u7528\u6237\u624b\u518c(\u4e2d\u6587)](<https://www.elastic.co/guide/cn/kibana/current/index.html>)\\n- [Elasticsearch\u6743\u5a01\u6307\u5357](<https://www.elastic.co/guide/cn/elasticsearch/guide/current/intro.html>)\\n- [ELK\u642d\u5efa\u5168\u8fc7\u7a0b](<https://blog.csdn.net/tanqian351/article/details/83827583>)\\n- [ES\u7cfb\u5217\u5341\u516b\u3001FileBeat\u53d1\u9001\u65e5\u5fd7\u5230logstash\u3001ES\u3001\u591a\u4e2aoutput\u8fc7\u6ee4\u914d\u7f6e](https://www.cnblogs.com/wangzhuxing/p/9678578.html)\\n- [ELK\u53ef\u4ee5\u5e72\u4ec0\u4e48\u5462\uff1f](https://www.zhihu.com/question/338932215/answer/777380560)\\n- [ELK7.4+filebeat+Redis\u5206\u6790nginx\u670d\u52a1\u8bbf\u95ee\u65e5\u5fd7](<https://blog.csdn.net/weixin_44766368/article/details/102550216>)"},{"id":"zuul-basic","metadata":{"permalink":"/blog/zuul-basic","source":"@site/blog\\\\2019-10-27-\u521d\u8bc6\u7f51\u5173Zuul.md","title":"\u521d\u8bc6Zuul","description":"\u4e00\u76f4\u542c\u8bf4\u5fae\u670d\u52a1\uff0c\u53ef\u82e6\u4e8e\u4e00\u76f4\u6ca1\u6709\u673a\u4f1a\u5c1d\u8bd5\u3002\u516c\u53f8\u9879\u76ee\u642d\u5efa\u57fa\u4e8eSpringCLoud\uff0c\u6b63\u597d\u53ef\u4ee5\u6df1\u5165\u4e86\u89e3\u4e0b\u5fae\u670d\u52a1\u7684\u5965\u79d8\u3002 \u90a3\u5c31\u4ece\u7f51\u5173-Zuul\u5f00\u59cb\u5427\uff01","date":"2019-10-27T00:00:00.000Z","formattedDate":"2019\u5e7410\u670827\u65e5","tags":[{"label":"Zuul","permalink":"/blog/tags/zuul"}],"truncated":false,"authors":[],"frontMatter":{"slug":"zuul-basic","title":"\u521d\u8bc6Zuul","tags":["Zuul"]},"prevItem":{"title":"\u521d\u8bc6ELK","permalink":"/blog/elk"},"nextItem":{"title":"CentOS\u4e0b\u642d\u5efaFTP","permalink":"/blog/ftp-on-centos"}},"content":"\u4e00\u76f4\u542c\u8bf4\u5fae\u670d\u52a1\uff0c\u53ef\u82e6\u4e8e\u4e00\u76f4\u6ca1\u6709\u673a\u4f1a\u5c1d\u8bd5\u3002\u516c\u53f8\u9879\u76ee\u642d\u5efa\u57fa\u4e8eSpringCLoud\uff0c\u6b63\u597d\u53ef\u4ee5\u6df1\u5165\u4e86\u89e3\u4e0b\u5fae\u670d\u52a1\u7684\u5965\u79d8\u3002 \u90a3\u5c31\u4ece\u7f51\u5173-Zuul\u5f00\u59cb\u5427\uff01\\n\u6b64\u7247\u4e3a\u81ea\u5df1\u5b66\u4e60\u8fc7\u7a0b\u4e2d\u8ba4\u4e3a\u6bd4\u8f83\u91cd\u8981\u7684\u77e5\u8bc6\u70b9\uff0c\u5927\u90e8\u5206\u57fa\u4e8e\u7f51\u4e0a\u5404\u5927\u795e\u7684\u6587\u7ae0\uff0c\u5728\u6b64\u505a\u4e00\u4e0b\u6574\u7406\u3002\\n\\n\x3c!--more--\x3e\\n\\n## \u4f7f\u7528\\n\\n### \u6dfb\u52a0\u4f9d\u8d56\\n\\n```xml\\n<dependency>\\n    <groupId>org.springframework.cloud</groupId>\\n    <artifactId>spring-cloud-starter-netflix-eureka-client</artifactId>\\n</dependency>\\n\\n<dependency>\\n    <groupId>org.springframework.cloud</groupId>\\n    <artifactId>spring-cloud-starter-netflix-zuul</artifactId>\\n</dependency>\\n```\\n\\n### \u542f\u7528\u529f\u80fd\\n\\n\u6ce8\u91ca`@EnableZuulProxy`\\n\\n```java\\n@SpringBootApplication\\n@EnableDiscoveryClient\\n@EnableZuulProxy\\npublic class Application {\\n\\n    public static void main(String[] args) {\\n        SpringApplication.run(Application.class, args);\\n    }\\n\\n}\\n```\\n\\n### \u914d\u7f6e\u8def\u7531\u89c4\u5219\\n\\n**\u63a8\u8350**\\n\\n`zuul.routes.<route>.path` \u914d\u7f6e\u5339\u914d\u89c4\u5219\uff0c`zuul.routes.<route>.service-id` \u914d\u7f6e\u670d\u52a1\u540d\u79f0\uff0c\u5176\u4e2d `<route>` \u4e3a\u8def\u7531\u540d\u79f0\uff0c\u53ef\u4ee5\u4efb\u610f\u6307\u5b9a\\n\\n```xml\\n## \u9762\u5411\u670d\u52a1\u7684\u8def\u7531\\nzuul.routes.hello-service.path=/hello-service/**\\nzuul.routes.hello-service.service-id=hello-service\\n\\n## \u9762\u5411\u670d\u52a1\u8def\u7531\u7684\u7b80\u6613\u914d\u7f6e\\n## zuul.routes.<serviceId>=<path>\\nzuul.routes.hello-service=/hello-service/**\\n```\\n\\n**\u4f20\u7edf\u591a\u670d\u52a1\u5b9e\u4f8b\u914d\u7f6e**\\n\\n\u9700\u5173\u95ed\u8d1f\u8f7d\u5747\u8861\u548c Eureka \u7684\u7ed3\u5408\uff0c\u901a\u8fc7\u914d\u7f6e Ribbon \u7684\u670d\u52a1\u5217\u8868\u8fdb\u884c\u8d1f\u8f7d\u5747\u8861\u3002\\n\\n```xml\\n## \u4f20\u7edf\u8def\u7531\u591a\u5b9e\u4f8b\u914d\u7f6e\\nzuul.routes.hello-service.path=/hello-service/**\\nzuul.routes.hello-service.service-id=hello-service\\nribbon.eureka.enabled=false\\nhello-service.ribbon.listOfServers=http://localhost:8081/,http://localhost:8082/\\n```\\n\\n**Zuui\u9ed8\u8ba4\u914d\u7f6e**\\n\\n\u9ed8\u8ba4\u60c5\u51b5\u4e0b\uff0cZuul\u4f1a\u4ee3\u7406\u6240\u6709\u6ce8\u518c\u5230Eureka Server\u7684\u5fae\u670d\u52a1\uff0c\u5e76\u4e14Zuul\u7684\u8def\u7531\u89c4\u5219\u5982\u4e0b\uff1a`http://ZUUL_HOST:ZUUL_PORT/`\u5fae\u670d\u52a1\u5728Eureka\u4e0a\u7684`serviceId/**`\u4f1a\u88ab\u8f6c\u53d1\u5230`serviceId`\u5bf9\u5e94\u7684\u5fae\u670d\u52a1\u3002\\n\\n## \u670d\u52a1\u8fc7\u6ee4\\n\\n### \u81ea\u5b9a\u4e49\u8fc7\u6ee4\u5668\\n\\n\u81ea\u5b9a\u4e49\u8fc7\u6ee4\u5668\u7684\u5b9e\u73b0\uff0c\u9700\u8981\u7ee7\u627f`ZuulFilter`\uff0c\u9700\u8981\u91cd\u5199\u5b9e\u73b0\u4e0b\u9762\u56db\u4e2a\u65b9\u6cd5\uff1a\u8fc7\u6ee4\u7c7b\u578b\u3001\u6267\u884c\u987a\u5e8f\u3001\u6267\u884c\u6761\u4ef6\u3001\u5177\u4f53\u64cd\u4f5c\\n\\n- `filterType`  \uff1a\u8fd4\u56de\u4e00\u4e2a\u5b57\u7b26\u4e32\u4ee3\u8868\u8fc7\u6ee4\u5668\u7684\u7c7b\u578b\uff0c\u5728zuul\u4e2d\u5b9a\u4e49\u4e86\u56db\u79cd\u4e0d\u540c\u751f\u547d\u5468\u671f\u7684\u8fc7\u6ee4\u5668\u7c7b\u578b\uff0c\u5177\u4f53\u5982\u4e0b\uff1a\\n  - `pre`\uff1a\u53ef\u4ee5\u5728\u8bf7\u6c42\u88ab\u8def\u7531\u4e4b\u524d\u8c03\u7528\\n  - `routing`\uff1a\u5728\u8def\u7531\u8bf7\u6c42\u65f6\u5019\u88ab\u8c03\u7528\\n  - `post`\uff1a\u5728routing\u548cerror\u8fc7\u6ee4\u5668\u4e4b\u540e\u88ab\u8c03\u7528\\n  - `error`\uff1a\u5904\u7406\u8bf7\u6c42\u65f6\u53d1\u751f\u9519\u8bef\u65f6\u88ab\u8c03\u7528\\n  \\n- `filterOrder`\uff1a\u901a\u8fc7int\u503c\u6765\u5b9a\u4e49\u8fc7\u6ee4\u5668\u7684\u6267\u884c\u987a\u5e8f\\n\\n- `shouldFilter`\uff1a\u8fd4\u56de\u4e00\u4e2aboolean\u7c7b\u578b\u6765\u5224\u65ad\u8be5\u8fc7\u6ee4\u5668\u662f\u5426\u8981\u6267\u884c\uff0c\u6240\u4ee5\u901a\u8fc7\u6b64\u51fd\u6570\u53ef\u5b9e\u73b0\u8fc7\u6ee4\u5668\u7684\u5f00\u5173\u3002\u5728\u4e0a\u4f8b\u4e2d\uff0c\u6211\u4eec\u76f4\u63a5\u8fd4\u56detrue\uff0c\u6240\u4ee5\u8be5\u8fc7\u6ee4\u5668\u603b\u662f\u751f\u6548\u3002\\n\\n- `run`\uff1a\u8fc7\u6ee4\u5668\u7684\u5177\u4f53\u903b\u8f91\u3002\u9700\u8981\u6ce8\u610f\uff0c\u8fd9\u91cc\u6211\u4eec\u901a\u8fc7`ctx.setSendZuulResponse(false)`\u4ee4zuul\u8fc7\u6ee4\u8be5\u8bf7\u6c42\uff0c\u4e0d\u5bf9\u5176\u8fdb\u884c\u8def\u7531\uff0c\u7136\u540e\u901a\u8fc7`ctx.setResponseStatusCode(401)`\u8bbe\u7f6e\u4e86\u5176\u8fd4\u56de\u7684\u9519\u8bef\u7801\uff0c\u5f53\u7136\u6211\u4eec\u4e5f\u53ef\u4ee5\u8fdb\u4e00\u6b65\u4f18\u5316\u6211\u4eec\u7684\u8fd4\u56de\uff0c\u6bd4\u5982\uff0c\u901a\u8fc7`ctx.setResponseBody(body)`\u5bf9\u8fd4\u56debody\u5185\u5bb9\u8fdb\u884c\u7f16\u8f91\u7b49\u3002\\n\\n```java\\npublic class AccessFilter extends ZuulFilter  {\\n\\n    private static Logger log = LoggerFactory.getLogger(AccessFilter.class);\\n\\n    @Override\\n    public String filterType() {\\n        return \\"pre\\";\\n    }\\n\\n    @Override\\n    public int filterOrder() {\\n        return 0;\\n    }\\n\\n    @Override\\n    public boolean shouldFilter() {\\n        return true;\\n    }\\n\\n    @Override\\n    public Object run() {\\n        RequestContext ctx = RequestContext.getCurrentContext();\\n        HttpServletRequest request = ctx.getRequest();\\n\\n        log.info(String.format(\\"%s request to %s\\", request.getMethod(), request.getRequestURL().toString()));\\n\\n        Object accessToken = request.getParameter(\\"accessToken\\");\\n        if(accessToken == null) {\\n            log.warn(\\"access token is empty\\");\\n            ctx.setSendZuulResponse(false);\\n            ctx.setResponseStatusCode(401);\\n            return null;\\n        }\\n        log.info(\\"access token ok\\");\\n        return null;\\n    }\\n\\n}\\n```\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/10/20191021132307.png)\\n\\n### \u6838\u5fc3\u8fc7\u6ee4\u5668\\n\\n\u5728Spring Cloud Zuul\u4e2d\uff0c\u4e3a\u4e86\u8ba9API\u7f51\u5173\u7ec4\u4ef6\u53ef\u4ee5\u66f4\u65b9\u4fbf\u7684\u4e0a\u624b\u4f7f\u7528\uff0c\u5b83\u5728HTTP\u8bf7\u6c42\u751f\u547d\u5468\u671f\u7684\u5404\u4e2a\u9636\u6bb5\u9ed8\u8ba4\u5730\u5b9e\u73b0\u4e86\u4e00\u6279\u6838\u5fc3\u8fc7\u6ee4\u5668\uff0c\u5b83\u4eec\u4f1a\u5728API\u7f51\u5173\u670d\u52a1\u542f\u52a8\u7684\u65f6\u5019\u88ab\u81ea\u52a8\u5730\u52a0\u8f7d\u548c\u542f\u7528\u3002\u5b9a\u4e49\u4e8e`org.springframework.cloud.netflix.zuul.filters`\u5305\u4e0b\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/10/20191021134033.png)\\n\\n\\n\\n#### pre\u8fc7\u6ee4\u5668\\n\\n- `ServletDetectionFilter`\uff1a\u5b83\u7684\u6267\u884c\u987a\u5e8f\u4e3a-3\uff0c\u662f\u6700\u5148\u88ab\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u3002\u8be5\u8fc7\u6ee4\u5668\u603b\u662f\u4f1a\u88ab\u6267\u884c\uff0c\u4e3b\u8981\u7528\u6765\u68c0\u6d4b\u5f53\u524d\u8bf7\u6c42\u662f\u901a\u8fc7Spring\u7684DispatcherServlet\u5904\u7406\u8fd0\u884c\uff0c\u8fd8\u662f\u901a\u8fc7ZuulServlet\u6765\u5904\u7406\u8fd0\u884c\u7684\u3002\u5b83\u7684\u68c0\u6d4b\u7ed3\u679c\u4f1a\u4ee5\u5e03\u5c14\u7c7b\u578b\u4fdd\u5b58\u5728\u5f53\u524d\u8bf7\u6c42\u4e0a\u4e0b\u6587\u7684isDispatcherServletRequest\u53c2\u6570\u4e2d\uff0c\u8fd9\u6837\u5728\u540e\u7eed\u7684\u8fc7\u6ee4\u5668\u4e2d\uff0c\u6211\u4eec\u5c31\u53ef\u4ee5\u901a\u8fc7RequestUtils.isDispatcherServletRequest()\u548cRequestUtils.isZuulServletRequest()\u65b9\u6cd5\u5224\u65ad\u5b83\u4ee5\u5b9e\u73b0\u505a\u4e0d\u540c\u7684\u5904\u7406\u3002\u4e00\u822c\u60c5\u51b5\u4e0b\uff0c\u53d1\u9001\u5230API\u7f51\u5173\u7684\u5916\u90e8\u8bf7\u6c42\u90fd\u4f1a\u88abSpring\u7684DispatcherServlet\u5904\u7406\uff0c\u9664\u4e86\u901a\u8fc7/zuul/*\u8def\u5f84\u8bbf\u95ee\u7684\u8bf7\u6c42\u4f1a\u7ed5\u8fc7DispatcherServlet\uff0c\u88abZuulServlet\u5904\u7406\uff0c\u4e3b\u8981\u7528\u6765\u5e94\u5bf9\u5904\u7406\u5927\u6587\u4ef6\u4e0a\u4f20\u7684\u60c5\u51b5\u3002\u53e6\u5916\uff0c\u5bf9\u4e8eZuulServlet\u7684\u8bbf\u95ee\u8def\u5f84/zuul/*\uff0c\u6211\u4eec\u53ef\u4ee5\u901a\u8fc7zuul.servletPath\u53c2\u6570\u6765\u8fdb\u884c\u4fee\u6539\u3002\\n- `Servlet30WrapperFilter`\uff1a\u5b83\u7684\u6267\u884c\u987a\u5e8f\u4e3a-2\uff0c\u662f\u7b2c\u4e8c\u4e2a\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u3002\u76ee\u524d\u7684\u5b9e\u73b0\u4f1a\u5bf9\u6240\u6709\u8bf7\u6c42\u751f\u6548\uff0c\u4e3b\u8981\u4e3a\u4e86\u5c06\u539f\u59cb\u7684HttpServletRequest\u5305\u88c5\u6210Servlet30RequestWrapper\u5bf9\u8c61\u3002\\n- `FormBodyWrapperFilter`\uff1a\u5b83\u7684\u6267\u884c\u987a\u5e8f\u4e3a-1\uff0c\u662f\u7b2c\u4e09\u4e2a\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u3002\u8be5\u8fc7\u6ee4\u5668\u4ec5\u5bf9\u4e24\u79cd\u7c7b\u8bf7\u6c42\u751f\u6548\uff0c\u7b2c\u4e00\u7c7b\u662fContent-Type\u4e3aapplication/x-www-form-urlencoded\u7684\u8bf7\u6c42\uff0c\u7b2c\u4e8c\u7c7b\u662fContent-Type\u4e3amultipart/form-data\u5e76\u4e14\u662f\u7531Spring\u7684DispatcherServlet\u5904\u7406\u7684\u8bf7\u6c42\uff08\u7528\u5230\u4e86ServletDetectionFilter\u7684\u5904\u7406\u7ed3\u679c\uff09\u3002\u800c\u8be5\u8fc7\u6ee4\u5668\u7684\u4e3b\u8981\u76ee\u7684\u662f\u5c06\u7b26\u5408\u8981\u6c42\u7684\u8bf7\u6c42\u4f53\u5305\u88c5\u6210FormBodyRequestWrapper\u5bf9\u8c61\u3002\\n- `DebugFilter`\uff1a\u5b83\u7684\u6267\u884c\u987a\u5e8f\u4e3a1\uff0c\u662f\u7b2c\u56db\u4e2a\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u3002\u8be5\u8fc7\u6ee4\u5668\u4f1a\u6839\u636e\u914d\u7f6e\u53c2\u6570zuul.debug.request\u548c\u8bf7\u6c42\u4e2d\u7684debug\u53c2\u6570\u6765\u51b3\u5b9a\u662f\u5426\u6267\u884c\u8fc7\u6ee4\u5668\u4e2d\u7684\u64cd\u4f5c\u3002\u800c\u5b83\u7684\u5177\u4f53\u64cd\u4f5c\u5185\u5bb9\u5219\u662f\u5c06\u5f53\u524d\u7684\u8bf7\u6c42\u4e0a\u4e0b\u6587\u4e2d\u7684debugRouting\u548cdebugRequest\u53c2\u6570\u8bbe\u7f6e\u4e3atrue\u3002\u7531\u4e8e\u5728\u540c\u4e00\u4e2a\u8bf7\u6c42\u7684\u4e0d\u540c\u751f\u547d\u5468\u671f\u4e2d\uff0c\u90fd\u53ef\u4ee5\u8bbf\u95ee\u5230\u8fd9\u4e24\u4e2a\u503c\uff0c\u6240\u4ee5\u6211\u4eec\u5728\u540e\u7eed\u7684\u5404\u4e2a\u8fc7\u6ee4\u5668\u4e2d\u53ef\u4ee5\u5229\u7528\u8fd9\u4e24\u503c\u6765\u5b9a\u4e49\u4e00\u4e9bdebug\u4fe1\u606f\uff0c\u8fd9\u6837\u5f53\u7ebf\u4e0a\u73af\u5883\u51fa\u73b0\u95ee\u9898\u7684\u65f6\u5019\uff0c\u53ef\u4ee5\u901a\u8fc7\u8bf7\u6c42\u53c2\u6570\u7684\u65b9\u5f0f\u6765\u6fc0\u6d3b\u8fd9\u4e9bdebug\u4fe1\u606f\u4ee5\u5e2e\u52a9\u5206\u6790\u95ee\u9898\u3002\u53e6\u5916\uff0c\u5bf9\u4e8e\u8bf7\u6c42\u53c2\u6570\u4e2d\u7684debug\u53c2\u6570\uff0c\u6211\u4eec\u4e5f\u53ef\u4ee5\u901a\u8fc7zuul.debug.parameter\u6765\u8fdb\u884c\u81ea\u5b9a\u4e49\u3002\\n- `PreDecorationFilter`\uff1a\u5b83\u7684\u6267\u884c\u987a\u5e8f\u4e3a5\uff0c\u662fpre\u9636\u6bb5\u6700\u540e\u88ab\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u3002\u8be5\u8fc7\u6ee4\u5668\u4f1a\u5224\u65ad\u5f53\u524d\u8bf7\u6c42\u4e0a\u4e0b\u6587\u4e2d\u662f\u5426\u5b58\u5728forward.to\u548cserviceId\u53c2\u6570\uff0c\u5982\u679c\u90fd\u4e0d\u5b58\u5728\uff0c\u90a3\u4e48\u5b83\u5c31\u4f1a\u6267\u884c\u5177\u4f53\u8fc7\u6ee4\u5668\u7684\u64cd\u4f5c\uff08\u5982\u679c\u6709\u4e00\u4e2a\u5b58\u5728\u7684\u8bdd\uff0c\u8bf4\u660e\u5f53\u524d\u8bf7\u6c42\u5df2\u7ecf\u88ab\u5904\u7406\u8fc7\u4e86\uff0c\u56e0\u4e3a\u8fd9\u4e24\u4e2a\u4fe1\u606f\u5c31\u662f\u6839\u636e\u5f53\u524d\u8bf7\u6c42\u7684\u8def\u7531\u4fe1\u606f\u52a0\u8f7d\u8fdb\u6765\u7684\uff09\u3002\u800c\u5b83\u7684\u5177\u4f53\u64cd\u4f5c\u5185\u5bb9\u5c31\u662f\u4e3a\u5f53\u524d\u8bf7\u6c42\u505a\u4e00\u4e9b\u9884\u5904\u7406\uff0c\u6bd4\u5982\uff1a\u8fdb\u884c\u8def\u7531\u89c4\u5219\u7684\u5339\u914d\u3001\u5728\u8bf7\u6c42\u4e0a\u4e0b\u6587\u4e2d\u8bbe\u7f6e\u8be5\u8bf7\u6c42\u7684\u57fa\u672c\u4fe1\u606f\u4ee5\u53ca\u5c06\u8def\u7531\u5339\u914d\u7ed3\u679c\u7b49\u4e00\u4e9b\u8bbe\u7f6e\u4fe1\u606f\u7b49\uff0c\u8fd9\u4e9b\u4fe1\u606f\u5c06\u662f\u540e\u7eed\u8fc7\u6ee4\u5668\u8fdb\u884c\u5904\u7406\u7684\u91cd\u8981\u4f9d\u636e\uff0c\u6211\u4eec\u53ef\u4ee5\u901a\u8fc7RequestContext.getCurrentContext()\u6765\u8bbf\u95ee\u8fd9\u4e9b\u4fe1\u606f\u3002\u53e6\u5916\uff0c\u6211\u4eec\u8fd8\u53ef\u4ee5\u5728\u8be5\u5b9e\u73b0\u4e2d\u627e\u5230\u4e00\u4e9b\u5bf9HTTP\u5934\u8bf7\u6c42\u8fdb\u884c\u5904\u7406\u7684\u903b\u8f91\uff0c\u5176\u4e2d\u5305\u542b\u4e86\u4e00\u4e9b\u8033\u719f\u80fd\u8be6\u7684\u5934\u57df\uff0c\u6bd4\u5982\uff1aX-Forwarded-Host\u3001X-Forwarded-Port\u3002\u53e6\u5916\uff0c\u5bf9\u4e8e\u8fd9\u4e9b\u5934\u57df\u7684\u8bb0\u5f55\u662f\u901a\u8fc7zuul.addProxyHeaders\u53c2\u6570\u8fdb\u884c\u63a7\u5236\u7684\uff0c\u800c\u8fd9\u4e2a\u53c2\u6570\u9ed8\u8ba4\u503c\u4e3atrue\uff0c\u6240\u4ee5Zuul\u5728\u8bf7\u6c42\u8df3\u8f6c\u65f6\u9ed8\u8ba4\u5730\u4f1a\u4e3a\u8bf7\u6c42\u589e\u52a0X-Forwarded-*\u5934\u57df\uff0c\u5305\u62ec\uff1aX-Forwarded-Host\u3001X-Forwarded-Port\u3001X-Forwarded-For\u3001X-Forwarded-Prefix\u3001X-Forwarded-Proto\u3002\u6211\u4eec\u4e5f\u53ef\u4ee5\u901a\u8fc7\u8bbe\u7f6ezuul.addProxyHeaders=false\u5173\u95ed\u5bf9\u8fd9\u4e9b\u5934\u57df\u7684\u6dfb\u52a0\u52a8\u4f5c\u3002\\n\\n> [\u300aSpring Cloud\u5b9e\u6218\u5c0f\u8d34\u58eb\uff1aZuul\u5904\u7406Cookie\u548c\u91cd\u5b9a\u5411\u300b](http://blog.didispace.com/spring-cloud-zuul-cookie-redirect/) \u4e00\u6587\u4e2d\u63d0\u5230\u7684\u52a0\u8f7d\u654f\u611f\u5934\u4fe1\u606f\u52a0\u5165\u5230\u5ffd\u7565\u5934\u4fe1\u606f\u7684\u64cd\u4f5c\u8c03\u7528\u5c31\u5728PreDecorationFilter\u8fc7\u6ee4\u5668\u4e2d\u5b9e\u73b0\u3002\\n\\n#### route\u8fc7\u6ee4\u5668\\n\\n- RibbonRoutingFilter\uff1a\u5b83\u7684\u6267\u884c\u987a\u5e8f\u4e3a10\uff0c\u662froute\u9636\u6bb5\u7b2c\u4e00\u4e2a\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u3002\u8be5\u8fc7\u6ee4\u5668\u53ea\u5bf9\u8bf7\u6c42\u4e0a\u4e0b\u6587\u4e2d\u5b58\u5728serviceId\u53c2\u6570\u7684\u8bf7\u6c42\u8fdb\u884c\u5904\u7406\uff0c\u5373\u53ea\u5bf9\u901a\u8fc7serviceId\u914d\u7f6e\u8def\u7531\u89c4\u5219\u7684\u8bf7\u6c42\u751f\u6548\u3002\u800c\u8be5\u8fc7\u6ee4\u5668\u7684\u6267\u884c\u903b\u8f91\u5c31\u662f\u9762\u5411\u670d\u52a1\u8def\u7531\u7684\u6838\u5fc3\uff0c\u5b83\u901a\u8fc7\u4f7f\u7528Ribbon\u548cHystrix\u6765\u5411\u670d\u52a1\u5b9e\u4f8b\u53d1\u8d77\u8bf7\u6c42\uff0c\u5e76\u5c06\u670d\u52a1\u5b9e\u4f8b\u7684\u8bf7\u6c42\u7ed3\u679c\u8fd4\u56de\u3002\\n- SimpleHostRoutingFilter\uff1a\u5b83\u7684\u6267\u884c\u987a\u5e8f\u4e3a100\uff0c\u662froute\u9636\u6bb5\u7b2c\u4e8c\u4e2a\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u3002\u8be5\u8fc7\u6ee4\u5668\u53ea\u5bf9\u8bf7\u6c42\u4e0a\u4e0b\u6587\u4e2d\u5b58\u5728routeHost\u53c2\u6570\u7684\u8bf7\u6c42\u8fdb\u884c\u5904\u7406\uff0c\u5373\u53ea\u5bf9\u901a\u8fc7url\u914d\u7f6e\u8def\u7531\u89c4\u5219\u7684\u8bf7\u6c42\u751f\u6548\u3002\u800c\u8be5\u8fc7\u6ee4\u5668\u7684\u6267\u884c\u903b\u8f91\u5c31\u662f\u76f4\u63a5\u5411routeHost\u53c2\u6570\u7684\u7269\u7406\u5730\u5740\u53d1\u8d77\u8bf7\u6c42\uff0c\u4ece\u6e90\u7801\u4e2d\u6211\u4eec\u53ef\u4ee5\u77e5\u9053\u8be5\u8bf7\u6c42\u662f\u76f4\u63a5\u901a\u8fc7httpclient\u5305\u5b9e\u73b0\u7684\uff0c\u800c\u6ca1\u6709\u4f7f\u7528Hystrix\u547d\u4ee4\u8fdb\u884c\u5305\u88c5\uff0c\u6240\u4ee5\u8fd9\u7c7b\u8bf7\u6c42\u5e76\u6ca1\u6709\u7ebf\u7a0b\u9694\u79bb\u548c\u65ad\u8def\u5668\u7684\u4fdd\u62a4\u3002\\n- SendForwardFilter\uff1a\u5b83\u7684\u6267\u884c\u987a\u5e8f\u4e3a500\uff0c\u662froute\u9636\u6bb5\u7b2c\u4e09\u4e2a\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u3002\u8be5\u8fc7\u6ee4\u5668\u53ea\u5bf9\u8bf7\u6c42\u4e0a\u4e0b\u6587\u4e2d\u5b58\u5728forward.to\u53c2\u6570\u7684\u8bf7\u6c42\u8fdb\u884c\u5904\u7406\uff0c\u5373\u7528\u6765\u5904\u7406\u8def\u7531\u89c4\u5219\u4e2d\u7684forward\u672c\u5730\u8df3\u8f6c\u914d\u7f6e\u3002\\n\\n#### post\u8fc7\u6ee4\u5668\\n\\n- SendErrorFilter\uff1a\u5b83\u7684\u6267\u884c\u987a\u5e8f\u4e3a0\uff0c\u662fpost\u9636\u6bb5\u7b2c\u4e00\u4e2a\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u3002\u8be5\u8fc7\u6ee4\u5668\u4ec5\u5728\u8bf7\u6c42\u4e0a\u4e0b\u6587\u4e2d\u5305\u542berror.status_code\u53c2\u6570\uff08\u7531\u4e4b\u524d\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u8bbe\u7f6e\u7684\u9519\u8bef\u7f16\u7801\uff09\u5e76\u4e14\u8fd8\u6ca1\u6709\u88ab\u8be5\u8fc7\u6ee4\u5668\u5904\u7406\u8fc7\u7684\u65f6\u5019\u6267\u884c\u3002\u800c\u8be5\u8fc7\u6ee4\u5668\u7684\u5177\u4f53\u903b\u8f91\u5c31\u662f\u5229\u7528\u8bf7\u6c42\u4e0a\u4e0b\u6587\u4e2d\u7684\u9519\u8bef\u4fe1\u606f\u6765\u7ec4\u7ec7\u6210\u4e00\u4e2aforward\u5230API\u7f51\u5173/error\u9519\u8bef\u7aef\u70b9\u7684\u8bf7\u6c42\u6765\u4ea7\u751f\u9519\u8bef\u54cd\u5e94\u3002\\n- SendResponseFilter\uff1a\u5b83\u7684\u6267\u884c\u987a\u5e8f\u4e3a1000\uff0c\u662fpost\u9636\u6bb5\u6700\u540e\u6267\u884c\u7684\u8fc7\u6ee4\u5668\u3002\u8be5\u8fc7\u6ee4\u5668\u4f1a\u68c0\u67e5\u8bf7\u6c42\u4e0a\u4e0b\u6587\u4e2d\u662f\u5426\u5305\u542b\u8bf7\u6c42\u54cd\u5e94\u76f8\u5173\u7684\u5934\u4fe1\u606f\u3001\u54cd\u5e94\u6570\u636e\u6d41\u6216\u662f\u54cd\u5e94\u4f53\uff0c\u53ea\u6709\u5728\u5305\u542b\u5b83\u4eec\u5176\u4e2d\u4e00\u4e2a\u7684\u65f6\u5019\u5c31\u4f1a\u6267\u884c\u5904\u7406\u903b\u8f91\u3002\u800c\u8be5\u8fc7\u6ee4\u5668\u7684\u5904\u7406\u903b\u8f91\u5c31\u662f\u5229\u7528\u8bf7\u6c42\u4e0a\u4e0b\u6587\u7684\u54cd\u5e94\u4fe1\u606f\u6765\u7ec4\u7ec7\u9700\u8981\u53d1\u9001\u56de\u5ba2\u6237\u7aef\u7684\u54cd\u5e94\u5185\u5bb9\u3002\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/10/20191021133625.png)\\n\\n\\n\\n## \u53c2\u8003\u6587\u7ae0\\n\\n- [Spring Cloud \u6e90\u7801\u5206\u6790\uff08\u56db\uff09Zuul\uff1a\u6838\u5fc3\u8fc7\u6ee4\u5668](<http://blog.didispace.com/spring-cloud-source-zuul/>)\\n- [Spring Cloud Netflix\u5957\u4ef6](<http://blog.didispace.com/spring-cloud-learning/>)"},{"id":"ftp-on-centos","metadata":{"permalink":"/blog/ftp-on-centos","source":"@site/blog\\\\2019-05-11-CentOS7\u4e0b\u642d\u5efaFTP.md","title":"CentOS\u4e0b\u642d\u5efaFTP","description":"\u73af\u5883\uff1a","date":"2019-05-11T00:00:00.000Z","formattedDate":"2019\u5e745\u670811\u65e5","tags":[{"label":"FTP","permalink":"/blog/tags/ftp"}],"truncated":false,"authors":[],"frontMatter":{"slug":"ftp-on-centos","title":"CentOS\u4e0b\u642d\u5efaFTP","tags":["FTP"]},"prevItem":{"title":"\u521d\u8bc6Zuul","permalink":"/blog/zuul-basic"},"nextItem":{"title":"Git\u5b66\u4e60\u7b14\u8bb0","permalink":"/blog/git-notes"}},"content":"\u73af\u5883\uff1a\\n\\n- \u767e\u5ea6\u4e91\u670d\u52a1\u5668Cent OS 7\\n- \u4f7f\u7528\u5ba2\u6237\u7aefwin 10\\n\\n\x3c!--more--\x3e\\n\\n## \u5b89\u88c5\u5e76\u542f\u52a8 FTP \u670d\u52a1\\n\\n### \u5b89\u88c5 VSFTPD\\n\\n\u4f7f\u7528 `yum` \u5b89\u88c5 `vsftpd`\\n\\n```shell\\nyum install -y vsftpd\\n```\\n\\n### \u542f\u52a8 VSFTPD\\n\\n\u5b89\u88c5\u5b8c\u6210\u540e\uff0c\u542f\u52a8 FTP \u670d\u52a1\uff1a\\n\\n```bash\\nservice vsftpd start\\n# CentOS 7\u4f7f\u7528\u4e0b\u9762\u7684\u547d\u4ee4\u542f\u52a8\u670d\u52a1\\nsystemctl start vsftpd.service\\n# \u5f00\u673a\u81ea\u542f\\nsystemctl enable vsftpd\\n```\\n\\n\u542f\u52a8\u540e\uff0c\u53ef\u4ee5\u770b\u5230\u7cfb\u7edf\u5df2\u7ecf\u76d1\u542c\u4e86 21 \u7aef\u53e3\uff1a\\n\\n```shell\\nnetstat -nltp | grep 21\\n```\\n\\n\u6b64\u65f6\uff0c\u8bbf\u95ee ftp://192.168.1.170 \u53ef\u6d4f\u89c8\u673a\u5668\u4e0a\u7684 /var/ftp\u76ee\u5f55\u4e86\u3002\\n\\n## \u914d\u7f6e FTP \u6743\u9650\\n\\n### \u4e86\u89e3 VSFTP \u914d\u7f6e\\n\\nvsftpd \u7684\u914d\u7f6e\u76ee\u5f55\u4e3a /etc/vsftpd\uff0c\u5305\u542b\u4e0b\u5217\u7684\u914d\u7f6e\u6587\u4ef6\uff1a\\n\\n- vsftpd.conf \u4e3a\u4e3b\u8981\u914d\u7f6e\u6587\u4ef6\\n- ftpusers \u914d\u7f6e\u7981\u6b62\u8bbf\u95ee FTP \u670d\u52a1\u5668\u7684\u7528\u6237\u5217\u8868\\n- user_list \u914d\u7f6e\u7528\u6237\u8bbf\u95ee\u63a7\u5236\\n\\n### \u963b\u6b62\u533f\u540d\u8bbf\u95ee\u548c\u5207\u6362\u6839\u76ee\u5f55\\n\\n\u533f\u540d\u8bbf\u95ee\u548c\u5207\u6362\u6839\u76ee\u5f55\u90fd\u4f1a\u7ed9\u670d\u52a1\u5668\u5e26\u6765\u5b89\u5168\u98ce\u9669\uff0c\u6211\u4eec\u628a\u8fd9\u4e24\u4e2a\u529f\u80fd\u5173\u95ed\u3002\\n\\n\u7f16\u8f91 /etc/vsftpd/vsftpd.conf\uff0c\u627e\u5230\u4e0b\u9762\u4e24\u5904\u914d\u7f6e\u5e76\u4fee\u6539\uff1a\\n\\n```xml\\n# \u7981\u7528\u533f\u540d\u7528\u6237  12 YES \u6539\u4e3aNO\\nanonymous_enable=NO\\n\\n# \u7981\u6b62\u5207\u6362\u6839\u76ee\u5f55 101 \u884c \u5220\u9664#\\nchroot_local_user=YES\\n```\\n\\n\u7f16\u8f91\u5b8c\u6210\u540e\u4fdd\u5b58\u914d\u7f6e\uff0c\u91cd\u65b0\u542f\u52a8 FTP \u670d\u52a1\\n\\n```bash\\nservice vsftpd restart\\n# CentOS 7\\nsystemctl restart vsftpd.service\\n```\\n\\n\\n\\nvsftpd.conf\u914d\u7f6e\u6587\u4ef6\\n\\n```properties\\n# \u662f\u5426\u5141\u8bb8\u533f\u540d\u767b\u5f55\\nanonymous_enable=YES\\n# \u662f\u5426\u5141\u8bb8\u672c\u5730\u7528\u6237\u767b\u5f55\\nlocal_enable=YES\\n# \u662f\u5426\u5141\u8bb8\u672c\u5730\u7528\u6237\u5bf9FTP\u670d\u52a1\u5668\u6587\u4ef6\u5177\u6709\u5199\u6743\u9650\\nwrite_enable=YES\\n# \u672c\u5730\u7528\u6237\u4e3b\u76ee\u5f55\\nlocal_root=/var/ftp\\n# \u533f\u540d\u7528\u6237\u4e3b\u76ee\u5f55\\nanon_root=/var/ftp/pub\\n# \u662f\u5426\u5141\u8bb8\u533f\u540d\u7528\u6237\u4e0a\u4f20\u6587\u4ef6\uff0c\u5982\u5141\u8bb8\uff0c\u987b\u5c06\u5168\u5c40\u7684write_enable=YES\\nanon_upload_enable=YES\\n# \u662f\u5426\u5141\u8bb8\u533f\u540d\u7528\u6237\u521b\u5efa\u65b0\u6587\u4ef6\u5939\\nanon_mkdir_write_enable=YES\\n# \u5bb9\u8bb8\u533f\u540d\u7528\u6237\u9664\u4e86\u65b0\u5efa\u548c\u4e0a\u4f20\u5916\u7684\u5176\u4ed6\u6743\u9650\\nanon_other_write_enable=YES\\n# \u672c\u5730\u7528\u6237\u63a9\u7801\\nlocal_umask=022\\n# \u8bbe\u7f6e\u533f\u540d\u767b\u5165\u8005\u65b0\u589e\u6216\u4e0a\u4f20\u6863\u6848\u65f6\u7684umask\u503c\\nanon_umask=022\\n# \u662f\u5426\u6fc0\u6d3b\u76ee\u5f55\u6b22\u8fce\u4fe1\u606f\u529f\u80fd\\ndirmessage_enable=YES\\nxferlog_enable=YES\\n# \u4e3b\u52a8\u6a21\u5f0f\u6570\u636e\u4f20\u8f9320\u7aef\u53e3\\nconnect_from_port_20=NO\\nxferlog_std_format=YES\\n# \u662f\u5426\u76d1\u542cipv4\\nlisten=YES\\n# listen_ipv6=YES\\n\\npam_service_name=vsftpd\\nuserlist_enable=YES\\ntcp_wrappers=YES\\n\\n# \u662f\u5426\u8bbe\u7f6e\u88ab\u52a8\u6a21\u5f0f\\npasv_enable=YES\\n\\n# \u88ab\u52a8\u6a21\u5f0f\u4f20\u8f93\u4f7f\u7528\u7aef\u53e3\\npasv_min_port=20020\\npasv_max_port=20020\\n\\n# \u88ab\u52a8\u6a21\u5f0f\u8fd4\u56de\u7ed9\u5ba2\u6237\u7aef\u7684ip\u5730\u5740(\u670d\u52a1\u5668\u5185\u7f51\u7a7f\u900f\u65f6\u4f7f\u7528)\\npasv_address=0.0.0.0( \u670d\u52a1\u5668\u5916\u7f51ip )\\n\\n# \u8bbe\u7f6e\u7528\u6237\u8bbf\u95ee\u76ee\u5f55\uff0c\u9ed8\u8ba4\u53ea\u5141\u8bb8\u7528\u6237\u81ea\u5df1\u7684ftp\u76ee\u5f55\\n# \u9700\u8981\u540c\u65f6\u8bbe\u7f6eallow_writeable_chroot\uff0c\u5141\u8bb8\u53d7\u9650\u7528\u6237\u7684\u5199\u6743\u9650\uff0c\u4e0d\u7136\u4f1a\u62a5\u9519\\nchroot_local_user=YES\\nchroot_list_enable=YES\\nchroot_list_file=/etc/vsftpd/chroot_list\\nallow_writeable_chroot=YES\\n```\\n\\n\\n\\n|                            | chroot_local_user=YES                                        | chroot_local_user=NO                                         |\\n| -------------------------- | ------------------------------------------------------------ | ------------------------------------------------------------ |\\n| **chroot_list_enable=YES** | 1.\u6240\u6709\u7528\u6237\u90fd\u88ab\u9650\u5236\u5728\u5176\u4e3b\u76ee\u5f55\u4e0b <br/>2.\u4f7f\u7528chroot_list_file\u6307\u5b9a\u7684\u7528\u6237\u5217\u8868\uff0c\u8fd9\u4e9b\u7528\u6237\u4f5c\u4e3a\u201c\u4f8b\u5916\u201d\uff0c\u4e0d\u53d7\u9650\u5236 | 1.\u6240\u6709\u7528\u6237\u90fd\u4e0d\u88ab\u9650\u5236\u5176\u4e3b\u76ee\u5f55\u4e0b <br/>2.\u4f7f\u7528chroot_list_file\u6307\u5b9a\u7684\u7528\u6237\u5217\u8868\uff0c\u8fd9\u4e9b\u7528\u6237\u4f5c\u4e3a\u201c\u4f8b\u5916\u201d\uff0c\u53d7\u5230\u9650\u5236 |\\n| **chroot_list_enable=NO**  | 1.\u6240\u6709\u7528\u6237\u90fd\u88ab\u9650\u5236\u5728\u5176\u4e3b\u76ee\u5f55\u4e0b<br/> 2.\u4e0d\u4f7f\u7528chroot_list_file\u6307\u5b9a\u7684\u7528\u6237\u5217\u8868\uff0c\u6ca1\u6709\u4efb\u4f55\u201c\u4f8b\u5916\u201d\u7528\u6237 | 1.\u6240\u6709\u7528\u6237\u90fd\u4e0d\u88ab\u9650\u5236\u5176\u4e3b\u76ee\u5f55\u4e0b<br/> 2.\u4e0d\u4f7f\u7528chroot_list_file\u6307\u5b9a\u7684\u7528\u6237\u5217\u8868\uff0c\u6ca1\u6709\u4efb\u4f55\u201c\u4f8b\u5916\u201d\u7528\u6237 |\\n\\n\\n\\n### \u521b\u5efa FTP \u7528\u6237\\n\\n\u521b\u5efa\u4e00\u4e2a\u7528\u6237 `ftpuser`\\n\\n```bash\\nuseradd ftpuser\\n```\\n\\n\u4e3a\u7528\u6237 ftpuser \u8bbe\u7f6e\u5bc6\u7801\\n\\n```bash\\necho \\"pwd\\" | passwd ftpuser --stdin\\n```\\n\\n### \u9650\u5236\u8be5\u7528\u6237\u4ec5\u80fd\u901a\u8fc7 FTP \u8bbf\u95ee\\n\\n\u9650\u5236\u7528\u6237 `ftpuser`\u53ea\u80fd\u901a\u8fc7 FTP \u8bbf\u95ee\u670d\u52a1\u5668\uff0c\u800c\u4e0d\u80fd\u76f4\u63a5\u767b\u5f55\u670d\u52a1\u5668\uff1a\\n\\n```bash\\nusermod -s /sbin/nologin ftpuser\\n\\n```\\n\\n### \u4e3a\u7528\u6237\u5206\u914d\u4e3b\u76ee\u5f55\\n\\n\u56e0\u5b89\u5168\u95ee\u9898\uff0cvsftpd\u4e0d\u5141\u8bb8\u533f\u540d\u7528\u6237\u5728ftp\u4e3b\u76ee\u5f55\u4e0a\u4f20\uff0c\u53ef\u4ee5\u65b0\u5efa\u4e00\u4e2a\u5b50\u76ee\u5f55\uff0c\u7136\u540e\u8bbe\u7f6e\u6743\u9650\u4e3a777\\n\\n\u4e3a\u7528\u6237 `ftpuser`\u521b\u5efa\u4e3b\u76ee\u5f55\u5e76\u7ea6\u5b9a\uff1a\\n\\n`/data/ftp` \u4e3a\u4e3b\u76ee\u5f55, \u8be5\u76ee\u5f55\u4e0d\u53ef\u4e0a\u4f20\u6587\u4ef6 \\n`/data/ftp/pub` \u6587\u4ef6\u53ea\u80fd\u4e0a\u4f20\u5230\u8be5\u76ee\u5f55\u4e0b\\n\\n\u5728`/data`\u4e2d\u521b\u5efa\u76f8\u5173\u7684\u76ee\u5f55\\n\\n```bash\\nmkdir -p /data/ftp/pub\\n\\n```\\n\\n#### \u521b\u5efa\u767b\u5f55\u6b22\u8fce\u6587\u4ef6\\n\\n```bash\\necho \\"Welcome to use FTP service.\\" > /data/ftp/welcome.txt\\n\\n```\\n\\n\u8bbe\u7f6e\u8bbf\u95ee\u6743\u9650\\n\\n```bash\\nchmod a-w /data/ftp && chmod 777 -R /data/ftp/pub\\n\\n```\\n\\n\u8fd9\u91cc\u53bb\u6389\u4e86ftp\u76ee\u5f55\u5199\u5165\u7684\u6743\u9650\\n\\n\u8bbe\u7f6e\u4e3a\u7528\u6237\u7684\u4e3b\u76ee\u5f55\uff1a\\n\\n```bash\\nusermod -d /data/ftp ftpuser\\n\\n```\\n\\n\\n\\n\u6ce8\u610f\uff1a\u8bb0\u5f97\u5173\u95ed\u9632\u706b\u5899\u6216\u8005\u5f00\u653eFTP\u9ed8\u8ba4\u7aef\u53e3(21)\\n\\n```bash\\n# \u5173\u95edSELinux\u670d\u52a1\\nsetenforce 0 \\n# \u5173\u95ed\u9632\u706b\u5899\\niptables -F \\n\\n```\\n\\n\\n\\nbase: https://www.linuxidc.com/Linux/2017-11/148518.htm\\n\\n\\n\\n## FTP\u7684\u8fde\u63a5\u65b9\u5f0f\\n\\n> FTP\u662f\u4ec5\u57fa\u4e8eTCP\u7684\u670d\u52a1\uff0c\u4e0d\u652f\u6301UDP\u3002\u4e0e\u4f17\u4e0d\u540c\u7684\u662fFTP\u4f7f\u75282\u4e2a\u7aef\u53e3\uff0c\u4e00\u4e2a\u6570\u636e\u7aef\u53e3\u548c\u4e00\u4e2a\u547d\u4ee4\u7aef\u53e3\uff08\u4e5f\u53ef\u53eb\u505a\u63a7\u5236\u7aef\u53e3\uff09\\n\\n> \u4e3b\u52a8\u6a21\u5f0f\u548c\u88ab\u52a8\u6a21\u5f0f\u7684\u4e0d\u540c\u7b80\u5355\u6982\u8ff0\u4e3a\uff1a \u4e3b\u52a8\u6a21\u5f0f\u4f20\u9001\u6570\u636e\u65f6\u662f\u201c\u670d\u52a1\u5668\u201d\u8fde\u63a5\u5230\u201c\u5ba2\u6237\u7aef\u201d\u7684\u7aef\u53e3\uff1b\u88ab\u52a8\u6a21\u5f0f\u4f20\u9001\u6570\u636e\u662f\u201c\u5ba2\u6237\u7aef\u201d\u8fde\u63a5\u5230\u201c\u670d\u52a1\u5668\u201d\u7684\u7aef\u53e3\u3002\\n\\n> \u4e3b\u52a8\u6a21\u5f0f\u9700\u8981\u5ba2\u6237\u7aef\u5fc5\u987b\u5f00\u653e\u7aef\u53e3\u7ed9\u670d\u52a1\u5668\uff0c\u5f88\u591a\u5ba2\u6237\u7aef\u90fd\u662f\u5728\u9632\u706b\u5899\u5185\uff0c\u5f00\u653e\u7aef\u53e3\u7ed9FTP\u670d\u52a1\u5668\u8bbf\u95ee\u6bd4\u8f83\u56f0\u96be\u3002\\n\\n> \u88ab\u52a8\u6a21\u5f0f\u53ea\u9700\u8981\u670d\u52a1\u5668\u7aef\u5f00\u653e\u7aef\u53e3\u7ed9\u5ba2\u6237\u7aef\u8fde\u63a5\u5c31\u884c\u4e86\u3002\\n\\n\\n\\n### \u4e3b\u52a8\u6a21\u5f0f(PORT)\\n\\nPORT\u662f\u4e3b\u52a8\u6a21\u5f0f\uff0c\u5728\u5efa\u7acb\u6570\u636e\u901a\u9053\u65f6\uff0c\u670d\u52a1\u7aef\u53bb\u8fde\u63a5\u522b\u4eba\\n\\n\u5de5\u4f5c\u8fc7\u7a0b\uff1a\\n\\n1. \u5ba2\u6237\u7aef\u4ece\u4e00\u4e2a\u4efb\u610f\u7684\u975e\u7279\u6743\u7aef\u53e3N\uff08N\u5927\u4e8e1024\uff09\u8fde\u63a5\u5230FTP\u670d\u52a1\u5668\u7684\u547d\u4ee4\u7aef\u53e3(21\u7aef\u53e3)\\n2. \u5ba2\u6237\u7aef\u5f00\u59cb\u76d1\u542c\u7aef\u53e3N+1\uff0c\u5e76\u53d1\u9001FTP\u547d\u4ee4\u201cport N+1\u201d\u5230FTP\u670d\u52a1\u5668\\n3. \u670d\u52a1\u5668\u4f1a\u4e3b\u52a8\u4ece\u6570\u636e\u7aef\u53e3\uff0820\uff09\u8fde\u63a5\u5230\u5ba2\u6237\u7aef\u6307\u5b9a\u7684\u6570\u636e\u7aef\u53e3\uff08N+1\uff09\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/05/20190509223643.png)\\n\\n**\u547d\u4ee4\u8fde\u63a5\uff1a\u5ba2\u6237\u7aef \uff08\u5927\u4e8e1024\u7aef\u53e3\uff09 ->  \u670d\u52a1\u5668 21\u7aef\u53e3 **\\n\\n**\u6570\u636e\u8fde\u63a5\uff1a\u670d\u52a1\u5668 20\u7aef\u53e3 ->  \u5ba2\u6237\u7aef\uff08\u5927\u4e8e1024\u7684\u7aef\u53e3**\\n\\n\\n\\n### \u88ab\u52a8\u6a21\u5f0f(PASV)\\n\\nPASV\u662f\u88ab\u52a8\u6a21\u5f0f\uff0c\u5728\u5efa\u7acb\u6570\u636e\u901a\u9053\u65f6\uff0c\u670d\u52a1\u7aef\u88ab\u522b\u4eba\u8fde\u63a5\u3002\u5f53\u5ba2\u6237\u7aef\u901a\u77e5\u670d\u52a1\u5668\u5b83\u5904\u4e8e\u88ab\u52a8\u6a21\u5f0f\u65f6\u624d\u542f\u7528\\n\\n\u5728\u88ab\u52a8\u65b9\u5f0fFTP\u4e2d\uff0c\u547d\u4ee4\u8fde\u63a5\u548c\u6570\u636e\u8fde\u63a5\u90fd\u7531\u5ba2\u6237\u7aef\u53d1\u8d77\uff0c\u8fd9\u6837\u5c31\u53ef\u4ee5\u89e3\u51b3\u4ece\u670d\u52a1\u5668\u5230\u5ba2\u6237\u7aef\u7684\u6570\u636e\u7aef\u53e3\u7684\u5165\u65b9\u5411\u8fde\u63a5\u88ab\u9632\u706b\u5899\u8fc7\u6ee4\u6389\u7684\u95ee\u9898\\n\\n\u5de5\u4f5c\u8fc7\u7a0b\uff1a\\n\\n1. \u5ba2\u6237\u7aef\u6253\u5f00\u4e24\u4e2a\u4efb\u610f\u7684\u975e\u7279\u6743\u672c\u5730\u7aef\u53e3\uff08N \u5927\u4e8e 1024\u548cN+1\uff09\u3002\u7b2c\u4e00\u4e2a\u7aef\u53e3\u8fde\u63a5\u670d\u52a1\u5668\u768421\u7aef\u53e3\uff0c\u7136\u540e\u5411\u670d\u52a1\u5668\u53d1\u9001PASV\u547d\u4ee4\uff0c\u901a\u77e5\u670d\u52a1\u7aef\u81ea\u5df1\u5904\u4e8e\u88ab\u52a8\u72b6\u6001\uff08\u4e3b\u52a8\u65b9\u5f0f\u7684FTP\u4e0d\u540c\uff0c\u5ba2\u6237\u7aef\u4e0d\u4f1a\u63d0\u4ea4PORT\u547d\u4ee4\u5e76\u5141\u8bb8\u670d\u52a1\u5668\u6765\u56de\u8fde\u5b83\u7684\u6570\u636e\u7aef\u53e3\uff09\\n2. \u670d\u52a1\u7aef\u6536\u5230\u547d\u4ee4\u540e\uff0c\u4f1a\u5f00\u542f\u4e00\u4e2a\u4efb\u610f\u7684\u975e\u7279\u6743\u7aef\u53e3\uff08P\u5927\u4e8e 1024\uff09\uff0c\u5e76\u53d1\u9001PORT P\u547d\u4ee4\u7ed9\u5ba2\u6237\u7aef\uff0c\u901a\u77e5\u81ea\u5df1\u7684\u6570\u636e\u7aef\u53e3\u662fP\u3002\\n3. \u5ba2\u6237\u7aef\u6536\u5230\u547d\u4ee4\u540e\uff0c\u901a\u8fc7N+1\u7aef\u53e3\u8fde\u63a5\u670d\u52a1\u5668\u7684\u7aef\u53e3P, \u7528\u6765\u4f20\u9001\u6570\u636e\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/05/20190509223749.png)\\n\\n**\u547d\u4ee4\u8fde\u63a5\uff1a\u5ba2\u6237\u7aef\u5927\u4e8e1024\u7aef\u53e3 -> \u670d\u52a1\u5668 21\u7aef\u53e3**\\n\\n**\u6570\u636e\u8fde\u63a5\uff1a\u5ba2\u6237\u7aef\u5927\u4e8e1024\u7aef\u53e3 -> \u670d\u52a1\u5668\u5927\u4e8e1024\u7aef\u53e3**\\n\\n\\n\\n\u6709\u4e9bftp\u5ba2\u6237\u7aef\u9ed8\u8ba4\u5c31\u662f\u4f7f\u7528PASV\u88ab\u52a8\u6a21\u5f0f\u6765\u8fde\u63a5ftp\u670d\u52a1\u5668\u7684\uff0c\u5982\u679c\u6211\u4eec\u7684ftp\u670d\u52a1\u5668\u53ea\u652f\u6301\u4e3b\u52a8\u6a21\u5f0f\uff0c\u5c31\u4f1a\u9020\u6210\u5ba2\u6237\u7aef\u53ef\u4ee5\u8fdb\u884c\u7528\u6237\u9a8c\u8bc1\uff0c\u4f46\u65e0\u6cd5\u5217\u76ee\u5f55\uff0c\u4e5f\u65e0\u6cd5\u8fdb\u884c\u6570\u636e\u4f20\u9001\uff0c\u5e76\u63d0\u793a\u201c\u4f60\u6ca1\u6709\u6743\u9650\u201d\u8fd9\u6837\u7684550\u8fd4\u56de\u9519\u8bef\\n\\n\\n\\n### \u4e3b\u52a8\u6a21\u5f0f\u4e0e\u88ab\u52a8\u6a21\u5f0f\u7684\u4f18\u7f3a\u70b9\\n\\n- \u4e3b\u52a8FTP - \u5bf9FTP`\u670d\u52a1\u5668`\u7684\u7ba1\u7406\u6709\u5229\\n\\n  \u4f18\u70b9\uff1a\u670d\u52a1\u7aef\u914d\u7f6e\u7b80\u5355\uff0c\u5229\u4e8e\u670d\u52a1\u5668\u5b89\u5168\u7ba1\u7406\uff0c\u670d\u52a1\u5668\u53ea\u9700\u8981\u5f00\u653e21\u7aef\u53e3\\n\\n  \u7f3a\u70b9\uff1a\u5982\u679c\u5ba2\u6237\u7aef\u5f00\u542f\u4e86\u9632\u706b\u5899\uff0c\u6216\u5ba2\u6237\u7aef\u5904\u4e8e\u5185\u7f51\uff08NAT\u7f51\u5173\u4e4b\u540e\uff09\uff0c \u90a3\u4e48\u670d\u52a1\u5668\u5bf9\u5ba2\u6237\u7aef\u7aef\u53e3\u53d1\u8d77\u7684\u8fde\u63a5\u53ef\u80fd\u4f1a\u5931\u8d25\\n\\n- \u88ab\u52a8FTP - \u5bf9FTP`\u5ba2\u6237\u7aef`\u7684\u7ba1\u7406\u6709\u5229\\n\\n  \u7f3a\u70b9\uff1a\u670d\u52a1\u5668\u914d\u7f6e\u7ba1\u7406\u7a0d\u663e\u590d\u6742\uff0c\u4e0d\u5229\u4e8e\u5b89\u5168\uff0c\u670d\u52a1\u5668\u9700\u8981\u5f00\u653e\u968f\u673a\u9ad8\u4f4d\u7aef\u53e3\u4ee5\u4fbf\u5ba2\u6237\u7aef\u53ef\u4ee5\u8fde\u63a5\uff0c\u56e0\u6b64\u5927\u591a\u6570FTP\u670d\u52a1\u8f6f\u4ef6\u90fd\u53ef\u4ee5\u624b\u52a8\u914d\u7f6e\u88ab\u52a8\u7aef\u53e3\u7684\u8303\u56f4\\n\\n  \u4f18\u70b9\uff1a\u5bf9\u5ba2\u6237\u7aef\u7f51\u7edc\u73af\u5883\u6ca1\u6709\u8981\u6c42\\n\\n\\n\\n### \u5e38\u7528\u65b9\u6848\\n\\n\u88ab\u52a8\u6a21\u5f0f\u4e0b\uff0c\u5728FTP\u670d\u52a1\u7aef\u8bbe\u7f6e\u88ab\u52a8\u6a21\u5f0f\u4e0b\u5f00\u653e\u7684\u968f\u673a\u7aef\u53e3\u8303\u56f4\uff0c\u7136\u540e\u8bbe\u7f6e\u670d\u52a1\u5668\u9632\u706b\u5899\u89c4\u5219\uff0c\u5f00\u653e\u670d\u52a1\u5668\u7aef\u5bf9\u5e94\u7684\u7aef\u53e3\\n\\n```properties\\npasv_enable=YES   //\u5f00\u542fPASV\u6a21\u5f0f\\npasv_min_port=40000   //\u6700\u5c0f\u7aef\u53e3\u53f7\\npasv_max_port=40000   //\u6700\u5927\u7aef\u53e3\u53f7\\npasv_promiscuous=YES\\n\\n```\\n\\n\\n\\n## DOS\u73af\u5883\u4e0bFTP\u5e38\u7528\u547d\u4ee4\\n\\n```bash\\n# \u4e0e\u670d\u52a1\u5668\u5efa\u7acb\u8fde\u63a5\\nopen/ftp ...\\n# \u5207\u6362\u76ee\u5f55\\ncd\\n# \u5207\u6362\u672c\u5730\u76ee\u5f55\\nlcd\\n# \u4e0b\u8f7d\u6587\u4ef6 / \u4e0b\u8f7d\u591a\u4e2a\u6587\u4ef6\\nget / wget\\n# \u4e0a\u4f20\u6587\u4ef6\\nsend / put\\n# \u65ad\u5f00\u8fde\u63a5\\nbye\\n# \u5173\u95ed\u4ea4\u4e92\u6a21\u5f0f\\nprompt off\\n# \u5207\u6362\u4e3b\u52a8/\u88ab\u52a8\u6a21\u5f0f\\nquote PORT / PASV\\n```"},{"id":"git-notes","metadata":{"permalink":"/blog/git-notes","source":"@site/blog\\\\2019-05-07-Git\u5b66\u4e60\u7b14\u8bb0.md","title":"Git\u5b66\u4e60\u7b14\u8bb0","description":"Git\u662f\u5206\u5e03\u5f0f\u7248\u672c\u63a7\u5236\u7cfb\u7edf\uff0cGit\u4e2d\u6bcf\u4e2a\u4eba\u7684\u7535\u8111\u5c31\u662f\u4e00\u4e2a\u5b8c\u6574\u7684\u7248\u672c\u5e93\uff0c\u5f53\u591a\u4eba\u534f\u4f5c\u65f6\uff0c\u53ea\u9700\u628a\u5404\u81ea\u7684\u4fee\u6539\u63a8\u9001\u7ed9\u5bf9\u65b9\u3002","date":"2019-05-07T00:00:00.000Z","formattedDate":"2019\u5e745\u67087\u65e5","tags":[{"label":"git","permalink":"/blog/tags/git"},{"label":"\u5b66\u4e60\u7b14\u8bb0","permalink":"/blog/tags/\u5b66\u4e60\u7b14\u8bb0"}],"truncated":false,"authors":[],"frontMatter":{"slug":"git-notes","title":"Git\u5b66\u4e60\u7b14\u8bb0","tags":["git","\u5b66\u4e60\u7b14\u8bb0"]},"prevItem":{"title":"CentOS\u4e0b\u642d\u5efaFTP","permalink":"/blog/ftp-on-centos"}},"content":"Git\u662f\u5206\u5e03\u5f0f\u7248\u672c\u63a7\u5236\u7cfb\u7edf\uff0cGit\u4e2d\u6bcf\u4e2a\u4eba\u7684\u7535\u8111\u5c31\u662f\u4e00\u4e2a\u5b8c\u6574\u7684\u7248\u672c\u5e93\uff0c\u5f53\u591a\u4eba\u534f\u4f5c\u65f6\uff0c\u53ea\u9700\u628a\u5404\u81ea\u7684\u4fee\u6539\u63a8\u9001\u7ed9\u5bf9\u65b9\u3002\\n\\n\x3c!--more--\x3e\\n\\n## Git\u662f\u4ec0\u4e48\\n\\nGit\u662f\u5206\u5e03\u5f0f\u7248\u672c\u63a7\u5236\u7cfb\u7edf\\n\u5b98\u7f51:[https://git-scm.com/](https://git-scm.com/)\\n\\n### \u5de5\u4f5c\u539f\u7406 / \u6d41\u7a0b\\n\\n![](https://raw.githubusercontent.com/hans-yoyo/FigureBed/master/2019/20190502000850.png)\\n\\n* Workspace: \u5de5\u4f5c\u533a\\n* Index / Stage: \u6682\u5b58\u533a\\n* Repository: \u4ed3\u5e93\u533a\uff08\u6216\u672c\u5730\u4ed3\u5e93\uff09\\n* Remote: \u8fdc\u7a0b\u4ed3\u5e93\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502002525.png)\\n\\n### SVN\u4e0eGit\u7684\u4e3b\u8981\u533a\u522b\\n\\nSVN-\u96c6\u4e2d\u5f0f\u7248\u672c\u63a7\u5236\u7cfb\u7edf\uff0c\u7248\u672c\u5e93\u653e\u5728\u4e2d\u592e\u670d\u52a1\u5668\u3002\u4ee5\u4e2d\u592e\u670d\u52a1\u5668\u7684\u7248\u672c\u4e3a\u57fa\u51c6\uff0c\u5e72\u6d3b\u524d\u9700\u8981\u5148\u540c\u6b65\u4e2d\u592e\u670d\u52a1\u5668\u5f97\u5230\u6700\u65b0\u7684\u7248\u672c\uff0c\u81ea\u5df1\u672c\u5730\u7684\u66f4\u65b0\u4e5f\u9700\u8981\u63a8\u9001\u5230\u4e2d\u592e\u670d\u52a1\u5668\u3002\\n\\nGit\u662f\u5206\u5e03\u5f0f\u7248\u672c\u63a7\u5236\u7cfb\u7edf\uff0cGit\u4e2d\u6bcf\u4e2a\u4eba\u7684\u7535\u8111\u5c31\u662f\u4e00\u4e2a\u5b8c\u6574\u7684\u7248\u672c\u5e93\uff0c\u5f53\u591a\u4eba\u534f\u4f5c\u65f6\uff0c\u53ea\u9700\u628a\u5404\u81ea\u7684\u4fee\u6539\u63a8\u9001\u7ed9\u5bf9\u65b9\u3002\\n\\n## Git\u5b89\u88c5\u4f7f\u7528\\n\\n### Git\u5b89\u88c5\\n\\n\u53c2\u7167Git\u5b98\u7f51\u4e0b\u8f7d\u5b89\u88c5,\u5b89\u88c5\u5b8c\u6210\u540e\u9f20\u6807\u53f3\u952e\u83dc\u5355\u591a\u4e862\u4e2a\u9009\u9879\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502145216.png)\\n\\n### Git\u521d\u59cb\u5316\u7528\u6237\u4fe1\u606f\\n\\n\u8bbe\u7f6e\u7528\u6237\u5168\u5c40\u914d\u7f6e\uff1a\\n\\n```shell\\ngit config --global user.name \\"[name]\\"\\nSets the name you want to attached to your transactions\\n\\ngit config --global user.email \\"[email address]\\"\\nSets the email you want to attached to your transactions\\n\\ngit config --global color.ui auto\\nEnables helpful colorization of command line output\\n```\\n\\n\u67e5\u770b\u7528\u6237\u4fe1\u606f\u914d\u7f6e\\n\\n```shell\\ngit config user.name\\ngit config user.email\\n```\\n\\n### GitHub\u914d\u7f6eSSH\u516c\u94a5\\n\\n```shell\\nssh-keygen -t rsa -C \'[email address using in github]\'\\n```\\n\\n* \u5728Git Bash\u8f93\u5165\u4ee5\u4e0a\u547d\u4ee4\u540e\uff0c\u56de\u8f66\u540e\u518d\u6309\u4e09\u4e2a\u56de\u8f66(\u9ed8\u8ba4\u5b58\u50a8\u4f4d\u7f6e\uff0c\u5bc6\u7801\u4e3a\u7a7a\uff0c\u786e\u8ba4\u5bc6\u7801)\u3002\\n\\n* \u5c06\u4e0a\u4e00\u6b65\u751f\u6210\u7684\u516c\u94a5\u8def\u5f84\uff1aC:\\\\Users\\\\\u4f60\u7684\u7528\u6237\u540d\\\\\\\\.ssh\u3002id_rsa\u662f\u79c1\u94a5\uff0c\u4e0d\u80fd\u6cc4\u9732\u51fa\u53bb\uff0cid_rsa.pub\u662f\u516c\u94a5\uff0c\u53ef\u4ee5\u653e\u5fc3\u5730\u544a\u8bc9\u4efb\u4f55\u4eba\u3002\\n\\n* \u5c06\u751f\u6210\u7684\u516c\u94a5(id_rsa.pub)\u6dfb\u52a0\u5230GitHub:\u9009\u62e9\u5934\u50cf--\x3eSettings--\x3eSSH and GPG keys\\n\\n### [Git GUI Clients](https://git-scm.com/downloads/guis)\\n\\n* GitHub Desktop\\n* TortoiseGit\\n* Git Extensions\\n* ...\\n\\n## Git\u7ba1\u7406\u4ee3\u7801\u4ed3\u5e93\\n\\n### \u521b\u5efa\u7248\u672c\u5e93\\n\\nRepository\u53ef\u4ee5\u7406\u89e3\u4e3a\u4e00\u4e2a\u76ee\u5f55\uff0c\u8fd9\u4e2a\u76ee\u5f55\u91cc\u9762\u7684\u6240\u6709\u6587\u4ef6\u90fd\u53ef\u4ee5\u88abGit\u7ba1\u7406\u8d77\u6765\u3002\\n\\n```shell\\n$ mkdir testgit\\n$ cd testgit/\\n$ git init\\nInitialized empty Git repository in D:/WorkSpaces/testgit/.git/\\n```\\n\\n\u6267\u884c\u4e0a\u9762\u7684\u64cd\u4f5c\uff0cgittest\u5c31\u6210\u4e3a\u4e86\u4e00\u4e2aGit\u4ed3\u5e93\u3002\u5728testgit\u76ee\u5f55\u4e0b\u81ea\u52a8\u65b0\u589e\u4e86\u4e00\u4e2a.git\u6587\u4ef6\u5939\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502150628.png)\\n\\n\u65b0\u5efareadme.txt\u6587\u4ef6\u5e76\u63d0\u4ea4\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502151123.png)\\n\\n\u7ee7\u7eed\u4fee\u6539readme.txt\u6587\u4ef6\u540e\uff0c\u63d0\u4ea4\u4fee\u6539\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502152011.png)\\n\\n\u53d1\u73b0\u6bcf\u6b21\u90fd\u4f1a\u6709warning: LF will be replaced by CRLF in readme.txt.\u63d0\u793a\u3002\\n\\n\u539f\u56e0\u662f\u4e0d\u540c\u64cd\u4f5c\u7cfb\u7edf\u4e2d\u6362\u884c\u7b26\u7684\u6807\u8bc6\u4e0d\u540c\\n\\n* CRLF->Windows-style\\n\\n* LF->Unix Style\\n\\n* CR->Mac Style\\n\\n\u53ef\u901a\u8fc7\u5982\u4e0b\u547d\u4ee4\u8fdb\u884c\u8f6c\u6362\u8bbe\u7f6e\\n\\n```shell\\ngit config --global core.autocrlf true/false/inout\\n```\\n\\n* true\uff0c\u6dfb\u52a0\u6587\u4ef6\u5230git\u4ed3\u5e93\u65f6\uff0cgit\u5c06\u5176\u89c6\u4e3a\u6587\u672c\u6587\u4ef6\u3002\u4ed6\u5c06\u628acrlf\u53d8\u6210lf\\n* false\uff0cline-endings\u5c06\u4e0d\u505a\u8f6c\u6362\u64cd\u4f5c\u3002\u6587\u672c\u6587\u4ef6\u4fdd\u6301\u539f\u6765\u7684\u6837\u5b50\u3002\\n* input\uff0c\u6dfb\u52a0\u6587\u4ef6git\u4ed3\u5e93\u77f3\uff0cgit\u628acrlf\u7f16\u7a0blf\u3002\u5f53\u6709\u4ebaCheck\u4ee3\u7801\u65f6\u8fd8\u662flf\u65b9\u5f0f\u3002\u56e0\u6b64\u5728window\u64cd\u4f5c\u7cfb\u7edf\u4e0b\uff0c\u4e0d\u8981\u4f7f\u7528\u8fd9\u4e2a\u8bbe\u7f6e\\n\\n### \u7248\u672c\u56de\u9000\\n\\n\u7ee7\u7eed\u4fee\u6539readme.txt\u6587\u4ef6\uff0c\u65b0\u589e\\"33333333\\"\u5e76\u63d0\u4ea4\\n\\n\u67e5\u770b\u4fee\u6539\u7684\u5386\u53f2\u8bb0\u5f55\\n\\n```shell\\ngit log\\ngit log --pretty=oneline\\ngit reflog\\n```\\n\\ngit log \u4e0egit reflog\u7684\u533a\u522b\\n\\n1) git log: commit \u7684\u7248\u672c\u65e5\u5fd7 \u5305\u542b\u63d0\u4ea4\u7684\u7248\u672c \u64cd\u4f5c\u8005 \u65e5\u671f (\u65b9\u4fbf\u67e5\u770bcommit\u7684\u7248\u672c,\u4f46\u662f\u7248\u672c\u56de\u9000\u540e,\u4f7f\u7528git log \u770b\u4e0d\u5230\u56de\u9000\u7248\u672c\u53f7\u4e4b\u540e\u7684\u7248\u672c\u8bb0\u5f55) \\n\\n2) git reflog: \u4f7f\u7528git \u547d\u4ee4\u8fdb\u884c\u64cd\u4f5c\u7684\u65e5\u5fd7  \u5305\u62ec\u5f53\u524d\u6b65\u9aa4\u6240\u5728\u54ea\u4e2a\u7248\u672c(\u4e00\u4e2acommit \u4ea7\u751f\u4e00\u4e2a\u7248\u672c, \u6307\u5b9a\u7248\u672c\u56de\u9000\u53ea\u80fd\u56de\u9000\u5230\u8be5commit) \u4ee5\u53ca\u64cd\u4f5c\u7684\u5177\u4f53\u5185\u5bb9\\n\\n\u7248\u672c\u56de\u9000\u540e,\u4ecd\u7136\u53ef\u4ee5\u770b\u5230\u6240\u6709\u7684\u7248\u672c\u8bb0\u5f55 \u65b9\u4fbf\u67e5\u770b\u6bcf\u4e2a\u64cd\u4f5c\u6b65\u9aa4\u6240\u5728\u7684\u7248\u672c,\u53ef\u4ee5\u6839\u636e\u7248\u672c\u53f7\u81ea\u7531\u524d\u8fdb\u540e\u9000\\n\\n\u7248\u672c\u56de\u9000\u64cd\u4f5c\\n\\n```shell\\ngit reset --hard HEAD^\\ngit reset --hard HEAD^^\\ngit reset --hard HEAD~100\\ngit reset --hard \'\u7248\u672c\u53f7\'\\n```\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502155810.png)\\n\\n### \u64a4\u9500\u548c\u5220\u9664\u6587\u4ef6\\n\\n#### \u64a4\u9500\u4fee\u6539\\n\\n```shell\\n# \u4e22\u5f03\u5de5\u4f5c\u533a\u7684\u4fee\u6539\u3002--\u5f88\u91cd\u8981\uff0c\u6ca1\u6709--\u7684\u8bdd\u547d\u4ee4\u5c31\u53d8\u6210\u521b\u5efa\u5206\u652f\u4e86\\ngit checkout -- file\\n```\\n\\n\u67092\u79cd\u60c5\u51b5\uff1a\\n\\n* \u6587\u4ef6\u4fee\u6539\u540e\uff0c\u8fd8\u6ca1\u6709\u653e\u5230\u6682\u5b58\u533a\uff0c\u4f7f\u7528\u64a4\u9500\u4fee\u6539\u5c31\u56de\u5230\u548c\u7248\u672c\u5e93\u4e00\u6a21\u4e00\u6837\u7684\u72b6\u6001\\n* \u53e6\u5916\u4e00\u79cd\u662f\u6587\u4ef6\u7684\u4fee\u6539\u5df2\u7ecf\u653e\u5165\u6682\u5b58\u533a\u4e86\uff0c\u63a5\u7740\u53c8\u4f5c\u4e86\u4fee\u6539\uff0c\u64a4\u9500\u4fee\u6539\u5c31\u56de\u5230\u6dfb\u52a0\u6682\u5b58\u533a\u540e\u7684\u72b6\u6001\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502162025.png)\\n\\n#### \u5220\u9664\u6587\u4ef6\\n\\n\u5220\u9664\u6587\u4ef6\u540e\u518dcommit\u5230git\uff0c\u5982\u679c\u5220\u9664\u5e76\u63d0\u4ea4\u5230\u6682\u5b58\u533a\u540e\uff0c\u53ef\u6267\u884ccheckout\u64cd\u4f5c\u6062\u590d\u5220\u9664\u7684\u6587\u4ef6\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502162924.png)\\n\\n\\n\\n## \u8fdc\u7a0b\u4ed3\u5e93\\n\\n### \u6ce8\u518cGitHub\uff0c\u5e76\u5728\u672c\u5730\u521b\u5efaSSH\u6dfb\u52a0\u5230GitHub \\n\\n\u64cd\u4f5c\u53c2\u7167\u6b65\u9aa42-3\\n\\n### \u6dfb\u52a0\u8fdc\u7a0b\u5e93\\n\\n#### \u672c\u5730\u5148\u6709\u4ed3\u5e93\uff0c\u7136\u540e\u5173\u8054\u5230\u8fdc\u7a0b\u5e93\\n\\n* 1. \u5728GitHub\u4e0a\u521b\u5efa\u4ed3\u5e93\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502171256.png)\\n\\n* 2. \u5728\u672c\u5730\u4ed3\u5e93\u76ee\u5f55\u4e0b\u8fd0\u884c\u547d\u4ee4\\n\\n```shell\\ngit remote add origin https://github.com/hyman213/testgit.git\\n# \u7b2c\u4e00\u6b21\u63a8\u9001\\ngit push -u origin master\\n# \u4e4b\u540e\u7684\u63a8\u9001\\ngit push origin master\\n```\\n\\n\u6211\u4eec\u7b2c\u4e00\u6b21\u63a8\u9001master\u5206\u652f\u65f6\uff0c\u52a0\u4e0a\u4e86 \u2013u\u53c2\u6570\uff0cGit\u4e0d\u4f46\u4f1a\u628a\u672c\u5730\u7684master\u5206\u652f\u5185\u5bb9\u63a8\u9001\u7684\u8fdc\u7a0b\u65b0\u7684master\u5206\u652f\uff0c\u8fd8\u4f1a\u628a\u672c\u5730\u7684master\u5206\u652f\u548c\u8fdc\u7a0b\u7684master\u5206\u652f\u5173\u8054\u8d77\u6765\uff0c\u5728\u4ee5\u540e\u7684\u63a8\u9001\u6216\u8005\u62c9\u53d6\u65f6\u5c31\u53ef\u4ee5\u7b80\u5316\u547d\u4ee4\u3002\\n\\n\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502171627.png)\\n\\n\u6b64\u65f6\u672c\u5730\u4ed3\u5e93\u7684\u5185\u5bb9\u5c31\u4e0a\u4f20\u5230\u4e86\u8fdc\u7a0b\u5e93\\n\\n\u518d\u6b21\u4fee\u6539\u672c\u5730\u5e93\u7684readme.txt\u6587\u4ef6\uff0c\u6d4b\u8bd5\u4e0a\u4f20\u66f4\u65b0\u5230\u8fdc\u7a0b\u5e93\\n\\n```shell\\n$ vi readme.txt\\n$ git status\\n$ git add readme.txt\\n$ git commit -m \'\u589e\u52a0\u4e8655555555\u548c66666666\'\\n$ git push origin master\\n```\\n\\n\u5237\u65b0GitHub\u4e0a\u5185\u5bb9\uff0c\u5185\u5bb9\u4e0e\u672c\u5730\u5e93\u4e00\u81f4\uff0c\u672c\u5730\u5185\u5bb9\u6210\u529f\u63a8\u9001\u5230\u53ef\u8fdc\u7a0b\u5e93\\n\\n#### \u5148\u6709\u8fdc\u7a0b\u4ed3\u5e93\\n\\n* 1. \u5728GitHub\u4e0a\u521b\u5efa\u4ed3\u5e93testgit2\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502172525.png)\\n\\n* 2. \u5728\u672c\u5730clone\u8fdc\u7a0b\u5e93\u7684\u5185\u5bb9, \u6ce8\u610fclone\u4e0b\u6765\u5185\u5bb9\u4f1a\u5728\u5f53\u524d\u8def\u5f84\u751f\u6210\u65b0\u6587\u4ef6\u5939testgit2\\n\\n```shell\\n$ git clone https://github.com/hyman213/testgit2.git\\n```\\n\\n* 3. \u6d4b\u8bd5\u5728\u672c\u5730\u589e\u52a0readme.txt\u6587\u4ef6\uff0c\u5e76\u4e0a\u4f20\u63a8\u9001\u5230\u8fdc\u7a0b\u5e93\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502173248.png)\\n\\n\\n\\n## \u5206\u652f-branch\\n\\n> \u6bcf\u6b21\u63d0\u4ea4\uff0cGit\u90fd\u628a\u5b83\u4eec\u4e32\u6210\u4e00\u6761\u65f6\u95f4\u7ebf\uff0c\u8fd9\u6761\u65f6\u95f4\u7ebf\u5c31\u662f\u4e00\u4e2a\u5206\u652f\u3002\u622a\u6b62\u5230\u76ee\u524d\uff0c\u53ea\u6709\u4e00\u6761\u65f6\u95f4\u7ebf\uff0c\u5728Git\u91cc\uff0c\u8fd9\u4e2a\u5206\u652f\u53eb\u4e3b\u5206\u652f\uff0c\u5373master\u5206\u652f\u3002HEAD\u4e25\u683c\u6765\u8bf4\u4e0d\u662f\u6307\u5411\u63d0\u4ea4\uff0c\u800c\u662f\u6307\u5411master\uff0cmaster\u624d\u662f\u6307\u5411\u63d0\u4ea4\u7684\uff0c\u6240\u4ee5\uff0cHEAD\u6307\u5411\u7684\u5c31\u662f\u5f53\u524d\u5206\u652f\\n\\n\\n\\n\u7528\u5230\u7684\u547d\u4ee4\u6709\\n\\n```shell\\n# \u521b\u5efa\u5206\u652fdev\\ngit branch dev\\n# \u5207\u6362\u5230dev\u5206\u652f\\ngit checkout dev\\n# \u4e0a\u9762\u4e24\u4e2a\u547d\u4ee4\u5408\u5e76\\ngit checkout -b dev\\n# \u67e5\u770b\u5206\u652f(\u5217\u51fa\u6240\u6709\u5206\u652f,\u5f53\u524d\u5206\u652f\u4f1a\u6dfb\u52a0\u4e00\u4e2a\u661f\u53f7)\\ngit branch\\n# \u5408\u5e76\u5206\u652f(\u5c06dev\u5206\u652f\u4e0a\u7684\u66f4\u65b0\u5408\u5e76\u5230\u5f53\u524d\u5206\u652f)\\ngit merge dev\\n# \u5220\u9664\u5206\u652f\\ngit branch -d dev\\n```\\n\\n\\n\\n### \u521b\u5efa\u5206\u652f\\n\\n\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502223958.png)\\n\\n\u5207\u6362\u5230dev\u5206\u652f\uff0c\u7136\u540e\u5728dev\u5206\u652f\u4e0a\u8fdb\u884c\u4fee\u6539\u3002\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502225423.png)\\n\\n\u5207\u6362\u5230master\u5206\u652f\uff0c\u67e5\u770breadme.txt\u6587\u4ef6\u3002\u5185\u5bb9\u6ca1\u6709\u4fee\u6539\\n\\n### \u5408\u5e76/\u5220\u9664\u5206\u652f\\n\\n\u5c06dev\u5206\u652f\u4e0a\u7684\u4fee\u6539\u5408\u5e76\u5230master\u5206\u652f\u4e0a\\n\\n![1556808994739](C:\\\\Users\\\\idobe\\\\AppData\\\\Roaming\\\\Typora\\\\typora-user-images\\\\1556808994739.png)\\n\\n\u901a\u5e38\u5408\u5e76\u5206\u652f\u65f6\uff0cgit\u4e00\u822c\u4f7f\u7528\\"Fast forward\\"\u6a21\u5f0f\uff0c\u5728\u8fd9\u79cd\u6a21\u5f0f\u4e0b\uff0c\u5220\u9664\u5206\u652f\u540e\uff0c\u4f1a\u4e22\u6389\u5206\u652f\u4fe1\u606f\uff0c\u73b0\u5728\u6211\u4eec\u6765\u4f7f\u7528\u5e26\u53c2\u6570 \u2013no-ff\u6765\u7981\u7528\u201dFast forward\u201d\u6a21\u5f0f\\n\\n\u7981\u7528\u201dFast forward\u201d\u6a21\u5f0f\u5408\u5e76\u5206\u652f\\n\\n```shell\\ngit merge --no-ff -m \\"merge with mo-ff\\" dev\\n```\\n\\n### \u89e3\u51b3\u5206\u652f\u51b2\u7a81\\n\\n\u65b0\u5efa\u5206\u652fbranch1,\u5728branch1\u5206\u652f\u548cmaster\u5206\u652f\u5206\u522b\u4fee\u6539readme.txt\u6587\u4ef6\u5e76\u63d0\u4ea4\u3002\u7136\u540e\u5c06branch1\u5206\u652f\u7684\u4fee\u6539\u5408\u5e76\u5230master\u5206\u652f\u3002\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190502231618.png)\\n\\n\u67e5\u770b\u51b2\u7a81\u5e76\u89e3\u51b3\u51b2\u7a81\u540e\uff0c\u518d\u6b21\u63d0\u4ea4\u6587\u4ef6\\n\\n![1556810416998](C:\\\\Users\\\\idobe\\\\AppData\\\\Roaming\\\\Typora\\\\typora-user-images\\\\1556810416998.png)\\n\\n### \u5206\u652f\u7ba1\u7406\\n\\n\u9996\u5148master\u4e3b\u5206\u652f\u5e94\u8be5\u662f\u975e\u5e38\u7a33\u5b9a\u7684\uff0c\u4e5f\u5c31\u662f\u7528\u6765\u53d1\u5e03\u65b0\u7248\u672c\uff0c\u4e00\u822c\u60c5\u51b5\u4e0b\u4e0d\u5141\u8bb8\u5728\u4e0a\u9762\u5e72\u6d3b\uff0c\u5e72\u6d3b\u4e00\u822c\u60c5\u51b5\u4e0b\u5728\u65b0\u5efa\u7684dev\u5206\u652f\u4e0a\u5e72\u6d3b\uff0c\u5e72\u5b8c\u540e\uff0c\u6bd4\u5982\u4e0a\u8981\u53d1\u5e03\uff0c\u6216\u8005\u8bf4dev\u5206\u652f\u4ee3\u7801\u7a33\u5b9a\u540e\u53ef\u4ee5\u5408\u5e76\u5230\u4e3b\u5206\u652fmaster\u4e0a\u6765\\n\\n> bug\u5206\u652f: \u5728\u5f00\u53d1\u4e2d\uff0c\u4f1a\u7ecf\u5e38\u78b0\u5230bug\u95ee\u9898\uff0c\u90a3\u4e48\u6709\u4e86bug\u5c31\u9700\u8981\u4fee\u590d\uff0c\u5728Git\u4e2d\uff0c\u5206\u652f\u662f\u5f88\u5f3a\u5927\u7684\uff0c\u6bcf\u4e2abug\u90fd\u53ef\u4ee5\u901a\u8fc7\u4e00\u4e2a\u4e34\u65f6\u5206\u652f\u6765\u4fee\u590d\uff0c\u4fee\u590d\u5b8c\u6210\u540e\uff0c\u5408\u5e76\u5206\u652f\uff0c\u7136\u540e\u5c06\u4e34\u65f6\u7684\u5206\u652f\u5220\u9664\u6389\u3002\\n\\n\u5728dev\u5206\u652f\u4fee\u6539readme.txt\u7684\u5185\u5bb9\uff0c\u7136\u540e\u7d27\u6025\u6709\u4e2abug\u9700\u8981\u4fee\u590d, \u9700\u8981\u65b0\u589e\u5206\u652f\u5728master\u57fa\u7840\u4e0a\u8fdb\u884c\u4fee\u590d\u3002\u9700\u8981\u5148\u5c06dev\u5206\u652f\u4e0a\u7684\u4fee\u6539\u9690\u85cf\\n\\n```shell\\n# \u5c06\u5f53\u524d\u5206\u652f\u7684\u4fee\u6539\u9690\u85cf\\ngit stash\\n# \u5217\u51fa\u9690\u85cf\u7684\u4fee\u6539\\ngit stash list\\n# \u6062\u590d\u9690\u85cf\u7684\u4fee\u6539\\ngit stash apply\\n# \u5220\u9664stash\\ngit stash drop\\n# \u6062\u590d\u7684\u540c\u65f6\u5220\u9664\\ngit stash pop\\n```\\n\\n## \u591a\u4eba\u534f\u4f5c\\n\\n### \u67e5\u770b\u8fdc\u7a0b\u5e93\u4fe1\u606f\\n\\n```shell\\ngit remote\\n# \u8be6\u7ec6\u4fe1\u606f\\ngit remote -v\\n```\\n\\n### \u63a8\u9001\u5206\u652f\\n\\n\u63a8\u9001\u5206\u652f\u5c31\u662f\u628a\u8be5\u5206\u652f\u4e0a\u6240\u6709\u672c\u5730\u63d0\u4ea4\u5230\u8fdc\u7a0b\u5e93\u4e2d\uff0c\u63a8\u9001\u65f6\uff0c\u8981\u6307\u5b9a\u672c\u5730\u5206\u652f\\n\\n```shell\\n# \u63a8\u9001master\u5206\u652f\\ngit push origin master\\n# \u63a8\u9001dev\u5206\u652f\\ngit push origin dev\\n```\\n\\n\u4fee\u6539dev\u5206\u652f\u7684\u5185\u5bb9\uff0c\u5e76\u5c06dev\u5206\u652f\u63a8\u9001\u5230\u8fdc\u7a0b\u5e93\uff0c\u7ed3\u679c\u8fdc\u7a0b\u5e93\u4f1a\u65b0\u589edev\u5206\u652f\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190503000207.png)\\n\\n\\n\\ngitHub\u4e0a\u65b0\u589e\u5206\u652fdev\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/20190503000251.png)\\n\\n\\n\\nmaster\u5206\u652f\u662f\u4e3b\u5206\u652f\uff0c\u56e0\u6b64\u8981\u65f6\u523b\u4e0e\u8fdc\u7a0b\u540c\u6b65\u3002\\n\\n\u4e00\u4e9b\u4fee\u590dbug\u5206\u652f\u4e0d\u9700\u8981\u63a8\u9001\u5230\u8fdc\u7a0b\u53bb\uff0c\u53ef\u4ee5\u5148\u5408\u5e76\u5230\u4e3b\u5206\u652f\u4e0a\uff0c\u7136\u540e\u628a\u4e3b\u5206\u652fmaster\u63a8\u9001\u5230\u8fdc\u7a0b\u53bb\u3002\\n\\n### \u6293\u53d6\u5206\u652f\\n\\n\u5c06\u8fdc\u7a0b\u7684origin\u7684dev\u5206\u652f\u540c\u6b65\u5230\u672c\u5730\\n\\n```shell\\ngit checkout -b dev origin/dev\\n```\\n\\n\u73b0\u5728\u5c31\u53ef\u4ee5\u5728dev\u5206\u652f\u4e0a\u505a\u5f00\u53d1\u4e86\uff0c\u5f00\u53d1\u5b8c\u6210\u540e\u628adev\u5206\u652f\u63a8\u9001\u5230\u8fdc\u7a0b\u5e93\u3002\\n\\n```shell\\ngit push origin dev\\n```\\n\\n\u6293\u53d6\u8fdc\u7a0b\u4ed3\u5e93\\n\\n```shell\\ngit pull\\n# \u6307\u5b9aden\u5206\u652f\u4e0e\u8fdc\u7a0borigin/dev\u5206\u652f\u7684\u94fe\u63a5\\ngit branch --set-upstream-to dev origin/dev\\n```\\n\\n\\n\\n\u591a\u4eba\u534f\u4f5c\u5de5\u4f5c\u6a21\u5f0f\u4e00\u822c\u662f\u8fd9\u6837\u7684\uff1a\\n\\n- \u9996\u5148\uff0c\u53ef\u4ee5\u8bd5\u56fe\u7528git push origin branch-name\u63a8\u9001\u81ea\u5df1\u7684\u4fee\u6539.\\n- \u5982\u679c\u63a8\u9001\u5931\u8d25\uff0c\u5219\u56e0\u4e3a\u8fdc\u7a0b\u5206\u652f\u6bd4\u4f60\u7684\u672c\u5730\u66f4\u65b0\u65e9\uff0c\u9700\u8981\u5148\u7528git pull\u8bd5\u56fe\u5408\u5e76\u3002\\n- \u5982\u679c\u5408\u5e76\u6709\u51b2\u7a81\uff0c\u5219\u9700\u8981\u89e3\u51b3\u51b2\u7a81\uff0c\u5e76\u5728\u672c\u5730\u63d0\u4ea4\u3002\u518d\u7528git push origin branch-name\u63a8\u9001\u3002\\n\\n\\n\\n## GitHub-Git Cheat Sheet\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/05/20190507214432.png)\\n\\n![](https://raw.githubusercontent.com/hyman213/FigureBed/master/2019/05/20190507214558.png)"}]}')}}]);